def _format_entry_price_text(value):
    try:
        price = int(float(value))
    except (TypeError, ValueError):
        return "-"
    return f"{price:,}원"


def _translate_latency_state(value):
    return {
        "SAFE": "양호",
        "CAUTION": "주의",
        "DANGER": "위험",
    }.get(str(value or "").upper(), value or "-")


def _translate_entry_decision(value):
    return {
        "ALLOW_NORMAL": "기본 진입 허용",
        "REJECT_DANGER": "진입 보류",
        "REJECT": "진입 보류",
    }.get(str(value or "").upper(), value or "-")


def _translate_order_tag(value):
    return {
        "fallback_scout": "폐기된 탐색 주문",
        "fallback_main": "폐기된 본 주문",
        "fallback_single": "폐기된 fallback 주문",
    }.get(value, value or "주문")


def _translate_tif(value):
    return {
        "IOC": "즉시체결 우선",
        "DAY": "장중 유지",
    }.get(str(value or "").upper(), value or "-")


def _format_entry_order_line(order):
    return (
        f"- {_translate_order_tag(order.get('tag'))}: "
        f"{int(order.get('qty') or 0)}주 / "
        f"{_format_entry_price_text(order.get('price'))} / "
        f"{_translate_tif(order.get('tif'))}"
    )


def _resolve_buy_signal_audience(*, liquidity_value=0, ai_score=0):
    threshold = _rule_float('VIP_LIQUIDITY_THRESHOLD', 1_000_000_000)
    try:
        liquidity = float(liquidity_value or 0)
    except (TypeError, ValueError):
        liquidity = 0.0
    try:
        score = float(ai_score or 0)
    except (TypeError, ValueError):
        score = 0.0
    return 'VIP_ALL' if liquidity >= float(threshold or 0) and score >= 90.0 else 'ADMIN_ONLY'


def _publish_buy_signal_submission_notice(
    stock,
    code,
    *,
    strategy,
    curr_price,
    requested_qty,
    entry_mode,
    latency_gate,
    liquidity_value=0,
    ai_score=0,
):
    if EVENT_BUS is None:
        return

    bundle_id = str(stock.get('entry_bundle_id', '') or '').strip()
    if bundle_id and stock.get('last_buy_signal_telegram_bundle_id') == bundle_id:
        return

    audience = (
        "VIP_ALL"
        if greenfield_stage_telegram_enabled() and not _is_any_simulated_position(stock, strategy)
        else _resolve_telegram_audience_for_stock(stock, strategy, default="VIP_ALL")
    )
    dynamic_reason = (
        stock.get('entry_dynamic_reason')
        or stock.get('entry_armed_dynamic_reason')
        or '-'
    )
    order_price = _coerce_int_value(
        (latency_gate or {}).get('order_price')
        or (latency_gate or {}).get('submitted_order_price')
        or (latency_gate or {}).get('latency_guarded_order_price')
    )
    gap_pct = 0.0
    if _coerce_int_value(curr_price) > 0 and order_price > 0:
        gap_pct = ((float(order_price) - float(curr_price)) / float(curr_price)) * 100.0
    order_price_text = f"{order_price:,}원" if order_price > 0 else "-"
    gap_text = f"{gap_pct:+.2f}%" if order_price > 0 and _coerce_int_value(curr_price) > 0 else "-"
    msg = (
        f"🛒 **[BUY 주문 제출] {stock.get('name')} ({code})**\n"
        f"전략: `{strategy}` | 진입모드: `{entry_mode}`\n"
        f"현재가: `{int(curr_price):,}원` | 제출수량: `{int(requested_qty or 0)}주`\n"
        f"주문가: `{order_price_text}` | 현재가대비: `{gap_text}`\n"
        f"진입근거: `{dynamic_reason}`\n"
        f"Latency: `{_translate_latency_state(latency_gate.get('latency_state'))}` / "
        f"`{_translate_entry_decision(latency_gate.get('decision'))}`"
    )
    try:
        EVENT_BUS.publish(
            'TELEGRAM_BROADCAST',
            {'message': msg, 'audience': audience, 'parse_mode': 'Markdown'},
        )
        if bundle_id:
            stock['last_buy_signal_telegram_bundle_id'] = bundle_id
        _log_entry_pipeline(
            stock,
            code,
            "buy_signal_telegram_enqueued",
            audience=audience,
            entry_mode=entry_mode,
            requested_qty=_safe_int(requested_qty, 0),
            order_price=order_price,
            current_price=_coerce_int_value(curr_price),
            order_price_gap_pct=f"{gap_pct:.4f}" if order_price > 0 and _coerce_int_value(curr_price) > 0 else "-",
            price_below_bid_bps=_coerce_int_value((latency_gate or {}).get("price_below_bid_bps")),
            liquidity_value=_safe_int(liquidity_value, 0),
            ai_score=f"{float(ai_score or 0):.1f}",
            latency=latency_gate.get('latency_state'),
            decision=latency_gate.get('decision'),
            dynamic_reason=dynamic_reason,
            **_panic_gap_weight_log_fields(latency_gate),
            actual_order_submitted=True,
            broker_order_forbidden=False,
            greenfield_stage_notice=bool(greenfield_stage_telegram_enabled()),
        )
        if greenfield_stage_telegram_enabled() and not _is_any_simulated_position(stock, strategy):
            decision = _greenfield_decision_for_stock(stock, stage="submit", action="ALLOW_SUBMIT", strategy=strategy)
            _log_entry_pipeline(
                stock,
                code,
                "greenfield_stage_telegram_enqueued",
                greenfield_stage_notice=True,
                greenfield_stage_notice_audience="VIP_ALL",
                greenfield_stage_notice_template="buy_signal_submission_notice",
                **decision.as_fields(),
            )
    except Exception as exc:
        log_error(f"🚨 [BUY 신호 알림 실패] {stock.get('name')}({code}): {exc}")
        _log_entry_pipeline(
            stock,
            code,
            "buy_signal_telegram_enqueue_failed",
            audience=audience,
            entry_mode=entry_mode,
            error=str(exc),
        )


def _greenfield_bucket_slug(value, *, max_len=96) -> str:
    text = re.sub(r"[^a-zA-Z0-9가-힣]+", "_", str(value or "").strip().lower()).strip("_")
    return text[:max_len] or "unknown"


def _entry_score_band_for_greenfield(value) -> str:
    score = _safe_float(value, None)
    if score is None:
        return "score_unknown"
    if score < 60:
        return "score_lt60"
    if score < 63:
        return "score_60_62"
    if score < 66:
        return "score_63_65"
    if score < 70:
        return "score_66_69"
    return "score_70p"


def _observed_greenfield_entry_bucket_id(stock) -> str | None:
    if not isinstance(stock, dict):
        return None
    source = str(stock.get("wait6579_probe_canary_source") or "").strip()
    if source not in {"score65_74_recovery_probe", "buy_recovery_canary_promoted", "wait6579_ev_cohort"}:
        return None
    score_value = (
        stock.get("wait6579_probe_canary_score")
        or stock.get("ai_score")
        or stock.get("current_ai_score")
        or stock.get("score")
    )
    if _entry_score_band_for_greenfield(score_value) != "score_66_69":
        bucket_key = ENTRY_LIVE_AUTO_BUCKET_KEY.replace(
            "score=score_66_69",
            f"score={_entry_score_band_for_greenfield(score_value)}",
        )
    else:
        bucket_key = ENTRY_LIVE_AUTO_BUCKET_KEY
    return f"entry:combo_entry_spot:{_greenfield_bucket_slug(bucket_key)}"


def _greenfield_decision_for_stock(stock, *, stage, action, strategy=None, hard_safety=False) -> GreenfieldDecision:
    resolved_strategy = strategy or normalize_strategy((stock or {}).get("strategy"))
    observed_bucket_id = _observed_greenfield_entry_bucket_id(stock) if str(stage) == "entry" else None
    return evaluate_greenfield_authority(
        stage=stage,
        action=action,
        strategy=resolved_strategy,
        hard_safety=hard_safety,
        observed_bucket_id=observed_bucket_id,
    )


def _greenfield_block_fields(decision: GreenfieldDecision) -> dict:
    return {
        **decision.as_fields(),
        "metric_role": "execution_quality_real_only",
        "window_policy": "runtime_greenfield_policy_version_window",
        "source_quality_gate": "greenfield_policy_loaded_and_stage_authority_checked",
        "forbidden_uses": "hard_safety_bypass|provider_route_change|bot_restart|intraday_threshold_mutation",
        "actual_order_submitted": False,
        "broker_order_forbidden": True,
        "legacy_policy_role": "baseline_prior",
    }


def _greenfield_bucket_notice_line(decision: GreenfieldDecision) -> str:
    return format_greenfield_bucket_notice_line(decision)


def _publish_greenfield_stage_notice(
    stock,
    code,
    *,
    stage,
    action,
    title,
    body,
    strategy=None,
    event_id="-",
    parse_mode="Markdown",
    log_fn=None,
    extra_fields=None,
    decision_override=None,
):
    if EVENT_BUS is None or not greenfield_stage_telegram_enabled():
        return
    if _is_any_simulated_position(stock, strategy or (stock or {}).get("strategy")):
        return
    decision = decision_override or _greenfield_decision_for_stock(stock, stage=stage, action=action, strategy=strategy)
    key = "|".join(
        [
            str(stock.get("id") if isinstance(stock, dict) else "-"),
            str(code or "-"),
            str(decision.policy_version or "-"),
            str(stage or "-"),
            str(action or "-"),
            str(event_id or "-"),
        ]
    )
    logger = log_fn or (_log_holding_pipeline if str(stage) in {"holding", "scale_in", "exit"} else _log_entry_pipeline)
    fields = {
        "greenfield_stage_notice": True,
        "greenfield_stage_notice_key": key,
        "greenfield_stage_notice_audience": "VIP_ALL",
        **decision.as_fields(),
        **(extra_fields or {}),
    }
    if key in _GREENFIELD_TELEGRAM_KEYS:
        logger(stock, code, "greenfield_stage_telegram_deduped", **fields)
        return
    try:
        EVENT_BUS.publish(
            "TELEGRAM_BROADCAST",
            {
                "message": f"{title}\n{body}",
                "audience": "VIP_ALL",
                "parse_mode": parse_mode,
            },
        )
        _GREENFIELD_TELEGRAM_KEYS.add(key)
        logger(stock, code, "greenfield_stage_telegram_enqueued", **fields)
    except Exception as exc:
        logger(stock, code, "greenfield_stage_telegram_failed", error=str(exc), **fields)


SCANNER_WATCH_EVICTION_TERMINAL_STAGES = {
    "blocked_strength_momentum",
    "blocked_vpw",
    "blocked_liquidity",
    "blocked_overbought",
    "blocked_ai_score",
    "ai_confirmed_terminal_no_budget",
}
SCANNER_WATCH_EVICTION_NON_TERMINAL_SKIP_REASONS = {
    "scanner_full_eval_loop_budget_deferred",
    "entry_cooldown_active",
    "strength_momentum_stability_recheck_waiting",
}
SCANNER_WATCH_EVICTION_POOL_BLOCK_SKIP_REASONS = {
    "entry_cooldown_active",
}


def _scanner_terminal_block_fresh_input_confirmed(fields):
    fields = fields if isinstance(fields, dict) else {}
    for key in (
        "reason",
        "source_quality_block_reason",
        "risk_state",
        "stability_window_result",
        "stability_window_reason",
    ):
        text = str(fields.get(key) or "").strip().lower()
        if text in {
            "insufficient_history",
            "not_available",
            "not_evaluated",
            "single_snapshot_only",
            "missing_orderbook_snapshot",
            "stale_ws_snapshot",
        }:
            return False
        if (
            "insufficient_history" in text
            or "not_available" in text
            or "single_snapshot_only" in text
            or "stale_ws_snapshot" in text
        ):
            return False
    for key in (
        "quote_stale",
        "tick_context_stale",
        "price_context_stale",
        "price_context_stale_at_submit",
        "quote_stale_at_submit",
    ):
        value = fields.get(key)
        if value is True or str(value).strip().lower() in {"true", "1", "yes", "stale"}:
            return False
    has_fresh_indicator = False
    for key in ("quote_age_ms", "tick_latest_age_ms"):
        value = fields.get(key)
        if value is None:
            continue
        text = str(value).strip().lower()
        if not text or text.startswith("not_available") or text.startswith("missing"):
            return False
        has_fresh_indicator = True
    for key in ("quote_age_source", "tick_context_quality"):
        value = fields.get(key)
        if value is None:
            continue
        text = str(value).strip().lower()
        if not text or "stale" in text or text.startswith("not_available") or text.startswith("missing"):
            return False
        has_fresh_indicator = True
    snapshot_source = str(fields.get("snapshot_source") or "").strip().lower()
    if snapshot_source in {"missing_ws_snapshot", "missing_orderbook_snapshot"}:
        return False
    return has_fresh_indicator


def _remember_scanner_terminal_block(stock, stage, fields):
    if not isinstance(stock, dict) or stage not in SCANNER_WATCH_EVICTION_TERMINAL_STAGES:
        return
    if not _is_scanner_watching_runtime_observation_target(stock):
        return
    reason = (
        fields.get("terminal_reason")
        or fields.get("strength_momentum_reason")
        or fields.get("reason")
        or fields.get("blocked_reason")
        or stage
    )
    stock["_scanner_watch_last_terminal_block"] = {
        "stage": str(stage),
        "reason": str(reason or stage),
        "observed_epoch": time.time(),
        "fresh_input_confirmed": _scanner_terminal_block_fresh_input_confirmed(fields),
    }


def _reset_scanner_terminal_eviction_memory(stock):
    if not isinstance(stock, dict):
        return
    for key in (
        "_scanner_watch_last_terminal_block",
        "_scanner_watch_eviction_terminal_stage",
        "_scanner_watch_eviction_terminal_reason",
        "_scanner_watch_eviction_terminal_count",
        "_scanner_watch_eviction_last_terminal_observed_epoch",
    ):
        stock.pop(key, None)


def _remember_scanner_pool_block(stock, skip_reason, fields, *, now_ts):
    if not isinstance(stock, dict) or not _is_scanner_watching_runtime_observation_target(stock):
        return
    reason = str(skip_reason or "")
    if reason not in SCANNER_WATCH_EVICTION_POOL_BLOCK_SKIP_REASONS:
        return
    stock["_scanner_watch_last_pool_block"] = {
        "reason": reason,
        "observed_epoch": float(now_ts),
        "cooldown_remaining_sec": fields.get("cooldown_remaining_sec", "not_applicable_cooldown_remaining_sec"),
    }


def _log_entry_pipeline(stock, code, stage, **fields):
    record_id = stock.get("id") if isinstance(stock, dict) else None
    merged_fields = {
        **_scanner_promotion_correlation_fields(stock),
        **fields,
    }
    _remember_scanner_terminal_block(stock, stage, merged_fields)
    emit_pipeline_event(
        "ENTRY_PIPELINE",
        stock.get("name"),
        code,
        stage,
        record_id=record_id,
        fields=merged_fields,
    )


def _is_scanner_watching_runtime_observation_target(stock) -> bool:
    if not isinstance(stock, dict):
        return False
    strategy = normalize_strategy(stock.get("strategy"))
    pos_tag = normalize_position_tag(strategy, stock.get("position_tag"))
    if strategy != "SCALPING" or pos_tag != "SCANNER":
        return False
    return bool(
        stock.get("scanner_promotion_id")
        or stock.get("scanner_promotion_reason")
        or stock.get("entry_armed_at_epoch")
    )


def _env_bool(name: str, default: bool = False) -> bool:
    raw = os.getenv(name, "")
    text = str(raw).strip().lower()
    if not text:
        return bool(default)
    if text in {"1", "true", "yes", "y", "on"}:
        return True
    if text in {"0", "false", "no", "n", "off"}:
        return False
    return bool(default)


def _env_int(name: str, default: int) -> int:
    raw = os.getenv(name, "")
    text = str(raw).strip()
    if not text:
        return int(default)
    try:
        return int(text)
    except Exception:
        return int(default)


def _scanner_rising_entry_min_delta_pct() -> float:
    raw = os.getenv("KORSTOCKSCAN_SCANNER_RISING_FULL_EVAL_MIN_DELTA_PCT", "")
    try:
        value = float(str(raw).strip()) if str(raw).strip() else 0.5
    except Exception:
        value = 0.5
    return max(0.0, min(value, 20.0))


def _scanner_positive_delta_pct(stock) -> float:
    stock = stock or {}
    _hydrate_scanner_promotion_runtime_context(stock)
    return max(
        0.0,
        _safe_float(stock.get("price_delta_since_first_seen_pct"), 0.0),
        _safe_float(stock.get("comparable_flu_delta_since_first_seen"), 0.0),
    )


def _scanner_rising_entry_relief_eligible(stock) -> bool:
    if not _is_scanner_watching_runtime_observation_target(stock):
        return False
    return _scanner_positive_delta_pct(stock) >= _scanner_rising_entry_min_delta_pct()


