def _scanner_active_rising_recheck_reason(stock, *, now_ts: float | None = None) -> str | None:
    stock = stock or {}
    now_value = time.time() if now_ts is None else float(now_ts)
    recheck_keys = (
        ("_scanner_rising_cooldown_recheck_after_epoch", "cooldown_recheck_pending"),
        ("_scanner_rising_cutoff_recheck_after_epoch", "next_buy_window_recheck_pending"),
        ("_scanner_rising_ws_gap_priority_recheck_after_epoch", "ws_gap_recovery_deferred_priority"),
    )
    for epoch_key, default_reason in recheck_keys:
        recheck_epoch = _safe_float(stock.get(epoch_key), 0.0)
        if recheck_epoch > now_value:
            return default_reason
    return None


def _scanner_active_full_eval_budget_source(stock, *, now_ts: float | None = None) -> str | None:
    reason = _scanner_active_rising_recheck_reason(stock, now_ts=now_ts)
    if not reason:
        return None
    if reason == "cooldown_recheck_pending":
        return "not_applicable_cooldown"
    if reason == "next_buy_window_recheck_pending":
        return "not_applicable_cutoff"
    if reason == "ws_gap_recovery_deferred_priority":
        return "not_applicable_ws_gap"
    return stock.get("_scanner_full_eval_budget_source")


def _scanner_rising_relief_observation_fields(
    stock,
    *,
    reason: str | None = None,
    budget_source: str | None = None,
    now_ts: float | None = None,
) -> dict[str, Any]:
    stock = stock or {}
    active_recheck_reason = _scanner_active_rising_recheck_reason(stock, now_ts=now_ts)
    active_budget_source = _scanner_active_full_eval_budget_source(stock, now_ts=now_ts)
    return {
        "rising_entry_relief_eligible": bool(_scanner_rising_entry_relief_eligible(stock)),
        "rising_entry_relief_reason": reason
        or active_recheck_reason
        or "not_applicable_rising_entry_relief",
        "scanner_positive_delta_pct": round(_scanner_positive_delta_pct(stock), 4),
        "scanner_full_eval_budget_source": budget_source
        or active_budget_source
        or "not_applicable_full_eval_budget_source",
    }


def _ws_realtime_type_freshness_fields(ws_data: dict | None, *, now_ts: float | None = None) -> dict[str, Any]:
    ws_data = ws_data if isinstance(ws_data, dict) else {}
    now_value = time.time() if now_ts is None else float(now_ts)

    def _age_ms(ts_value):
        ts = _safe_float(ts_value, 0.0)
        if ts <= 0:
            return "not_available_realtime_type_age_ms"
        return round(max(0.0, now_value - ts) * 1000.0, 3)

    received = ws_data.get("received_types") or []
    try:
        received_types = sorted(str(item) for item in received if str(item).strip())
    except Exception:
        received_types = []
    type_ts = ws_data.get("last_realtime_type_ts")
    type_ts = type_ts if isinstance(type_ts, dict) else {}
    history = ws_data.get("strength_momentum_history") or []
    history_count = len(history) if hasattr(history, "__len__") else 0
    latest_history_ts = 0.0
    if history_count > 0:
        try:
            latest = history[-1]
            latest_history_ts = _safe_float((latest or {}).get("ts"), 0.0) if isinstance(latest, dict) else 0.0
        except Exception:
            latest_history_ts = 0.0
    last_trade = ws_data.get("last_trade_tick")
    last_trade_ts = _safe_float((last_trade or {}).get("ts"), 0.0) if isinstance(last_trade, dict) else 0.0
    return {
        "ws_received_types": ",".join(received_types) if received_types else "-",
        "ws_received_type_count": len(received_types),
        "ws_last_0b_age_ms": _age_ms(type_ts.get("0B") or last_trade_ts),
        "ws_last_0d_age_ms": _age_ms(type_ts.get("0D")),
        "ws_last_0w_age_ms": _age_ms(type_ts.get("0w")),
        "ws_last_0f_age_ms": _age_ms(type_ts.get("0F")),
        "ws_last_strength_history_age_ms": _age_ms(latest_history_ts),
        "ws_strength_history_count": int(history_count or 0),
    }


def _numeric_realtime_type_age_ms(value) -> float | None:
    if value in (None, "", "-", "not_available_realtime_type_age_ms"):
        return None
    try:
        return float(value)
    except Exception:
        return None


def _ws_trade_tick_quiet_reason(ws_data: dict | None, *, max_ws_age_ms: float, now_ts: float | None = None) -> str:
    fields = _ws_realtime_type_freshness_fields(ws_data, now_ts=now_ts)
    if _safe_int(fields.get("ws_received_type_count"), 0) <= 0:
        return ""
    quiet_alive_max_ms = max(
        max_ws_age_ms,
        _rule_float("SCANNER_TRADE_TICK_QUIET_NON_TRADE_WS_FRESH_SEC", 10.0) * 1000.0,
    )
    non_trade_ages = [
        _numeric_realtime_type_age_ms(fields.get("ws_last_0d_age_ms")),
        _numeric_realtime_type_age_ms(fields.get("ws_last_0w_age_ms")),
        _numeric_realtime_type_age_ms(fields.get("ws_last_0f_age_ms")),
    ]
    non_trade_fresh = any(age is not None and age <= quiet_alive_max_ms for age in non_trade_ages)
    if not non_trade_fresh:
        return ""
    tick_age_ms = _numeric_realtime_type_age_ms(fields.get("ws_last_0b_age_ms"))
    history_age_ms = _numeric_realtime_type_age_ms(fields.get("ws_last_strength_history_age_ms"))
    trade_tick_stale = tick_age_ms is None or tick_age_ms > max_ws_age_ms
    history_stale = history_age_ms is None or history_age_ms > max_ws_age_ms
    if trade_tick_stale and history_stale:
        return "trade_tick_quiet"
    return ""


def _next_scalping_buy_window_recheck_epoch(now_dt) -> float | None:
    if now_dt is None:
        return None
    now_t = now_dt.time()
    for start, _end in sorted(SCALPING_BUY_WINDOWS, key=lambda window: window[0]):
        if now_t < start:
            return datetime.combine(now_dt.date(), start).timestamp()
    return None


def _scanner_watching_runtime_skip_fields(stock, *, skip_reason: str, now_ts: float, ws_data=None, **extra) -> dict[str, Any]:
    ws_data = ws_data if isinstance(ws_data, dict) else {}
    scanner_fields = _scanner_promotion_correlation_fields(stock)
    return {
        "scanner_promotion_id": scanner_fields.get("scanner_promotion_id")
        or "not_applicable_scanner_promotion_id",
        "scanner_promotion_emitted_epoch": scanner_fields.get("scanner_promotion_emitted_epoch")
        or "not_applicable_scanner_promotion_emitted_epoch",
        "scanner_promotion_reason": scanner_fields.get("scanner_promotion_reason")
        or "not_applicable_scanner_promotion_reason",
        "source_signature": scanner_fields.get("source_signature") or "not_applicable_source_signature",
        "price_delta_since_first_seen_pct": scanner_fields.get("price_delta_since_first_seen_pct")
        or "not_applicable_price_delta_since_first_seen_pct",
        "metric_role": "funnel_count",
        "decision_authority": "real_scalping_scanner_runtime_watchlist_observation_only",
        "window_policy": "intraday_runtime_watchlist",
        "sample_floor": "not_applicable_runtime_observation",
        "primary_decision_metric": "skip_reason",
        "source_quality_gate": "scalping_scanner_watching_runtime_skip_contract",
        "source_quality_route": "runtime_watchlist_skip_observation_only",
        "runtime_effect": False,
        "actual_order_submitted": False,
        "broker_order_forbidden": True,
        "forbidden_uses": (
            "score_threshold_change,provider_route_change,order_price_change,"
            "quantity_or_cap_change,broker_guard_change,real_execution_quality_approval"
        ),
        "skip_reason": skip_reason,
        "target_status": stock.get("status") or "not_applicable_target_status",
        "target_strategy": normalize_strategy(stock.get("strategy")),
        "target_position_tag": normalize_position_tag(normalize_strategy(stock.get("strategy")), stock.get("position_tag")),
        "runtime_record_id": stock.get("id") or "not_applicable_runtime_record_id",
        "entry_armed_at_epoch": stock.get("entry_armed_at_epoch") or "not_applicable_entry_armed_at_epoch",
        "added_time": stock.get("added_time") or "not_applicable_added_time",
        "ws_curr": ws_data.get("curr") if ws_data.get("curr") not in (None, "") else "not_applicable_ws_curr",
        "observed_epoch": f"{float(now_ts):.3f}",
        **_ws_realtime_type_freshness_fields(ws_data, now_ts=now_ts),
        **_scanner_rising_relief_observation_fields(stock, now_ts=now_ts),
        **extra,
    }


def emit_scanner_watching_runtime_skip(stock, code, *, skip_reason: str, now_ts: float | None = None, ws_data=None, throttle_sec: int = 30, **extra) -> bool:
    """Log scanner WATCHING skip causes that otherwise hide before downstream gates."""
    if not _is_scanner_watching_runtime_observation_target(stock):
        return False
    now_value = time.time() if now_ts is None else float(now_ts)
    throttle = max(0, int(throttle_sec or 0))
    key = str(skip_reason or "unknown_skip")
    if key in SCANNER_WATCH_EVICTION_NON_TERMINAL_SKIP_REASONS:
        _reset_scanner_terminal_eviction_memory(stock)
    _remember_scanner_pool_block(stock, key, extra, now_ts=now_value)
    logged = stock.setdefault("_scanner_watching_runtime_skip_logged", {})
    if not isinstance(logged, dict):
        logged = {}
        stock["_scanner_watching_runtime_skip_logged"] = logged
    last_logged = _safe_float(logged.get(key), 0.0)
    if throttle > 0 and now_value - last_logged < throttle:
        return False
    logged[key] = now_value
    _log_entry_pipeline(
        stock,
        code,
        "scalping_scanner_watching_runtime_skip",
        **_scanner_watching_runtime_skip_fields(
            stock,
            skip_reason=key,
            now_ts=now_value,
            ws_data=ws_data,
            **extra,
        ),
    )
    return True


def _scanner_runtime_queue_lag_fields(
    stock,
    *,
    now_ts: float,
    queue_rank: int,
    scanner_queue_rank: int,
    watching_count: int,
    scanner_watching_count: int,
    real_holding_count: int,
    non_real_holding_count: int,
    pre_scanner_runtime_count: int,
    loop_started_epoch: float,
) -> dict[str, Any]:
    scanner_fields = _scanner_promotion_correlation_fields(stock)
    added_time = _safe_float(stock.get("added_time"), 0.0)
    armed_time = _safe_float(stock.get("entry_armed_at_epoch"), 0.0)
    anchor_time = armed_time or added_time
    emit_epoch = float(now_ts)
    loop_epoch = _safe_float(loop_started_epoch, emit_epoch) or emit_epoch
    queue_lag_sec = max(0.0, emit_epoch - anchor_time) if anchor_time > 0 else 0.0
    anchor_to_loop_sec = max(0.0, loop_epoch - anchor_time) if anchor_time > 0 else 0.0
    loop_to_emit_sec = max(0.0, emit_epoch - loop_epoch)
    return {
        "scanner_promotion_id": scanner_fields.get("scanner_promotion_id")
        or "not_applicable_scanner_promotion_id",
        "scanner_promotion_emitted_epoch": scanner_fields.get("scanner_promotion_emitted_epoch")
        or "not_applicable_scanner_promotion_emitted_epoch",
        "scanner_promotion_reason": scanner_fields.get("scanner_promotion_reason")
        or "not_applicable_scanner_promotion_reason",
        "source_signature": scanner_fields.get("source_signature") or "not_applicable_source_signature",
        "metric_role": "funnel_count",
        "decision_authority": "real_scalping_scanner_runtime_watchlist_observation_only",
        "window_policy": "intraday_runtime_watchlist",
        "sample_floor": "not_applicable_runtime_observation",
        "primary_decision_metric": "queue_lag_sec",
        "source_quality_gate": "scalping_scanner_runtime_queue_lag_contract",
        "source_quality_route": "runtime_watchlist_queue_lag_observation_only",
        "runtime_effect": False,
        "actual_order_submitted": False,
        "broker_order_forbidden": True,
        "forbidden_uses": (
            "score_threshold_change,provider_route_change,order_price_change,"
            "quantity_or_cap_change,broker_guard_change,real_execution_quality_approval"
        ),
        "queue_rank": int(queue_rank or 0),
        "scanner_queue_rank": int(scanner_queue_rank or 0),
        "watching_count": int(watching_count or 0),
        "scanner_watching_count": int(scanner_watching_count or 0),
        "real_holding_count": int(real_holding_count or 0),
        "non_real_holding_count": int(non_real_holding_count or 0),
        "pre_scanner_runtime_count": int(pre_scanner_runtime_count or 0),
        "queue_lag_sec": round(queue_lag_sec, 3),
        "anchor_to_loop_sec": round(anchor_to_loop_sec, 3),
        "loop_to_emit_sec": round(loop_to_emit_sec, 3),
        "pre_emit_delay_sec": round(loop_to_emit_sec, 3),
        "loop_started_epoch": f"{loop_epoch:.3f}",
        "queue_emit_epoch": f"{emit_epoch:.3f}",
        "target_status": stock.get("status") or "not_applicable_target_status",
        "target_strategy": normalize_strategy(stock.get("strategy")),
        "target_position_tag": normalize_position_tag(normalize_strategy(stock.get("strategy")), stock.get("position_tag")),
        "runtime_record_id": stock.get("id") or "not_applicable_runtime_record_id",
        "entry_armed_at_epoch": stock.get("entry_armed_at_epoch") or "not_applicable_entry_armed_at_epoch",
        "added_time": stock.get("added_time") or "not_applicable_added_time",
        "observed_epoch": f"{float(now_ts):.3f}",
        **_scanner_rising_relief_observation_fields(stock),
    }


def emit_scanner_runtime_queue_lag(
    stock,
    code,
    *,
    now_ts: float | None = None,
    queue_rank: int = 0,
    scanner_queue_rank: int = 0,
    watching_count: int = 0,
    scanner_watching_count: int = 0,
    real_holding_count: int = 0,
    non_real_holding_count: int = 0,
    pre_scanner_runtime_count: int = 0,
    loop_started_epoch: float | None = None,
    throttle_sec: int = 10,
) -> bool:
    """Log scanner WATCHING runtime queue lag before downstream handling."""
    if not _is_scanner_watching_runtime_observation_target(stock):
        return False
    now_value = time.time() if now_ts is None else float(now_ts)
    throttle = max(0, int(throttle_sec or 0))
    last_logged = _safe_float(stock.get("_scanner_runtime_queue_lag_logged_at"), 0.0)
    if throttle > 0 and now_value - last_logged < throttle:
        return False
    stock["_scanner_runtime_queue_lag_logged_at"] = now_value
    _log_entry_pipeline(
        stock,
        code,
        "scalping_scanner_runtime_queue_lag",
        **_scanner_runtime_queue_lag_fields(
            stock,
            now_ts=now_value,
            queue_rank=queue_rank,
            scanner_queue_rank=scanner_queue_rank,
            watching_count=watching_count,
            scanner_watching_count=scanner_watching_count,
            real_holding_count=real_holding_count,
            non_real_holding_count=non_real_holding_count,
            pre_scanner_runtime_count=pre_scanner_runtime_count,
            loop_started_epoch=now_value if loop_started_epoch is None else float(loop_started_epoch),
        ),
    )
    return True


def _scanner_fast_precheck_fields(
    stock,
    *,
    now_ts: float,
    ws_data=None,
    queue_rank: int = 0,
    scanner_queue_rank: int = 0,
    watching_count: int = 0,
    scanner_watching_count: int = 0,
) -> dict[str, Any]:
    ws_data = ws_data if isinstance(ws_data, dict) else {}
    scanner_fields = _scanner_promotion_correlation_fields(stock)
    added_time = _safe_float((stock or {}).get("added_time"), 0.0)
    armed_time = _safe_float((stock or {}).get("entry_armed_at_epoch"), 0.0)
    anchor_time = armed_time or added_time
    quote_age_sec = _get_ws_snapshot_age_sec(ws_data)
    curr = _safe_int(ws_data.get("curr"), 0)
    max_age_sec = _rule_float("SCALP_PRE_AI_MAX_WS_AGE_SEC", 3.0)
    realtime_type_ts = ws_data.get("last_realtime_type_ts")
    realtime_type_ts = realtime_type_ts if isinstance(realtime_type_ts, dict) else {}
    last_0b_age_sec = None
    last_0b_ts = _safe_float(realtime_type_ts.get("0B"), 0.0)
    if last_0b_ts > 0:
        last_0b_age_sec = max(0.0, float(now_ts) - last_0b_ts)
    history = ws_data.get("strength_momentum_history") or []
    latest_history_ts = 0.0
    if isinstance(history, list):
        for item in reversed(history):
            if isinstance(item, dict):
                latest_history_ts = _safe_float(item.get("ts") or item.get("timestamp"), 0.0)
                if latest_history_ts > 0:
                    break
    latest_history_age_sec = None
    if latest_history_ts > 0:
        latest_history_age_sec = max(0.0, float(now_ts) - latest_history_ts)
    fresh_realtime_evidence = (
        (last_0b_age_sec is not None and last_0b_age_sec <= max_age_sec)
        or (latest_history_age_sec is not None and latest_history_age_sec <= max_age_sec)
    )
    subscription_recheck_age_sec = _safe_float(
        ws_data.get("scanner_subscription_recheck_age_sec"),
        999999.0,
    )
    subscription_recheck_fresh_sec = _safe_float(
        ws_data.get("scanner_subscription_recheck_fresh_sec"),
        0.0,
    )
    subscription_recheck_fresh_realtime_evidence = (
        subscription_recheck_fresh_sec > 0
        and (
            (last_0b_age_sec is not None and last_0b_age_sec <= subscription_recheck_fresh_sec)
            or (
                latest_history_age_sec is not None
                and latest_history_age_sec <= subscription_recheck_fresh_sec
            )
        )
    )
    rising_subscription_recheck_curr_relief = (
        quote_age_sec is not None
        and quote_age_sec > max_age_sec
        and bool(ws_data.get("scanner_subscription_recheck_entry_relief"))
        and subscription_recheck_fresh_sec > 0
        and subscription_recheck_age_sec <= subscription_recheck_fresh_sec
        and _scanner_rising_entry_relief_eligible(stock)
    )
    rising_realtime_relief = (
        quote_age_sec is not None
        and quote_age_sec > max_age_sec
        and fresh_realtime_evidence
        and _scanner_rising_entry_relief_eligible(stock)
    )
    rising_subscription_recheck_relief = (
        rising_subscription_recheck_curr_relief
        and subscription_recheck_fresh_realtime_evidence
    )
    rest_quote_only_recovery = (
        str(ws_data.get("ws_snapshot_recovery_source") or "").strip()
        == "ka10001_rest_quote_fallback"
        and not fresh_realtime_evidence
        and not subscription_recheck_fresh_realtime_evidence
    )
    rest_quote_anchor_price = _scanner_rest_quote_recovery_anchor_price(scanner_fields)
    rest_quote_anchor_gap_max_pct = _scanner_rest_quote_recovery_anchor_gap_max_pct()
    rest_quote_anchor_gap_pct = (
        (float(rest_quote_anchor_price) - float(curr)) / float(rest_quote_anchor_price) * 100.0
        if rest_quote_anchor_price > 0 and curr > 0 and curr < rest_quote_anchor_price
        else 0.0
    )
    rest_quote_promotion_conflict = (
        rest_quote_only_recovery
        and rest_quote_anchor_price > 0
        and curr > 0
        and rest_quote_anchor_gap_pct > rest_quote_anchor_gap_max_pct
    )
    rising_rest_quote_relief = (
        rest_quote_only_recovery
        and not rest_quote_promotion_conflict
        and _scanner_rising_rest_quote_full_eval_relief_enabled()
        and _scanner_rising_entry_relief_eligible(stock)
        and _scanner_positive_delta_pct(stock) >= _scanner_rising_rest_quote_full_eval_min_delta_pct()
    )
    rising_stale_ws_relief = (
        quote_age_sec is not None
        and quote_age_sec > max_age_sec
        and not rising_realtime_relief
        and not rising_subscription_recheck_relief
        and not rest_quote_only_recovery
        and _scanner_rising_stale_ws_full_eval_relief_enabled()
        and _scanner_rising_entry_relief_eligible(stock)
        and _scanner_positive_delta_pct(stock) >= _scanner_rising_stale_ws_full_eval_min_delta_pct()
    )
    if curr <= 0:
        result = "source_quality_blocked"
        reason = "missing_or_zero_curr"
    elif rest_quote_promotion_conflict:
        result = "stability_pending"
        reason = "rest_quote_conflicts_with_scanner_promotion"
    elif rest_quote_only_recovery and not rising_rest_quote_relief:
        result = "stability_pending"
        reason = "rest_quote_without_realtime_strength"
    elif (
        quote_age_sec is not None
        and quote_age_sec > max_age_sec
        and not rising_realtime_relief
        and not rising_subscription_recheck_relief
        and not rising_stale_ws_relief
    ):
        result = "stability_pending"
        reason = (
            "subscription_recheck_without_realtime_strength"
            if rising_subscription_recheck_curr_relief
            else "stale_ws_snapshot"
        )
    else:
        result = "eligible_for_heavy_entry_eval"
        reason = (
            "rising_realtime_type_fresh_quote_timestamp_stale"
            if rising_realtime_relief
            else "rising_subscription_recheck_fresh_realtime_evidence"
            if rising_subscription_recheck_relief
            else "rising_rest_quote_recovery_without_realtime_strength"
            if rising_rest_quote_relief
            else "rising_stale_ws_snapshot_full_eval_relief"
            if rising_stale_ws_relief
            else "fast_precheck_pass"
        )
    return {
        "scanner_promotion_id": scanner_fields.get("scanner_promotion_id")
        or "not_applicable_scanner_promotion_id",
        "scanner_promotion_emitted_epoch": scanner_fields.get("scanner_promotion_emitted_epoch")
        or "not_applicable_scanner_promotion_emitted_epoch",
        "scanner_promotion_reason": scanner_fields.get("scanner_promotion_reason")
        or "not_applicable_scanner_promotion_reason",
        "source_signature": scanner_fields.get("source_signature") or "not_applicable_source_signature",
        "metric_role": "funnel_count",
        "decision_authority": "real_scalping_scanner_fast_precheck_observation_only",
        "window_policy": "intraday_runtime_watchlist",
        "sample_floor": "not_applicable_runtime_observation",
        "primary_decision_metric": "fast_precheck_lag_sec",
        "source_quality_gate": "scalping_scanner_fast_precheck_contract",
        "source_quality_route": "runtime_watchlist_fast_precheck_observation_only",
        "runtime_effect": False,
        "actual_order_submitted": False,
        "broker_order_forbidden": True,
        "forbidden_uses": (
            "score_threshold_change,provider_route_change,order_price_change,"
            "quantity_or_cap_change,broker_guard_change,real_execution_quality_approval"
        ),
        "fast_precheck_result": result,
        "fast_precheck_reason": reason,
        "fast_precheck_realtime_relief_applied": bool(rising_realtime_relief),
        "fast_precheck_subscription_recheck_relief_applied": bool(
            rising_subscription_recheck_curr_relief
        ),
        "fast_precheck_rest_quote_relief_applied": bool(rising_rest_quote_relief),
        "fast_precheck_rest_quote_relief_min_delta_pct": (
            round(_scanner_rising_rest_quote_full_eval_min_delta_pct(), 4)
            if rising_rest_quote_relief
            else "not_applicable_rest_quote_relief_min_delta_pct"
        ),
        "fast_precheck_rest_quote_anchor_price": (
            int(rest_quote_anchor_price)
            if rest_quote_only_recovery and rest_quote_anchor_price > 0
            else "not_applicable_rest_quote_anchor_price"
        ),
        "fast_precheck_rest_quote_anchor_gap_pct": (
            round(rest_quote_anchor_gap_pct, 3)
            if rest_quote_only_recovery and rest_quote_anchor_price > 0 and curr > 0
            else "not_applicable_rest_quote_anchor_gap_pct"
        ),
        "fast_precheck_rest_quote_anchor_gap_max_pct": (
            round(rest_quote_anchor_gap_max_pct, 3)
            if rest_quote_only_recovery
            else "not_applicable_rest_quote_anchor_gap_max_pct"
        ),
        "fast_precheck_rest_quote_consistency_status": (
            "conflicts_with_scanner_promotion"
            if rest_quote_promotion_conflict
            else "pass"
            if rest_quote_only_recovery
            else "not_applicable_rest_quote_consistency"
        ),
        "fast_precheck_stale_ws_relief_applied": bool(rising_stale_ws_relief),
        "fast_precheck_stale_ws_relief_min_delta_pct": (
            round(_scanner_rising_stale_ws_full_eval_min_delta_pct(), 4)
            if rising_stale_ws_relief
            else "not_applicable_stale_ws_relief_min_delta_pct"
        ),
        "fast_precheck_subscription_recheck_age_sec": (
            round(subscription_recheck_age_sec, 3)
            if subscription_recheck_age_sec < 999999.0
            else "not_applicable_subscription_recheck_age_sec"
        ),
        "fast_precheck_subscription_recheck_fresh_sec": (
            round(subscription_recheck_fresh_sec, 3)
            if subscription_recheck_fresh_sec > 0
            else "not_applicable_subscription_recheck_fresh_sec"
        ),
        "fast_precheck_realtime_relief_scope": (
            "rising_entry_relief_only"
            if (
                rising_realtime_relief
                or rising_subscription_recheck_curr_relief
                or rising_rest_quote_relief
                or rising_stale_ws_relief
            )
            else "not_applicable"
        ),
        "fast_precheck_seen_epoch": f"{float(now_ts):.3f}",
        "fast_precheck_lag_sec": round(max(0.0, float(now_ts) - anchor_time), 3) if anchor_time > 0 else 0.0,
        "heavy_queue_enter_epoch": f"{float(now_ts):.3f}" if result == "eligible_for_heavy_entry_eval" else "not_queued",
        "queue_rank": int(queue_rank or 0),
        "scanner_queue_rank": int(scanner_queue_rank or 0),
        "watching_count": int(watching_count or 0),
        "scanner_watching_count": int(scanner_watching_count or 0),
        "quote_age_ms": (
            round(float(quote_age_sec) * 1000.0, 3)
            if quote_age_sec is not None
            else "not_available_quote_age_ms"
        ),
        "snapshot_source": "ws_manager_latest_data" if ws_data else "missing_ws_snapshot",
        **_ws_realtime_type_freshness_fields(ws_data, now_ts=now_ts),
        "target_status": (stock or {}).get("status") or "not_applicable_target_status",
        "target_strategy": normalize_strategy((stock or {}).get("strategy")),
        "target_position_tag": normalize_position_tag(
            normalize_strategy((stock or {}).get("strategy")),
            (stock or {}).get("position_tag"),
        ),
        "runtime_record_id": (stock or {}).get("id") or "not_applicable_runtime_record_id",
        "entry_armed_at_epoch": (stock or {}).get("entry_armed_at_epoch") or "not_applicable_entry_armed_at_epoch",
        "added_time": (stock or {}).get("added_time") or "not_applicable_added_time",
        **_scanner_rising_relief_observation_fields(stock),
    }


def emit_scanner_fast_precheck(
    stock,
    code,
    *,
    now_ts: float | None = None,
    ws_data=None,
    queue_rank: int = 0,
    scanner_queue_rank: int = 0,
    watching_count: int = 0,
    scanner_watching_count: int = 0,
    throttle_sec: int = 5,
) -> bool:
    """Emit an order-forbidden scanner precheck before the heavy WATCHING handler."""
    if not _is_scanner_watching_runtime_observation_target(stock):
        return False
    now_value = time.time() if now_ts is None else float(now_ts)
    throttle = max(0, int(throttle_sec or 0))
    last_logged = _safe_float(stock.get("_scanner_fast_precheck_logged_at"), 0.0)
    if throttle > 0 and now_value - last_logged < throttle:
        return False
    stock["_scanner_fast_precheck_logged_at"] = now_value
    fields = _scanner_fast_precheck_fields(
        stock,
        now_ts=now_value,
        ws_data=ws_data,
        queue_rank=queue_rank,
        scanner_queue_rank=scanner_queue_rank,
        watching_count=watching_count,
        scanner_watching_count=scanner_watching_count,
    )
    if fields.get("fast_precheck_result") == "eligible_for_heavy_entry_eval":
        stock["_scanner_heavy_queue_enter_epoch"] = now_value
    stock["_scanner_fast_precheck_result"] = fields.get("fast_precheck_result")
    stock["_scanner_fast_precheck_reason"] = fields.get("fast_precheck_reason")
    _log_entry_pipeline(stock, code, "scalping_scanner_fast_precheck", **fields)
    return True


def _scanner_heavy_eval_lag_fields(stock, *, now_ts: float, queue_enter_epoch: float | None = None) -> dict[str, Any]:
    scanner_fields = _scanner_promotion_correlation_fields(stock)
    enter_epoch = _safe_float(queue_enter_epoch, 0.0) or _safe_float(
        (stock or {}).get("_scanner_heavy_queue_enter_epoch"),
        float(now_ts),
    )
    return {
        "scanner_promotion_id": scanner_fields.get("scanner_promotion_id")
        or "not_applicable_scanner_promotion_id",
        "scanner_promotion_emitted_epoch": scanner_fields.get("scanner_promotion_emitted_epoch")
        or "not_applicable_scanner_promotion_emitted_epoch",
        "source_signature": scanner_fields.get("source_signature") or "not_applicable_source_signature",
        "metric_role": "funnel_count",
        "decision_authority": "real_scalping_scanner_heavy_eval_observation_only",
        "window_policy": "intraday_runtime_watchlist",
        "sample_floor": "not_applicable_runtime_observation",
        "primary_decision_metric": "heavy_queue_wait_sec",
        "source_quality_gate": "scalping_scanner_heavy_eval_lag_contract",
        "source_quality_route": "runtime_watchlist_heavy_eval_lag_observation_only",
        "runtime_effect": False,
        "actual_order_submitted": False,
        "broker_order_forbidden": True,
        "forbidden_uses": (
            "score_threshold_change,provider_route_change,order_price_change,"
            "quantity_or_cap_change,broker_guard_change,real_execution_quality_approval"
        ),
        "heavy_queue_enter_epoch": f"{float(enter_epoch):.3f}",
        "heavy_eval_started_epoch": f"{float(now_ts):.3f}",
        "heavy_queue_wait_sec": round(max(0.0, float(now_ts) - float(enter_epoch)), 3),
        "target_status": (stock or {}).get("status") or "not_applicable_target_status",
        "target_strategy": normalize_strategy((stock or {}).get("strategy")),
        "target_position_tag": normalize_position_tag(
            normalize_strategy((stock or {}).get("strategy")),
            (stock or {}).get("position_tag"),
        ),
        "runtime_record_id": (stock or {}).get("id") or "not_applicable_runtime_record_id",
        **_scanner_rising_relief_observation_fields(stock),
    }


def emit_scanner_heavy_eval_lag(
    stock,
    code,
    *,
    now_ts: float | None = None,
    queue_enter_epoch: float | None = None,
    throttle_sec: int = 5,
) -> bool:
    """Log the delay between fast precheck eligibility and heavy WATCHING evaluation."""
    if not _is_scanner_watching_runtime_observation_target(stock):
        return False
    now_value = time.time() if now_ts is None else float(now_ts)
    throttle = max(0, int(throttle_sec or 0))
    last_logged = _safe_float(stock.get("_scanner_heavy_eval_lag_logged_at"), 0.0)
    if throttle > 0 and now_value - last_logged < throttle:
        return False
    stock["_scanner_heavy_eval_lag_logged_at"] = now_value
    _log_entry_pipeline(
        stock,
        code,
        "scalping_scanner_heavy_eval_lag",
        **_scanner_heavy_eval_lag_fields(stock, now_ts=now_value, queue_enter_epoch=queue_enter_epoch),
    )
    return True


def _scanner_promotion_correlation_fields(stock) -> dict[str, Any]:
    if not isinstance(stock, dict):
        return {}
    anchor_epoch = _safe_float(stock.get("entry_armed_at_epoch"), 0.0)
    promotion_epoch = _safe_float(stock.get("scanner_promotion_emitted_epoch"), 0.0)
    needs_refresh = (
        not stock.get("scanner_promotion_id")
        or not _scanner_promotion_price_anchor_present(stock)
        or (
            anchor_epoch > 0.0
            and promotion_epoch > 0.0
            and abs(anchor_epoch - promotion_epoch) > 5.0
        )
    )
    if needs_refresh and str(stock.get("position_tag") or "").upper() == "SCANNER":
        _hydrate_scanner_promotion_runtime_context(stock)
    fields: dict[str, Any] = {}
    for key in (
        "scanner_promotion_id",
        "scanner_promotion_emitted_epoch",
        "scanner_promotion_reason",
        "source_signature",
        "first_seen_price",
        "current_price",
        "current_price_observed",
        "price_delta_since_first_seen_pct",
    ):
        value = stock.get(key)
        if value not in (None, ""):
            fields[key] = value
    return fields


def _log_ai_confirmed_terminal_no_budget(
    stock,
    code,
    *,
    terminal_reason: str,
    source_stage: str,
    ai_decision=None,
    ai_score=None,
    entry_score_threshold: float = 75.0,
    extra_fields: dict[str, Any] | None = None,
) -> None:
    stock_fields = stock if isinstance(stock, dict) else {}
    action = str((ai_decision or {}).get("action") or stock_fields.get("last_watching_ai_action") or "WAIT").upper()
    score_value = _safe_float(ai_score if ai_score is not None else (ai_decision or {}).get("score"), 0.0)
    contract_fields = {
        **_build_observation_contract_fields("funnel_count"),
        "decision_authority": "ai_confirmed_terminal_attribution_only",
        "primary_decision_metric": "funnel_count",
        "source_quality_gate": "terminal_reason_contract_fields_present",
    }
    contract_fields = _ensure_ai_source_quality_fields(
        contract_fields,
        stock if isinstance(stock, dict) else None,
        not_evaluated_reason="ai_confirmed_terminal_no_budget_source_quality_missing",
    )
    _log_entry_pipeline(
        stock,
        code,
        "ai_confirmed_terminal_no_budget",
        **contract_fields,
        actual_order_submitted=False,
        broker_order_forbidden=True,
        allowed_runtime_apply=False,
        terminal_reason=str(terminal_reason or "unknown_terminal_no_budget"),
        source_stage=str(source_stage or "unknown"),
        ai_score=f"{score_value:.1f}",
        ai_action=action or "UNKNOWN",
        entry_score_threshold=f"{float(entry_score_threshold):.1f}",
        **(extra_fields or {}),
    )


def _should_first_ai_wait_for_big_bite(
    ai_decision=None,
    ai_score=None,
    *,
    big_bite_confirmed: bool = False,
    entry_score_threshold: float = 75.0,
) -> bool:
    if big_bite_confirmed:
        return False
    action = str((ai_decision or {}).get("action") or "").upper()
    score_value = _safe_float(ai_score if ai_score is not None else (ai_decision or {}).get("score"), 0.0)
    return not (action == "BUY" and score_value >= float(entry_score_threshold))


def _log_swing_entry_policy_evaluated(stock, code, *, strategy, source_stage, **policy_inputs):
    policy = evaluate_swing_entry_lifecycle_policy(
        strategy=strategy,
        source_stage=source_stage,
        **policy_inputs,
    )
    _log_entry_pipeline(stock, code, "swing_entry_policy_evaluated", **policy.as_log_fields())
    return policy


def _entry_adm_candidate_id(stock, code) -> str:
    if not isinstance(stock, dict):
        return f"ADM-{code}-{int(time.time() * 1000)}-{uuid4().hex[:6]}"
    existing = str(stock.get("entry_adm_candidate_id") or "").strip()
    if existing:
        return existing
    record_id = stock.get("id") or "noid"
    candidate_id = f"ADM-{code}-{record_id}-{int(time.time() * 1000)}-{uuid4().hex[:6]}"
    _mutate_stock_state(stock, set_fields={"entry_adm_candidate_id": candidate_id})
    return candidate_id


def _entry_adm_action_from_context(stage: str, *, ai_decision=None, ai_score=None, latency_gate=None, submit_fields=None) -> str:
    stage = str(stage or "")
    submit_fields = submit_fields or {}
    latency_gate = latency_gate or {}
    if stage in {"pre_submit_liquidity_guard_block", "pre_submit_overbought_pullback_guard_block"}:
        return "SKIP_PRE_SUBMIT_SAFETY"
    if stage == "entry_submit_revalidation_block" or bool(submit_fields.get("entry_submit_revalidation_block")):
        return "SKIP_STALE"
    if stage in {"entry_submit_revalidation_warning", "latency_block"}:
        return "WAIT_REQUOTE"
    if stage in {"latency_pass", "order_bundle_submitted"}:
        guard = str(latency_gate.get("entry_price_guard") or "").lower()
        canary_action = str(latency_gate.get("ai_entry_price_canary_action") or "").upper()
        if "defensive" in guard or canary_action == "USE_DEFENSIVE":
            return "BUY_DEFENSIVE"
        return "BUY_NOW"
    if bool(submit_fields.get("entry_submit_revalidation_warning")):
        return "WAIT_REQUOTE"
    action = str((ai_decision or {}).get("action") or "").upper()
    score_value = _safe_float(ai_score if ai_score is not None else (ai_decision or {}).get("score"), 0.0)
    if action == "BUY" and score_value >= 75:
        guard = str(latency_gate.get("entry_price_guard") or "").lower()
        canary_action = str(latency_gate.get("ai_entry_price_canary_action") or "").upper()
        if "defensive" in guard or canary_action == "USE_DEFENSIVE":
            return "BUY_DEFENSIVE"
        return "BUY_NOW"
    if stage == "blocked_ai_score":
        reason = str((ai_decision or {}).get("ai_input_source_quality_reason") or "").lower()
        return "SKIP_SOURCE_QUALITY" if "source" in reason or "stale" in reason else "NO_BUY_AI"
    return "NO_BUY_AI"


def _emit_scalp_entry_adm_snapshot(
    stock,
    code,
    stage,
    *,
    ai_decision=None,
    ai_score=None,
    chosen_action=None,
    latency_gate=None,
    submit_fields=None,
    price_snapshot=None,
    orderbook_fields=None,
    actual_order_submitted=False,
    broker_order_forbidden=True,
    extra_fields=None,
):
    if not isinstance(stock, dict) or str(stock.get("strategy") or "SCALPING").upper() not in {"SCALPING", "SCALP"}:
        return
    action = chosen_action or _entry_adm_action_from_context(
        stage,
        ai_decision=ai_decision,
        ai_score=ai_score,
        latency_gate=latency_gate,
        submit_fields=submit_fields,
    )
    candidate_id = _entry_adm_candidate_id(stock, code)
    eligible = {
        "BUY_NOW": "BUY_NOW,BUY_DEFENSIVE,WAIT_REQUOTE,NO_BUY_AI",
        "BUY_DEFENSIVE": "BUY_NOW,BUY_DEFENSIVE,WAIT_REQUOTE,NO_BUY_AI",
        "WAIT_REQUOTE": "WAIT_REQUOTE,SKIP_STALE,NO_BUY_AI",
        "SKIP_STALE": "WAIT_REQUOTE,SKIP_STALE,NO_BUY_AI",
        "SKIP_PRE_SUBMIT_SAFETY": "SKIP_PRE_SUBMIT_SAFETY,NO_BUY_AI",
        "SKIP_SOURCE_QUALITY": "SKIP_SOURCE_QUALITY,NO_BUY_AI",
        "NO_BUY_AI": "NO_BUY_AI",
    }.get(action, "NO_BUY_AI")
    rejected = ",".join(item for item in ("BUY_NOW", "WAIT_REQUOTE", "SKIP_STALE", "BUY_DEFENSIVE", "NO_BUY_AI", "SKIP_SOURCE_QUALITY", "SKIP_PRE_SUBMIT_SAFETY") if item not in eligible)
    observed_ai_action = str(
        (ai_decision or {}).get("action")
        or stock.get("last_watching_ai_action")
        or "not_evaluated"
    )
    fields = {
        "candidate_id": candidate_id,
        "entry_adm_candidate_id": candidate_id,
        "ai_score": f"{_safe_float(ai_score if ai_score is not None else (ai_decision or {}).get('score'), 0.0):.1f}",
        "ai_action": observed_ai_action,
        "chosen_action": action,
        "eligible_actions": eligible,
        "rejected_actions": rejected,
        "metric_role": "action_decision_matrix",
        "decision_authority": "entry_advisory_prompt_context_only",
        "window_policy": "same_day_intraday_events_plus_postclose_sim_post_sell_join",
        "sample_floor": 20,
        "primary_decision_metric": "source_quality_adjusted_ev_pct",
        "source_quality_gate": "entry pipeline event + post-sell sim evaluation join when available",
        "runtime_effect": False,
        "allowed_runtime_apply": False,
        "actual_order_submitted": bool(actual_order_submitted),
        "broker_order_forbidden": bool(broker_order_forbidden),
        "forbidden_uses": "threshold mutation,order guard mutation,provider change,bot restart,broker order submit",
        **_scalp_pre_ai_gate_context_log_fields(stock.get("scalp_pre_ai_gate_context")),
    }
    latency_snapshot_priority_keys = (
        "quote_stale",
        "latency_state",
        "latency_danger_reasons",
        "pre_submit_quote_refresh_enabled",
        "pre_submit_quote_refresh_applied",
        "pre_submit_quote_refresh_reason",
        "pre_submit_quote_refresh_source",
        "pre_submit_quote_refresh_quote_age_ms",
        "pre_submit_ws_snapshot_refresh_enabled",
        "pre_submit_ws_snapshot_refresh_applied",
        "pre_submit_ws_snapshot_refresh_reason",
        "pre_submit_ws_snapshot_refresh_source",
        "pre_submit_ws_snapshot_refresh_age_ms",
        "pre_submit_rest_orderbook_refresh_enabled",
        "pre_submit_rest_orderbook_refresh_applied",
        "pre_submit_rest_orderbook_refresh_reason",
        "pre_submit_rest_orderbook_refresh_source",
        "pre_submit_rest_orderbook_refresh_age_ms",
    )
    for payload in (ai_decision or {}, latency_gate or {}, submit_fields or {}, price_snapshot or {}, orderbook_fields or {}, extra_fields or {}):
        if isinstance(payload, dict):
            for key, value in payload.items():
                if key not in fields and value is not None:
                    fields[key] = value
    fields = _ensure_ai_source_quality_fields(
        fields,
        stock,
        not_evaluated_reason="snapshot_pre_contract_backfill",
    )
    if isinstance(latency_gate, dict):
        for key in latency_snapshot_priority_keys:
            if key in latency_gate and latency_gate.get(key) is not None:
                fields[key] = latency_gate.get(key)
    parity_keys = (
        "tick_acceleration_ratio",
        "tick_acceleration_ratio_raw",
        "tick_accel_source",
        "recent_5tick_seconds",
        "prev_5tick_seconds",
        "tick_accel_effective_recent_5tick_seconds",
        "buy_pressure_10t",
        "curr_vs_micro_vwap_bp",
        "curr_vs_ma5_bp",
    )
    source_quality_fields = stock.get("last_watching_ai_source_quality_fields")
    source_quality_fields = source_quality_fields if isinstance(source_quality_fields, dict) else {}
    for key in parity_keys:
        value = fields.get(key)
        if value in (None, "", "-", "None", "none"):
            fallback = source_quality_fields.get(key)
            if fallback not in (None, "", "-", "None", "none"):
                fields[key] = fallback
    for key in parity_keys:
        fields.setdefault(key, "-")
    if fields.get("ai_reason_numeric_inconsistency") is True:
        fields["source_quality_gate"] = "ai_numeric_consistency_review_required"
        fields["allowed_runtime_apply"] = False
        fields["forbidden_uses"] = (
            "EV/live-auto/runtime-apply/threshold mutation/order guard mutation/"
            "provider change/bot_restart/broker order submit"
        )
    _log_entry_pipeline(stock, code, "scalp_entry_action_decision_snapshot", source_stage=stage, **fields)


