def _shadow_runtime_enabled() -> bool:
    return _rule_bool("OPENAI_DUAL_PERSONA_ENABLED", False)


def _submit_watching_shared_prompt_shadow(*, stock_name, code, ws_data, recent_ticks, recent_candles, gemini_result, record_id=None):
    if (
        not _shadow_runtime_enabled()
        or DUAL_PERSONA_ENGINE is None
        or not hasattr(DUAL_PERSONA_ENGINE, "submit_watching_shared_prompt_shadow")
    ):
        return
    try:
        DUAL_PERSONA_ENGINE.submit_watching_shared_prompt_shadow(
            stock_name=stock_name,
            stock_code=code,
            ws_data=ws_data,
            recent_ticks=recent_ticks,
            recent_candles=recent_candles,
            gemini_result=gemini_result,
            callback=lambda payload: _log_watching_shared_prompt_shadow_result(
                stock_name,
                code,
                payload,
                record_id=record_id,
            ),
        )
    except Exception as e:
        log_error(f"🚨 [WATCHING shared prompt shadow 제출 실패] {stock_name}({code}): {e}")


def _submit_gatekeeper_dual_persona_shadow(*, stock_name, code, strategy, realtime_ctx, gatekeeper, record_id=None):
    if not _shadow_runtime_enabled() or DUAL_PERSONA_ENGINE is None:
        return
    try:
        DUAL_PERSONA_ENGINE.submit_gatekeeper_shadow(
            stock_name=stock_name,
            stock_code=code,
            strategy=strategy,
            realtime_ctx=realtime_ctx,
            gemini_result=gatekeeper,
            callback=lambda payload: _log_dual_persona_shadow_result(
                stock_name,
                code,
                strategy,
                payload,
                record_id=record_id,
            ),
        )
    except Exception as e:
        log_error(f"🚨 [Gatekeeper 듀얼 페르소나 shadow 제출 실패] {stock_name}({code}): {e}")


def _reason_codes(**checks) -> str:
    failed = [name for name, allowed in checks.items() if not allowed]
    return ",".join(failed) if failed else "eligible"


def _get_swing_gap_threshold(strategy: str) -> float:
    fallback = _rule_float('MAX_SWING_GAP_UP_PCT', 3.0)
    strategy_upper = str(strategy or '').upper()
    if strategy_upper == 'KOSPI_ML':
        return _rule_float('MAX_SWING_GAP_UP_PCT_KOSPI', fallback)
    return _rule_float('MAX_SWING_GAP_UP_PCT_KOSDAQ', fallback)


def _resolve_gatekeeper_reject_cooldown(action_label: str) -> tuple[int, str]:
    action_key = normalize_gatekeeper_action_key(action_label)
    if action_key == "pullback_wait":
        return (
            _rule_int('ML_GATEKEEPER_PULLBACK_WAIT_COOLDOWN', 60 * 20),
            'pullback_wait',
        )
    if action_key in {"full_avoid", "neither"}:
        return (
            _rule_int('ML_GATEKEEPER_REJECT_COOLDOWN', 60 * 60 * 2),
            'hard_reject',
        )
    return (
        _rule_int('ML_GATEKEEPER_NEUTRAL_COOLDOWN', 60 * 30),
        'neutral_hold',
    )


def _resolve_stock_marcap(stock, code) -> int:
    """시가총액 조회 (프로세스 레벨 TTL 캐시 + stock 캐시)."""
    existing = _safe_int(stock.get('marcap'), 0)
    if existing > 0:
        return existing
    now_ts = time.time()
    norm_code = str(code or "").strip()[:6]
    _prune_marcap_cache(now_ts)
    if norm_code:
        cached = _MARCAP_CACHE.get(norm_code)
        if cached is not None:
            val, exp_ts = cached
            if now_ts < exp_ts and val > 0:
                stock['marcap'] = val
                return val
    if DB is None:
        return 0
    try:
        marcap = int(DB.get_latest_marcap(code) or 0)
    except Exception:
        marcap = 0
    if marcap > 0 and norm_code:
        _MARCAP_CACHE[norm_code] = (marcap, now_ts + _MARCAP_CACHE_TTL)
        stock['marcap'] = marcap
    return marcap


def _dispatch_scalp_preset_exit(
    *,
    stock,
    code,
    now_ts,
    curr_p,
    buy_p,
    profit_rate,
    peak_profit,
    strategy,
    sell_reason_type,
    reason,
    exit_rule,
    extra_fields: dict | None = None,
    ws_data: dict | None = None,
    admin_id=None,
    market_regime=None,
):
    target_id = stock.get('id')
    expected_qty = _safe_int(stock.get('buy_qty'), 0)
    orig_ord_no = stock.get('preset_tp_ord_no', '')
    preset_ai_score = float(stock.get('rt_ai_prob', 0.5) or 0.5) * 100
    preset_held_sec = _resolve_holding_elapsed_sec(stock, now_ts=now_ts)

    _remember_exit_context(
        stock=stock,
        exit_rule=exit_rule,
        reason=reason,
        peak_profit=peak_profit,
        held_sec=preset_held_sec,
        current_ai_score=preset_ai_score,
    )
    stock['last_exit_reason'] = reason
    exit_decision_source = str(stock.get("last_exit_decision_source") or "MANUAL")
    _log_holding_pipeline(
        stock,
        code,
        "exit_signal",
        sell_reason_type=sell_reason_type,
        reason=reason,
        exit_rule=exit_rule or "-",
        exit_decision_source=exit_decision_source,
        profit_rate=f"{profit_rate:+.2f}",
        peak_profit=f"{peak_profit:+.2f}",
        current_ai_score=f"{preset_ai_score:.0f}",
        held_sec=preset_held_sec,
        curr_price=curr_p,
        buy_price=buy_p,
        buy_qty=expected_qty,
        **(extra_fields or {}),
    )

    if _is_scalp_simulated_position(stock, strategy):
        _complete_scalp_simulated_sell(
            stock=stock,
            code=code,
            ws_data={"curr": curr_p},
            curr_price=curr_p,
            now_ts=now_ts,
            sell_reason_type=sell_reason_type,
            exit_rule=exit_rule,
            profit_rate=profit_rate,
        )
        return

    sell_time_block_fields = _sell_side_open_time_block_fields(
        strategy=strategy,
        sell_reason_type=sell_reason_type,
        exit_rule=exit_rule,
    )
    if bool(sell_time_block_fields.get("sell_time_block_applied")):
        _log_holding_pipeline(
            stock,
            code,
            "sell_order_blocked_open_time",
            sell_reason_type=sell_reason_type,
            exit_rule=exit_rule or "-",
            exit_decision_source=exit_decision_source,
            qty=expected_qty,
            profit_rate=f"{profit_rate:+.2f}",
            actual_order_submitted=False,
            broker_order_forbidden=True,
            runtime_effect=True,
            **sell_time_block_fields,
        )
        log_info(
            f"[SELL_TIME_BLOCK] {stock.get('name', code)} {sell_reason_type} "
            f"SELL blocked before open-time cutoff."
        )
        return

    rem_qty = _confirm_cancel_or_reload_remaining(code, orig_ord_no, KIWOOM_TOKEN, expected_qty)
    ws_context = dict(ws_data or {})
    ws_context.setdefault("curr", curr_p)
    if rem_qty > 0:
        retry_result = _attempt_late_loss_avg_down_retry_before_sell(
            stock=stock,
            code=code,
            ws_data=ws_context,
            strategy=strategy,
            market_regime=market_regime,
            admin_id=admin_id,
            sell_reason_type=sell_reason_type,
            exit_rule=exit_rule,
            profit_rate=profit_rate,
            peak_profit=peak_profit,
            current_ai_score=preset_ai_score,
            held_sec=preset_held_sec,
            now_ts=now_ts,
            context_fields={
                "sell_intercept_context": "preset_tp_after_cancel_remaining",
                "preset_orig_ord_no": orig_ord_no or "-",
                "preset_remaining_qty": rem_qty,
                "preset_expected_qty": expected_qty,
            },
        )
        if retry_result.get("submitted"):
            return

    try:
        if target_id:
            with DB.get_session() as session:
                session.query(RecommendationHistory).filter_by(id=target_id).update({"status": "SELL_ORDERED"})
    except Exception as e:
        log_error(f"🚨 [DB 에러] {stock['name']} SELL_ORDERED 장부 잠금 실패: {e}")

    pending_sell_msg = ""
    set_fields = {
        'last_exit_reason': reason,
    }
    ord_no = ''
    if rem_qty > 0:
        sell_res = _send_exit_best_ioc(code, rem_qty, KIWOOM_TOKEN)
        set_fields.update({
            'exit_requested': True,
            'exit_order_type': '16',
            'exit_order_time': now_ts,
            'sell_order_time': now_ts,
        })
        ord_no = str(sell_res.get('ord_no', '') or '') if isinstance(sell_res, dict) else ''
        if ord_no:
            set_fields['sell_ord_no'] = ord_no
        sign = _resolve_sell_order_sign(sell_reason_type, profit_rate)
        pending_sell_msg = (
            f"{sign} **{stock['name']} 매도 전송 ({strategy})**\n"
            f"사유: `{reason}`\n"
            f"현재가 기준 수익: `{profit_rate:+.2f}%` (고점: {peak_profit:.1f}%)"
        )
        set_fields['pending_sell_msg'] = pending_sell_msg
        _log_holding_pipeline(
            stock,
            code,
            "sell_order_sent",
            sell_reason_type=sell_reason_type,
            exit_rule=exit_rule or "-",
            exit_decision_source=exit_decision_source,
            qty=rem_qty,
            ord_no=ord_no or "-",
            order_type=set_fields.get("exit_order_type") or stock.get("exit_order_type") or "-",
            profit_rate=f"{profit_rate:+.2f}",
            **sell_time_block_fields,
        )

    _mutate_stock_state(
        stock,
        set_fields=set_fields | {
            'status': 'SELL_ORDERED',
            'sell_target_price': curr_p,
        },
    )


def _get_best_levels_from_ws(ws_data):
    orderbook = ws_data.get('orderbook') or {}
    asks = orderbook.get('asks') or []
    bids = orderbook.get('bids') or []
    best_ask = 0
    best_bid = 0
    try:
        if asks:
            best_ask = _safe_int(asks[0].get('price'), 0)
    except Exception:
        best_ask = 0
    try:
        if bids:
            best_bid = _safe_int(bids[0].get('price'), 0)
    except Exception:
            best_bid = 0
    if best_ask <= 0:
        best_ask = _safe_int(
            ws_data.get("best_ask") or ws_data.get("ask_price") or ws_data.get("ask"),
            0,
        )
    if best_bid <= 0:
        best_bid = _safe_int(
            ws_data.get("best_bid") or ws_data.get("bid_price") or ws_data.get("bid"),
            0,
        )
    return best_ask, best_bid


def _pre_submit_refresh_real_ws_snapshot(code: str, ws_data: dict | None, strategy: str) -> tuple[dict, dict]:
    """Refresh the real SCALPING pre-submit snapshot from the live WS manager."""
    base = dict(ws_data or {})
    fields = {
        "pre_submit_ws_snapshot_refresh_enabled": False,
        "pre_submit_ws_snapshot_refresh_applied": False,
        "pre_submit_ws_snapshot_refresh_reason": "not_attempted",
        "pre_submit_ws_snapshot_refresh_source": "ws_manager_latest_data",
        "pre_submit_ws_snapshot_refresh_age_ms": None,
        "pre_submit_ws_snapshot_refresh_best_bid": 0,
        "pre_submit_ws_snapshot_refresh_best_ask": 0,
        "pre_submit_ws_snapshot_refresh_latest_price": _safe_int(base.get("curr"), 0),
    }
    if str(strategy or "").upper() not in {"SCALPING", "SCALP", "KOSPI_ML"}:
        fields["pre_submit_ws_snapshot_refresh_reason"] = "non_scalping"
        return base, fields
    enabled_env = os.getenv("KORSTOCKSCAN_SCALP_PRE_SUBMIT_QUOTE_REFRESH_ENABLED")
    if enabled_env is not None and str(enabled_env).strip().lower() not in {"1", "true", "yes", "y", "on"}:
        fields["pre_submit_ws_snapshot_refresh_reason"] = "disabled"
        return base, fields
    fields["pre_submit_ws_snapshot_refresh_enabled"] = True
    max_age_ms = _safe_int(
        os.getenv("KORSTOCKSCAN_SCALP_PRE_SUBMIT_QUOTE_REFRESH_MAX_AGE_MS"),
        _safe_int(getattr(TRADING_RULES, "SCALP_PRE_SUBMIT_QUOTE_REFRESH_MAX_AGE_MS", 700), 700),
    )
    base_best_ask, base_best_bid = _get_best_levels_from_ws(base)
    base_price = _safe_int(base.get("curr"), 0)
    base_ts = _safe_float(base.get("last_ws_update_ts"), 0.0)
    base_age_ms = None if base_ts <= 0 else max(0.0, (time.time() - base_ts) * 1000.0)
    if base_price > 0 and base_best_bid > 0 and base_best_ask > base_best_bid:
        if base_age_ms is None:
            fields["pre_submit_ws_snapshot_refresh_reason"] = "input_snapshot_timestamp_missing"
            return base, fields
        if base_age_ms <= max_age_ms:
            fields["pre_submit_ws_snapshot_refresh_reason"] = "input_snapshot_fresh"
            return base, fields
    manager = WS_MANAGER
    if manager is None or not hasattr(manager, "get_latest_data"):
        fields["pre_submit_ws_snapshot_refresh_reason"] = "ws_manager_missing"
        return base, fields
    try:
        latest = manager.get_latest_data(code) or {}
    except Exception as exc:
        fields["pre_submit_ws_snapshot_refresh_reason"] = "ws_manager_error"
        fields["pre_submit_ws_snapshot_refresh_error"] = str(exc)[:120]
        return base, fields
    if not isinstance(latest, dict) or not latest:
        fields["pre_submit_ws_snapshot_refresh_reason"] = "latest_snapshot_missing"
        return base, fields
    best_ask, best_bid = _get_best_levels_from_ws(latest)
    latest_price = _safe_int(latest.get("curr"), 0)
    latest_ts = _safe_float(latest.get("last_ws_update_ts"), 0.0)
    now_ts = time.time()
    age_ms = None if latest_ts <= 0 else max(0.0, (now_ts - latest_ts) * 1000.0)
    fields.update(
        {
            "pre_submit_ws_snapshot_refresh_age_ms": None if age_ms is None else round(age_ms, 3),
            "pre_submit_ws_snapshot_refresh_best_bid": best_bid,
            "pre_submit_ws_snapshot_refresh_best_ask": best_ask,
            "pre_submit_ws_snapshot_refresh_latest_price": latest_price,
        }
    )
    if latest_price <= 0:
        fields["pre_submit_ws_snapshot_refresh_reason"] = "latest_price_missing"
        return base, fields
    if best_bid <= 0 or best_ask <= 0 or best_ask <= best_bid:
        fields["pre_submit_ws_snapshot_refresh_reason"] = "latest_best_levels_invalid"
        return base, fields
    if age_ms is None:
        fields["pre_submit_ws_snapshot_refresh_reason"] = "latest_timestamp_missing"
        return base, fields
    if age_ms > max_age_ms:
        fields["pre_submit_ws_snapshot_refresh_reason"] = "latest_snapshot_stale"
        return base, fields
    if base_ts > 0 and latest_ts < base_ts:
        fields["pre_submit_ws_snapshot_refresh_reason"] = "latest_snapshot_older_than_input"
        return base, fields
    refreshed = dict(latest)
    refreshed.update(fields)
    fields["pre_submit_ws_snapshot_refresh_applied"] = True
    fields["pre_submit_ws_snapshot_refresh_reason"] = "latest_ws_snapshot_fresh"
    refreshed.update(fields)
    return refreshed, fields


def _parse_hhmmss_age_ms(hhmmss: str, *, now_ts: float | None = None) -> float | None:
    text = str(hhmmss or "").strip()
    if len(text) < 6 or not text[:6].isdigit():
        return None
    now = datetime.fromtimestamp(float(now_ts or time.time()))
    snapshot_dt = now.replace(
        hour=int(text[:2]),
        minute=int(text[2:4]),
        second=int(text[4:6]),
        microsecond=0,
    )
    age_ms = (now - snapshot_dt).total_seconds() * 1000.0
    if age_ms < -3000:
        return None
    return max(0.0, age_ms)


def _pre_submit_refresh_rest_orderbook_snapshot(
    code: str,
    ws_data: dict | None,
    strategy: str,
) -> tuple[dict, dict]:
    """Refresh real SCALPING pre-submit orderbook from Kiwoom ka10004 REST."""
    base = dict(ws_data or {})
    fields = {
        "pre_submit_rest_orderbook_refresh_enabled": False,
        "pre_submit_rest_orderbook_refresh_applied": False,
        "pre_submit_rest_orderbook_refresh_reason": "not_attempted",
        "pre_submit_rest_orderbook_refresh_source": "ka10004_rest_orderbook",
        "pre_submit_rest_orderbook_refresh_age_ms": None,
        "pre_submit_rest_orderbook_refresh_best_bid": 0,
        "pre_submit_rest_orderbook_refresh_best_ask": 0,
        "pre_submit_rest_orderbook_refresh_latest_price": _safe_int(base.get("curr"), 0),
        "pre_submit_rest_orderbook_refresh_bid_req_base_tm": "",
    }
    if str(strategy or "").upper() not in {"SCALPING", "SCALP", "KOSPI_ML"}:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "non_scalping"
        return base, fields
    enabled_env = os.getenv("KORSTOCKSCAN_SCALP_PRE_SUBMIT_QUOTE_REFRESH_ENABLED")
    if enabled_env is not None and str(enabled_env).strip().lower() not in {"1", "true", "yes", "y", "on"}:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "disabled"
        return base, fields
    rest_enabled_env = os.getenv("KORSTOCKSCAN_SCALP_PRE_SUBMIT_REST_ORDERBOOK_REFRESH_ENABLED")
    if rest_enabled_env is not None and str(rest_enabled_env).strip().lower() not in {"1", "true", "yes", "y", "on"}:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "rest_disabled"
        return base, fields
    fields["pre_submit_rest_orderbook_refresh_enabled"] = True
    if not KIWOOM_TOKEN:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "token_missing"
        return base, fields
    try:
        snapshot = kiwoom_utils.get_stock_orderbook_ka10004(KIWOOM_TOKEN, code) or {}
    except Exception as exc:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "rest_orderbook_error"
        fields["pre_submit_rest_orderbook_refresh_error"] = str(exc)[:120]
        return base, fields
    if not isinstance(snapshot, dict) or not snapshot:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "rest_orderbook_missing"
        return base, fields
    best_ask = _safe_int(snapshot.get("best_ask"), 0)
    best_bid = _safe_int(snapshot.get("best_bid"), 0)
    latest_price = _safe_int(snapshot.get("curr"), 0) or best_ask or best_bid
    bid_req_base_tm = str(snapshot.get("bid_req_base_tm") or "").strip()
    age_ms = _parse_hhmmss_age_ms(bid_req_base_tm)
    fields.update(
        {
            "pre_submit_rest_orderbook_refresh_age_ms": None if age_ms is None else round(age_ms, 3),
            "pre_submit_rest_orderbook_refresh_best_bid": best_bid,
            "pre_submit_rest_orderbook_refresh_best_ask": best_ask,
            "pre_submit_rest_orderbook_refresh_latest_price": latest_price,
            "pre_submit_rest_orderbook_refresh_bid_req_base_tm": bid_req_base_tm,
        }
    )
    max_age_ms = _safe_int(
        os.getenv("KORSTOCKSCAN_SCALP_PRE_SUBMIT_REST_ORDERBOOK_MAX_AGE_MS"),
        _safe_int(os.getenv("KORSTOCKSCAN_SCALP_PRE_SUBMIT_QUOTE_REFRESH_MAX_AGE_MS"), 1500),
    )
    max_spread_ratio = _safe_float(
        os.getenv("KORSTOCKSCAN_SCALP_PRE_SUBMIT_QUOTE_REFRESH_MAX_SPREAD_RATIO"),
        _safe_float(getattr(TRADING_RULES, "SCALP_PRE_SUBMIT_QUOTE_REFRESH_MAX_SPREAD_RATIO", 0.015), 0.015),
    )
    if latest_price <= 0:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "rest_latest_price_missing"
        return base, fields
    if best_bid <= 0 or best_ask <= 0 or best_ask <= best_bid:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "rest_best_levels_invalid"
        return base, fields
    if age_ms is None:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "rest_orderbook_time_missing"
        return base, fields
    if age_ms > max_age_ms:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "rest_orderbook_stale"
        return base, fields
    spread_ratio = (best_ask - best_bid) / max(best_bid, 1)
    if spread_ratio > max_spread_ratio:
        fields["pre_submit_rest_orderbook_refresh_reason"] = "rest_spread_too_wide"
        fields["pre_submit_rest_orderbook_refresh_spread_ratio"] = round(spread_ratio, 6)
        return base, fields

    refreshed = dict(base)
    refreshed.update(
        {
            "curr": latest_price,
            "best_ask": best_ask,
            "best_bid": best_bid,
            "best_ask_qty": _safe_int(snapshot.get("best_ask_qty"), 0),
            "best_bid_qty": _safe_int(snapshot.get("best_bid_qty"), 0),
            "ask_tot": _safe_int(snapshot.get("ask_tot"), 0),
            "bid_tot": _safe_int(snapshot.get("bid_tot"), 0),
            "orderbook": snapshot.get("orderbook") or {},
            "last_ws_update_ts": time.time() - (float(age_ms) / 1000.0),
            "quote_refresh_source": "ka10004_rest_orderbook",
        }
    )
    fields["pre_submit_rest_orderbook_refresh_applied"] = True
    fields["pre_submit_rest_orderbook_refresh_reason"] = "rest_orderbook_fresh"
    refreshed.update(fields)
    return refreshed, fields


def _pre_submit_input_snapshot_has_usable_quote(ws_data: dict | None) -> bool:
    data = dict(ws_data or {})
    if _safe_int(data.get("curr"), 0) <= 0:
        return False
    best_ask, best_bid = _get_best_levels_from_ws(data)
    return best_bid > 0 and best_ask > best_bid


