def _latency_gate_observer_unhealthy(latency_gate: dict | None) -> bool:
    if not isinstance(latency_gate, dict):
        return False
    snapshot = latency_gate.get("orderbook_stability")
    if not isinstance(snapshot, dict):
        return False
    if bool(snapshot.get("observer_healthy", True)):
        return False
    reason = str(snapshot.get("observer_missing_reason") or "").strip().lower()
    return reason not in {"", "ok", "none"}


def _latency_gate_needs_stale_quote_rest_recheck(latency_gate: dict | None) -> bool:
    if not isinstance(latency_gate, dict):
        return False
    if str(latency_gate.get("latency_state") or "").upper() != "DANGER":
        return False
    danger_reasons = str(latency_gate.get("latency_danger_reasons") or "").lower()
    return (
        bool(latency_gate.get("quote_stale"))
        or "quote_stale" in danger_reasons
        or "ws_age_too_high" in danger_reasons
    )


def _compute_price_below_bid_bps(price, best_bid):
    price = _coerce_int_value(price)
    best_bid = _coerce_int_value(best_bid)
    if price <= 0 or best_bid <= 0 or price >= best_bid:
        return 0
    return int(round(((best_bid - price) / best_bid) * 10000))


def _build_entry_price_snapshot_fields(latency_gate, *, request_price, curr_price, best_bid, best_ask):
    submitted_order_price = _coerce_int_value(request_price)
    defensive_order_price = _coerce_int_value(latency_gate.get('latency_guarded_order_price'))
    reference_target_price = _coerce_int_value(latency_gate.get('target_buy_price'))
    price_below_bid_bps = _compute_price_below_bid_bps(submitted_order_price, best_bid)

    resolution_reason = str(
        latency_gate.get('price_resolution_reason')
        or latency_gate.get('entry_price_guard')
        or 'none'
    )
    if reference_target_price > 0 and defensive_order_price > 0:
        if (
            submitted_order_price <= reference_target_price < defensive_order_price
            and not resolution_reason.startswith("ai_tier2_")
        ):
            resolution_reason = 'reference_target_cap'
    if (
        defensive_order_price > 0
        and submitted_order_price == defensive_order_price
        and resolution_reason not in {'scalping_reference_rejected_defensive'}
    ):
        resolution_reason = 'defensive_order_price'

    return {
        'submitted_order_price': submitted_order_price,
        'mark_price_at_submit': _coerce_int_value(curr_price),
        'best_bid_at_submit': _coerce_int_value(best_bid),
        'best_ask_at_submit': _coerce_int_value(best_ask),
        'defensive_order_price': defensive_order_price,
        'reference_target_price': reference_target_price,
        'resolved_order_price': submitted_order_price,
        'resolution_reason': resolution_reason,
        'price_below_bid_bps': price_below_bid_bps,
        'entry_price_gap_profile': str(latency_gate.get('entry_price_gap_profile') or ''),
        'entry_price_gap_profile_bps': _coerce_int_value(latency_gate.get('entry_price_gap_profile_bps')),
        'entry_price_gap_profile_reason': str(latency_gate.get('entry_price_gap_profile_reason') or ''),
        'entry_price_gap_profile_context': latency_gate.get('entry_price_gap_profile_context') or {},
        'aggressive_entry_price_override_applied': bool(latency_gate.get('aggressive_entry_price_override_applied')),
        'aggressive_entry_price_override_type': str(latency_gate.get('aggressive_entry_price_override_type') or ''),
        'aggressive_entry_price_override_reason': str(latency_gate.get('aggressive_entry_price_override_reason') or ''),
        'aggressive_entry_price_override_skip_reason': str(
            latency_gate.get('aggressive_entry_price_override_skip_reason') or ''
        ),
        'aggressive_entry_price_original_profile': str(latency_gate.get('aggressive_entry_price_original_profile') or ''),
        'aggressive_entry_price_original_bps': _coerce_int_value(latency_gate.get('aggressive_entry_price_original_bps')),
        'aggressive_entry_price_target_mode': str(latency_gate.get('aggressive_entry_price_target_mode') or ''),
        'aggressive_entry_price_order_price': _coerce_int_value(latency_gate.get('aggressive_entry_price_order_price')),
        'reference_target_applied': bool(latency_gate.get('reference_target_applied')),
        'reference_target_rejected_reason': str(latency_gate.get('reference_target_rejected_reason') or ''),
        'reference_target_below_bid_bps': _coerce_int_value(latency_gate.get('reference_target_below_bid_bps')),
        'reference_target_max_below_bid_bps': _coerce_int_value(
            latency_gate.get('reference_target_max_below_bid_bps')
        ),
        'entry_price_resolver_enabled': bool(latency_gate.get('entry_price_resolver_enabled')),
        'ai_entry_price_canary_applied': bool(latency_gate.get('ai_entry_price_canary_applied')),
        'ai_entry_price_canary_action': str(latency_gate.get('ai_entry_price_canary_action') or ''),
        'ai_entry_price_canary_confidence': _coerce_int_value(
            latency_gate.get('ai_entry_price_canary_confidence')
        ),
        'ai_entry_price_canary_reason': str(latency_gate.get('ai_entry_price_canary_reason') or ''),
        'ai_entry_price_canary_max_wait_sec': _coerce_int_value(
            latency_gate.get('ai_entry_price_canary_max_wait_sec')
        ),
    }


REAL_ENTRY_PANIC_GAP_WEIGHT_FAMILY = "real_entry_panic_gap_weight"


def _base_panic_gap_weight_fields(reason: str = "not_evaluated") -> dict:
    return {
        "panic_gap_weight_runtime_family": REAL_ENTRY_PANIC_GAP_WEIGHT_FAMILY,
        "panic_gap_weight_applied": False,
        "panic_gap_weight_bps": 0,
        "panic_gap_weight_reason": reason,
        "panic_regime_mode": "NORMAL",
        "panic_buy_regime_mode": "NORMAL",
        "original_order_price": 0,
        "panic_adjusted_order_price": 0,
        "panic_gap_weight_runtime_effect": False,
        "forbidden_uses": "sim_probe|adm_ldm_input|threshold_cycle_ev_input|tuning_input",
    }


def _panic_gap_weight_log_fields(latency_gate: dict | None) -> dict:
    gate = latency_gate if isinstance(latency_gate, dict) else {}
    fields = _base_panic_gap_weight_fields(str(gate.get("panic_gap_weight_reason") or "not_evaluated"))
    for key in fields:
        if key in gate:
            fields[key] = gate.get(key)
    return fields


def _resolve_real_entry_panic_gap_weight_delta(panic_context: dict | None, euphoria_context: dict | None) -> dict:
    fields = _base_panic_gap_weight_fields("normal_market")
    panic = panic_context if isinstance(panic_context, dict) else {}
    euphoria = euphoria_context if isinstance(euphoria_context, dict) else {}
    panic_status = str(panic.get("panic_context_status") or "MISSING").upper()
    euphoria_status = str(euphoria.get("euphoria_context_status") or "MISSING").upper()
    panic_regime = str(panic.get("panic_regime_mode") or "NORMAL").upper()
    panic_state = str(panic.get("panic_state") or "NORMAL").upper()
    panic_buy_mode = str(euphoria.get("panic_buy_regime_mode") or "NORMAL").upper()
    panic_buy_state = str(euphoria.get("panic_buy_state") or "NORMAL").upper()
    fields["panic_regime_mode"] = panic_regime
    fields["panic_buy_regime_mode"] = panic_buy_mode

    if panic_status == "OK":
        panic_level = _safe_int(panic.get("panic_level"), 0)
        liquidity_state = str(panic.get("liquidity_state") or "NORMAL").upper()
        if liquidity_state in {"BROKEN", "LIQUIDITY_BROKEN", "THIN_BROKEN"} or panic_level >= 2:
            fields.update({
                "panic_gap_weight_bps": _rule_int("REAL_ENTRY_PANIC_SELL_BROKEN_EXTRA_BPS", 50),
                "panic_gap_weight_reason": "panic_sell_liquidity_broken_or_level2",
            })
            return fields
        if panic_regime == "PANIC_DETECTED" or panic_state == "PANIC_SELL":
            fields.update({
                "panic_gap_weight_bps": _rule_int("REAL_ENTRY_PANIC_SELL_EXTRA_BPS", 30),
                "panic_gap_weight_reason": "panic_sell_detected",
            })
            return fields
    elif panic_status not in {"", "MISSING", "DISABLED"}:
        fields["panic_gap_weight_reason"] = f"panic_context_not_ok:{panic_status.lower()}"

    if euphoria_status == "OK":
        level = _safe_int(euphoria.get("euphoria_risk_level"), 0)
        if panic_buy_mode in {"PANIC_BUY_EXHAUSTION", "COOLDOWN"} or panic_buy_state in {
            "BUYING_EXHAUSTED",
            "EXHAUSTION_WATCH",
        } or level >= 3:
            fields.update({
                "panic_gap_weight_bps": _rule_int("REAL_ENTRY_PANIC_BUY_EXHAUSTION_EXTRA_BPS", 30),
                "panic_gap_weight_reason": "panic_buy_exhaustion",
            })
            return fields
        if panic_buy_mode == "PANIC_BUY_CONTINUATION" or panic_buy_state == "PANIC_BUY" or level == 2:
            fields.update({
                "panic_gap_weight_bps": -_rule_int("REAL_ENTRY_PANIC_BUY_ACTIVE_REDUCE_BPS", 20),
                "panic_gap_weight_reason": "panic_buy_active",
            })
            return fields
        if panic_buy_mode == "PANIC_BUY_DETECTED" or panic_buy_state == "PANIC_BUY_WATCH" or level == 1:
            fields.update({
                "panic_gap_weight_bps": -_rule_int("REAL_ENTRY_PANIC_BUY_WATCH_REDUCE_BPS", 10),
                "panic_gap_weight_reason": "panic_buy_watch",
            })
            return fields
    elif euphoria_status not in {"", "MISSING", "DISABLED"}:
        if fields.get("panic_gap_weight_reason") == "normal_market":
            fields["panic_gap_weight_reason"] = f"panic_buy_context_not_ok:{euphoria_status.lower()}"
        return fields

    return fields


def _apply_real_entry_panic_gap_weight(
    *,
    stock: dict,
    strategy: str,
    latency_gate: dict,
    planned_orders: list,
    curr_price: int,
    best_bid: int,
    best_ask: int,
    panic_context: dict | None,
    euphoria_context: dict | None,
    real_order_subject: bool,
) -> tuple[list, dict]:
    fields = _base_panic_gap_weight_fields("disabled")
    current_price = _coerce_int_value(curr_price)
    original_price = _coerce_int_value((latency_gate or {}).get("order_price"))
    fields["original_order_price"] = original_price
    fields["panic_adjusted_order_price"] = original_price
    if not _rule_bool("REAL_ENTRY_PANIC_GAP_WEIGHT_ENABLED", True):
        fields["panic_gap_weight_reason"] = "disabled"
        latency_gate.update(fields)
        return planned_orders, fields
    if str(strategy or "").upper() not in {"SCALPING", "SCALP"}:
        fields["panic_gap_weight_reason"] = "non_scalping_noop"
        latency_gate.update(fields)
        return planned_orders, fields
    if not real_order_subject:
        fields["panic_gap_weight_reason"] = "non_real_order_subject_noop"
        latency_gate.update(fields)
        return planned_orders, fields
    if current_price <= 0 or original_price <= 0:
        fields["panic_gap_weight_reason"] = "invalid_price_noop"
        latency_gate.update(fields)
        return planned_orders, fields

    decision = _resolve_real_entry_panic_gap_weight_delta(panic_context, euphoria_context)
    fields.update(decision)
    delta_bps = _safe_int(fields.get("panic_gap_weight_bps"), 0)
    if delta_bps == 0:
        latency_gate.update(fields)
        return planned_orders, fields

    current_gap_bps = max(0, int(round(((current_price - original_price) / current_price) * 10000.0)))
    adjusted_gap_bps = max(0, current_gap_bps + delta_bps)
    if delta_bps < 0 and best_ask <= 0:
        fields["panic_gap_weight_reason"] = f"{fields.get('panic_gap_weight_reason')}:best_ask_missing_noop"
        latency_gate.update(fields)
        return planned_orders, fields
    adjusted_price = move_price_down_by_bps(current_price, adjusted_gap_bps, floor_ticks=0)
    if best_ask > 0 and adjusted_price > best_ask:
        adjusted_price = clamp_price_to_tick(best_ask)
    adjusted_price = clamp_price_to_tick(adjusted_price)
    if adjusted_price <= 0:
        fields["panic_gap_weight_reason"] = "adjusted_price_invalid_noop"
        latency_gate.update(fields)
        return planned_orders, fields
    if adjusted_price == original_price:
        fields["panic_gap_weight_reason"] = f"{fields.get('panic_gap_weight_reason')}:rounded_no_change"
        latency_gate.update(fields)
        return planned_orders, fields

    adjusted_orders = []
    for order in planned_orders or []:
        next_order = dict(order)
        if str(next_order.get("tif", "DAY") or "DAY").upper() != "IOC":
            next_order["price"] = adjusted_price
        adjusted_orders.append(next_order)

    latency_gate["orders"] = adjusted_orders
    latency_gate["order_price"] = adjusted_price
    latency_gate["price_resolution_reason"] = f"{latency_gate.get('price_resolution_reason') or 'defensive_order_price'}|panic_gap_weight"
    latency_gate["price_below_bid_bps"] = _compute_price_below_bid_bps(adjusted_price, best_bid)
    fields.update({
        "panic_gap_weight_applied": True,
        "panic_adjusted_order_price": adjusted_price,
        "panic_gap_weight_runtime_effect": True,
    })
    latency_gate.update(fields)
    _mutate_stock_state(
        stock,
        set_fields={
            "real_entry_panic_gap_weight_applied": True,
            "real_entry_panic_gap_weight_bps": delta_bps,
            "real_entry_panic_adjusted_order_price": adjusted_price,
        },
    )
    return adjusted_orders, fields


def _build_orderbook_micro_context(
    latency_gate,
    *,
    curr_price,
    best_bid,
    best_ask,
    respect_scalping_flag: bool = True,
):
    if respect_scalping_flag and not bool(_rule("SCALPING_ENTRY_PRICE_ORDERBOOK_MICRO_ENABLED", True)):
        return None
    stability = (latency_gate or {}).get("orderbook_stability") or {}
    micro = stability.get("orderbook_micro") if isinstance(stability, dict) else None
    if not isinstance(micro, dict):
        return {
            "ready": False,
            "reason": "missing_snapshot",
            "micro_state": "insufficient",
            "sample_quote_count": 0,
            "observer_healthy": False,
            "observer_missing_reason": "missing_snapshot",
            "ofi_threshold_source": "fallback",
            "ofi_threshold_fallback_reason": "missing_snapshot",
            "ofi_bucket_key": (
                "spread=not_available_no_bid_ask|price=not_available_no_price|"
                "depth=not_available_no_depth|sample=insufficient"
            ),
            "ofi_calibration_bucket": (
                "spread=not_available_no_bid_ask|price=not_available_no_price|"
                "depth=not_available_no_depth|sample=insufficient"
            ),
            "ofi_calibration_warning": "missing_snapshot",
        }

    tick_size = 1
    try:
        tick_size = int(kiwoom_utils.get_tick_size(_coerce_int_value(curr_price) or _coerce_int_value(best_bid)) or 1)
    except Exception:
        tick_size = 1
    spread_ticks = 0
    if _coerce_int_value(best_ask) > 0 and _coerce_int_value(best_bid) > 0 and tick_size > 0:
        spread_ticks = max(0, int(round((_coerce_int_value(best_ask) - _coerce_int_value(best_bid)) / tick_size)))

    context = {
        "ready": bool(micro.get("ready")),
        "reason": str(micro.get("reason") or ""),
        "qi": micro.get("qi"),
        "qi_ewma": micro.get("qi_ewma"),
        "ofi_norm": micro.get("ofi_norm"),
        "ofi_z": micro.get("ofi_z"),
        "depth_ewma": micro.get("depth_ewma"),
        "micro_state": str(micro.get("micro_state") or "insufficient"),
        "sample_quote_count": _coerce_int_value(micro.get("sample_quote_count")),
        "spread_ticks": spread_ticks,
    }
    for key in (
        "captured_at_ms",
        "snapshot_age_ms",
        "observer_healthy",
        "observer_missing_reason",
        "observer_last_quote_age_ms",
        "observer_last_trade_age_ms",
        "micro_window_sec",
        "micro_z_min_samples",
        "micro_lambda",
        "ofi_bull_threshold",
        "ofi_bear_threshold",
        "qi_bull_threshold",
        "qi_bear_threshold",
        "ofi_threshold_source",
        "ofi_threshold_bucket_key",
        "ofi_threshold_manifest_id",
        "ofi_threshold_manifest_version",
        "ofi_threshold_fallback_reason",
        "ofi_calibration_bucket",
        "ofi_bucket_key",
        "ofi_symbol_sample_count",
        "ofi_bucket_sample_count",
        "ofi_symbol_bearish_rate",
        "ofi_bucket_bearish_rate",
        "ofi_symbol_bullish_rate",
        "ofi_bucket_bullish_rate",
        "ofi_symbol_bucket_deviation",
        "ofi_calibration_warning",
    ):
        if key in micro:
            context[key] = micro.get(key)
    return context


def _build_orderbook_micro_log_fields(micro):
    if not isinstance(micro, dict):
        return {
            "orderbook_micro_ready": False,
            "orderbook_micro_state": "missing",
            "orderbook_micro_reason": "micro_context_missing",
            "orderbook_micro_snapshot_age_ms": "not_evaluated",
            "orderbook_micro_observer_healthy": False,
        }
    fields = {
        "orderbook_micro_ready": bool(micro.get("ready")),
        "orderbook_micro_reason": str(micro.get("reason") or ""),
        "orderbook_micro_state": str(micro.get("micro_state") or "insufficient"),
        "orderbook_micro_sample_quote_count": _coerce_int_value(micro.get("sample_quote_count")),
    }
    for key in (
        "qi",
        "qi_ewma",
        "ofi_norm",
        "ofi_z",
        "depth_ewma",
        "spread_ticks",
        "captured_at_ms",
        "snapshot_age_ms",
        "observer_healthy",
        "observer_missing_reason",
        "observer_last_quote_age_ms",
        "observer_last_trade_age_ms",
        "micro_window_sec",
        "micro_z_min_samples",
        "micro_lambda",
        "ofi_bull_threshold",
        "ofi_bear_threshold",
        "qi_bull_threshold",
        "qi_bear_threshold",
        "ofi_threshold_source",
        "ofi_threshold_bucket_key",
        "ofi_threshold_manifest_id",
        "ofi_threshold_manifest_version",
        "ofi_threshold_fallback_reason",
        "ofi_calibration_bucket",
        "ofi_bucket_key",
        "ofi_symbol_sample_count",
        "ofi_bucket_sample_count",
        "ofi_symbol_bearish_rate",
        "ofi_bucket_bearish_rate",
        "ofi_symbol_bullish_rate",
        "ofi_bucket_bullish_rate",
        "ofi_symbol_bucket_deviation",
        "ofi_calibration_warning",
    ):
        value = micro.get(key)
        fields[f"orderbook_micro_{key}"] = "not_evaluated" if value is None else value
    for key, value in micro.items():
        if not str(key).startswith("wide_") or key == "wide_windows":
            continue
        fields[f"orderbook_micro_{key}"] = "-" if value is None else value
    return fields


def _apply_quote_fresh_composite_orderbook_micro_block(latency_gate, orderbook_micro_fields, strategy):
    if not isinstance(latency_gate, dict) or not latency_gate.get("allowed"):
        return latency_gate
    if normalize_strategy(strategy) != "SCALPING":
        return latency_gate
    if not _rule_bool("SCALPING_ENTRY_QUOTE_FRESH_COMPOSITE_ORDERBOOK_MICRO_BLOCK_ENABLED", True):
        return latency_gate

    effective_reason = str(latency_gate.get("effective_reason") or latency_gate.get("reason") or "")
    if effective_reason != "latency_quote_fresh_composite_normal_override":
        return latency_gate
    if str(latency_gate.get("latency_state") or "").upper() != "DANGER":
        return latency_gate
    if not _boolish_true(latency_gate.get("latency_canary_applied")):
        return latency_gate
    if not isinstance(orderbook_micro_fields, dict) or not _boolish_true(
        orderbook_micro_fields.get("orderbook_micro_ready")
    ):
        return latency_gate

    micro_state = str(orderbook_micro_fields.get("orderbook_micro_state") or "").strip().lower()
    ofi_norm = _safe_float(orderbook_micro_fields.get("orderbook_micro_ofi_norm"), None)
    min_ofi_norm = _rule_float("SCALPING_ENTRY_QUOTE_FRESH_COMPOSITE_MIN_OFI_NORM", 0.0)
    blocked_by_ofi = ofi_norm is not None and ofi_norm < min_ofi_norm
    blocked_by_state = micro_state == "bearish"
    if not blocked_by_ofi and not blocked_by_state:
        return latency_gate

    previous_decision = latency_gate.get("effective_decision", latency_gate.get("decision"))
    previous_reason = latency_gate.get("effective_reason", latency_gate.get("reason"))
    latency_gate.update(
        {
            "allowed": False,
            "mode": "reject",
            "decision": "REJECT_DANGER",
            "reason": "quote_fresh_composite_orderbook_micro_block",
            "effective_decision": "REJECT_DANGER",
            "effective_reason": "quote_fresh_composite_orderbook_micro_block",
            "quote_fresh_composite_micro_blocked": True,
            "quote_fresh_composite_micro_block_reason": (
                "negative_ofi" if blocked_by_ofi else "bearish_micro_state"
            ),
            "quote_fresh_composite_previous_decision": previous_decision,
            "quote_fresh_composite_previous_reason": previous_reason,
            "quote_fresh_composite_min_ofi_norm": min_ofi_norm,
            "quote_fresh_composite_ofi_norm": ofi_norm,
            "quote_fresh_composite_micro_state": micro_state,
        }
    )
    return latency_gate


def _build_swing_orderbook_micro_context(
    code: str,
    *,
    curr_price: int,
    latency_gate: dict | None = None,
    best_bid: int = 0,
    best_ask: int = 0,
) -> dict | None:
    if isinstance(latency_gate, dict):
        micro = _build_orderbook_micro_context(
            latency_gate,
            curr_price=curr_price,
            best_bid=best_bid,
            best_ask=best_ask,
            respect_scalping_flag=False,
        )
        if isinstance(micro, dict):
            return micro
    return _build_live_orderbook_micro_context(code, curr_price=curr_price)


def _build_swing_ws_quote_quality_fields(ws_data: dict | None) -> dict:
    best_ask, best_bid = _get_best_levels_from_ws(ws_data or {})
    quote_age_sec = _get_ws_snapshot_age_sec(ws_data or {})
    quote_age_ms = "-" if quote_age_sec is None else int(round(quote_age_sec * 1000.0))
    quote_present = bool(best_ask > 0 or best_bid > 0 or _safe_int((ws_data or {}).get("curr"), 0) > 0)
    quote_stale = quote_age_ms != "-" and int(quote_age_ms) > max(1, _rule_int("OFI_AI_SMOOTHING_STALE_THRESHOLD_MS", 700))
    if quote_age_sec is not None:
        source = "last_ws_update_ts"
    elif quote_present:
        source = "ws_quote_without_timestamp"
    else:
        source = "missing"
    return {
        "swing_micro_ws_quote_present": bool(quote_present),
        "swing_micro_ws_quote_source": source,
        "swing_micro_ws_quote_age_ms": quote_age_ms,
        "swing_micro_ws_quote_stale": bool(quote_stale) if quote_age_ms != "-" else "not_available_no_quote_age",
        "swing_micro_ws_best_bid": best_bid or "-",
        "swing_micro_ws_best_ask": best_ask or "-",
    }


def _build_swing_micro_log_fields(
    micro: dict | None,
    *,
    phase: str,
    add_type: str | None = None,
    ws_data: dict | None = None,
) -> dict:
    fields = _build_orderbook_micro_log_fields(micro)
    ws_quote_fields = _build_swing_ws_quote_quality_fields(ws_data)
    state = str(fields.get("orderbook_micro_state") or "missing").strip().lower()
    ready = bool(fields.get("orderbook_micro_ready"))
    observer_healthy = fields.get("orderbook_micro_observer_healthy")
    if observer_healthy == "-":
        observer_healthy = False
    observer_unhealthy = observer_healthy is not True
    snapshot_age_ms = _safe_float(fields.get("orderbook_micro_snapshot_age_ms"), None)
    stale_threshold_ms = max(1, _rule_int("OFI_AI_SMOOTHING_STALE_THRESHOLD_MS", 700))
    is_stale = snapshot_age_ms is not None and snapshot_age_ms > stale_threshold_ms
    missing = (
        not isinstance(micro, dict)
        or not ready
        or state in {"", "missing", "insufficient"}
        or observer_unhealthy
        or is_stale
    )
    if missing:
        advice = "MISSING"
        price_action = "NO_CHANGE"
        timeout_sec = 0
        reason = "missing_stale_or_insufficient_orderbook_micro"
        source_quality_status = "source_quality_blocker"
        if (
            observer_unhealthy
            and ws_quote_fields["swing_micro_ws_quote_present"] is True
            and ws_quote_fields["swing_micro_ws_quote_stale"] is False
        ):
            source_quality_status = "observer_gap_with_fresh_ws_quote"
    elif state == "bullish":
        advice = "SUPPORT_ENTRY"
        price_action = "ALLOW_EXISTING_PRICE"
        timeout_sec = 0
        reason = "ofi_qi_bullish_support_observed"
        source_quality_status = "ok"
    elif state == "bearish":
        advice = "RISK_BEARISH"
        price_action = "WAIT_FOR_PULLBACK"
        timeout_sec = 30
        reason = "ofi_qi_bearish_risk_observed"
        source_quality_status = "ok"
    else:
        advice = "WAIT_FOR_PULLBACK"
        price_action = "KEEP_EXISTING_PRICE"
        timeout_sec = 0
        reason = "ofi_qi_neutral_or_mixed_observed"
        source_quality_status = "ok"

    add_label = str(add_type or "").upper()
    micro_support = add_label == "PYRAMID" and advice in {"SUPPORT_ENTRY", "WAIT_FOR_PULLBACK"}
    micro_risk = add_label == "PYRAMID" and state == "bearish" and advice != "MISSING"
    recovery_support_observed = add_label == "AVG_DOWN" and advice == "SUPPORT_ENTRY"
    fields.update(
        {
            "swing_micro_phase": phase,
            "swing_micro_advice": advice,
            "swing_micro_counterfactual_price_action": price_action,
            "swing_micro_counterfactual_timeout_sec": timeout_sec,
            "swing_micro_counterfactual_reason": reason,
            "swing_micro_runtime_effect": False,
            "swing_micro_observe_only": True,
            "swing_micro_source_quality_status": source_quality_status,
            "swing_micro_state": state,
            "swing_micro_stale": bool(is_stale),
            "swing_micro_micro_support": bool(micro_support),
            "swing_micro_micro_risk": bool(micro_risk),
            "swing_micro_support": bool(micro_support),
            "swing_micro_risk": bool(micro_risk),
            "swing_micro_recovery_support_observed": bool(recovery_support_observed),
            "recovery_support_observed": bool(recovery_support_observed),
            **ws_quote_fields,
        }
    )
    return fields


def _ofi_ai_smoothing_config() -> OfiSmoothingConfig:
    return OfiSmoothingConfig(
        raw_weight=_rule_float("OFI_AI_SMOOTHING_RAW_WEIGHT", 0.30),
        bullish_threshold=_rule_float("OFI_AI_SMOOTHING_BULLISH_THRESHOLD", 0.45),
        bearish_threshold=_rule_float("OFI_AI_SMOOTHING_BEARISH_THRESHOLD", -0.45),
        release_threshold=_rule_float("OFI_AI_SMOOTHING_RELEASE_THRESHOLD", 0.15),
        persistence_required=max(1, _rule_int("OFI_AI_SMOOTHING_PERSISTENCE_REQUIRED", 2)),
        stale_threshold_ms=max(1, _rule_int("OFI_AI_SMOOTHING_STALE_THRESHOLD_MS", 700)),
    )


def _load_holding_flow_ofi_state(stock: dict) -> OfiSmoothingState:
    return OfiSmoothingState(
        micro_score_raw=_safe_float(stock.get("holding_flow_ofi_micro_score_raw"), None),
        micro_score_smooth=_safe_float(stock.get("holding_flow_ofi_micro_score_smooth"), 0.0),
        regime=str(stock.get("holding_flow_ofi_regime") or OFI_NEUTRAL),
        bullish_count=_safe_int(stock.get("holding_flow_ofi_bullish_count"), 0),
        bearish_count=_safe_int(stock.get("holding_flow_ofi_bearish_count"), 0),
        snapshot_age_ms=_safe_float(stock.get("holding_flow_ofi_snapshot_age_ms"), None),
        reason=str(stock.get("holding_flow_ofi_reason") or "ready"),
    )


def _store_holding_flow_ofi_state(stock: dict, state: OfiSmoothingState) -> None:
    _mutate_stock_state(
        stock,
        set_fields={
            "holding_flow_ofi_micro_score_raw": state.micro_score_raw,
            "holding_flow_ofi_micro_score_smooth": state.micro_score_smooth,
            "holding_flow_ofi_regime": state.regime,
            "holding_flow_ofi_bullish_count": state.bullish_count,
            "holding_flow_ofi_bearish_count": state.bearish_count,
            "holding_flow_ofi_snapshot_age_ms": state.snapshot_age_ms,
            "holding_flow_ofi_reason": state.reason,
        },
    )


def _evaluate_entry_skip_ofi_smoothing(orderbook_micro: dict | None) -> OfiSmoothingState:
    return evaluate_ofi_smoothing(orderbook_micro, config=_ofi_ai_smoothing_config())


def _should_demote_entry_ai_price_skip(confidence: int, orderbook_micro: dict | None) -> tuple[bool, OfiSmoothingState]:
    state = _evaluate_entry_skip_ofi_smoothing(orderbook_micro)
    if not _rule_bool("SCALPING_ENTRY_AI_PRICE_OFI_SKIP_DEMOTION_ENABLED", True):
        return False, state
    max_confidence = _rule_int("SCALPING_ENTRY_AI_PRICE_OFI_SKIP_DEMOTION_MAX_CONFIDENCE", 90)
    if int(confidence or 0) >= max_confidence:
        return False, state
    return entry_skip_demotion_allowed(orderbook_micro, state), state


def _build_live_orderbook_micro_context(code: str, *, curr_price: int) -> dict | None:
    try:
        snapshot = ORDERBOOK_STABILITY_OBSERVER.snapshot(code)
    except Exception:
        return None
    if not isinstance(snapshot, dict):
        return None
    micro = snapshot.get("orderbook_micro")
    if not isinstance(micro, dict):
        return None
    context = dict(micro)
    best_bid = _coerce_int_value(snapshot.get("best_bid"))
    best_ask = _coerce_int_value(snapshot.get("best_ask"))
    tick_size = 1
    try:
        tick_size = int(kiwoom_utils.get_tick_size(_coerce_int_value(curr_price) or best_bid) or 1)
    except Exception:
        tick_size = 1
    if best_ask > 0 and best_bid > 0 and tick_size > 0:
        context["spread_ticks"] = max(0, int(round((best_ask - best_bid) / tick_size)))
    else:
        context.setdefault("spread_ticks", 0)
    context.setdefault("captured_at_ms", snapshot.get("captured_at_ms"))
    context.setdefault("snapshot_age_ms", snapshot.get("snapshot_age_ms"))
    context.setdefault("observer_healthy", snapshot.get("observer_healthy"))
    context.setdefault("observer_missing_reason", snapshot.get("observer_missing_reason"))
    context.setdefault("observer_last_quote_age_ms", snapshot.get("observer_last_quote_age_ms"))
    context.setdefault("observer_last_trade_age_ms", snapshot.get("observer_last_trade_age_ms"))
    return context


def _evaluate_holding_flow_ofi_state(stock: dict, code: str, *, curr_price: int) -> tuple[dict | None, OfiSmoothingState]:
    micro = _build_live_orderbook_micro_context(code, curr_price=curr_price)
    state = evaluate_ofi_smoothing(
        micro,
        previous=_load_holding_flow_ofi_state(stock),
        config=_ofi_ai_smoothing_config(),
    )
    _store_holding_flow_ofi_state(stock, state)
    return micro, state


def _build_entry_ai_price_skip_policy_fields(orderbook_micro):
    micro = orderbook_micro if isinstance(orderbook_micro, dict) else {}
    state = str(micro.get("micro_state") or "missing").strip().lower()
    ready = bool(micro.get("ready"))
    if ready and state == "bearish":
        return {
            "entry_ai_price_skip_policy_warning": "",
            "entry_ai_price_skip_policy_basis": "ofi_bearish_supported",
        }
    if not ready:
        return {
            "entry_ai_price_skip_policy_warning": "ofi_not_ready",
            "entry_ai_price_skip_policy_basis": state or "missing",
        }
    if state in {"neutral", "insufficient", "missing", ""}:
        return {
            "entry_ai_price_skip_policy_warning": "skip_without_bearish_ofi",
            "entry_ai_price_skip_policy_basis": state or "missing",
        }
    return {
        "entry_ai_price_skip_policy_warning": "skip_without_bearish_ofi",
        "entry_ai_price_skip_policy_basis": state,
    }


def _is_pre_submit_price_guard_block(strategy, price, best_bid):
    if strategy not in ('SCALPING', 'SCALP'):
        return False
    if not bool(_rule("SCALPING_PRE_SUBMIT_PRICE_GUARD_ENABLED", True)):
        return False
    threshold_bps = int(_rule("SCALPING_PRE_SUBMIT_MAX_BELOW_BID_BPS", 80) or 80)
    if threshold_bps < 0:
        return False
    return _compute_price_below_bid_bps(price, best_bid) > threshold_bps


def _compute_price_above_reference_bps(price, reference_price) -> float:
    price = _safe_float(price, 0.0)
    reference_price = _safe_float(reference_price, 0.0)
    if price <= 0 or reference_price <= 0 or price <= reference_price:
        return 0.0
    return ((price - reference_price) / reference_price) * 10000.0


def _first_float_field(*sources, key: str, aliases=(), default=0.0) -> float:
    for source in sources:
        if not isinstance(source, dict):
            continue
        for candidate_key in (key, *aliases):
            value = source.get(candidate_key)
            if value in (None, ""):
                continue
            return _safe_float(value, default)
    return _safe_float(default, 0.0)


def _latency_price_drift_guard_relevant(latency_gate: dict | None) -> bool:
    fields = latency_gate if isinstance(latency_gate, dict) else {}
    state = str(fields.get("latency_state") or "").strip().upper()
    if state in {"DANGER", "CAUTION"}:
        return True
    danger_reasons = str(
        fields.get("latency_danger_reasons")
        or fields.get("danger_reasons")
        or fields.get("reason")
        or ""
    ).strip()
    if danger_reasons and danger_reasons not in {"-", "ok", "normal"}:
        return True
    return bool(fields.get("latency_canary_applied"))


def _evaluate_late_entry_price_drift_guard(
    *,
    strategy,
    stock,
    price,
    latency_gate,
    price_snapshot=None,
    pre_submit_fields=None,
    microstructure_fields=None,
    orderbook_fields=None,
) -> dict:
    if str(strategy or "").upper() not in {"SCALPING", "SCALP"}:
        return {"blocked": False, "reason": "non_scalping"}
    if not _rule_bool("SCALP_LATE_ENTRY_PRICE_DRIFT_GUARD_ENABLED", False):
        return {"blocked": False, "reason": "disabled"}
    if _is_any_simulated_position(stock, strategy) or _is_swing_live_order_dry_run(strategy):
        return {"blocked": False, "reason": "sim_or_dry_run"}

    latency_fields = latency_gate if isinstance(latency_gate, dict) else {}
    reference_price = _coerce_int_value(
        latency_fields.get("target_buy_price")
        or latency_fields.get("reference_target_price")
        or (stock or {}).get("target_buy_price")
    )
    submitted_price = _coerce_int_value(price)
    drift_bps = _compute_price_above_reference_bps(submitted_price, reference_price)
    hard_bps = _rule_float("SCALP_LATE_ENTRY_PRICE_DRIFT_HARD_BPS", 50.0)
    soft_bps = _rule_float("SCALP_LATE_ENTRY_PRICE_DRIFT_SOFT_BPS", 35.0)
    min_tick = _rule_float("SCALP_LATE_ENTRY_PRICE_DRIFT_MIN_TICK_ACCEL", 1.10)
    min_buy_pressure = _rule_float("SCALP_LATE_ENTRY_PRICE_DRIFT_MIN_BUY_PRESSURE", 0.0)
    min_micro_vwap = _rule_float("SCALP_LATE_ENTRY_PRICE_DRIFT_MIN_MICRO_VWAP_BP", 0.0)

    buy_pressure = _first_float_field(
        latency_fields,
        pre_submit_fields,
        microstructure_fields,
        orderbook_fields,
        stock or {},
        key="buy_pressure_10t",
        aliases=("buy_pressure", "buy_pressure_ratio"),
        default=0.0,
    )
    tick_accel = _first_float_field(
        latency_fields,
        pre_submit_fields,
        microstructure_fields,
        orderbook_fields,
        stock or {},
        key="tick_acceleration_ratio",
        aliases=("tick_accel", "tick_acceleration"),
        default=0.0,
    )
    micro_vwap_bp = _first_float_field(
        latency_fields,
        pre_submit_fields,
        microstructure_fields,
        orderbook_fields,
        stock or {},
        key="curr_vs_micro_vwap_bp",
        aliases=("micro_vwap_bp",),
        default=0.0,
    )
    positive_count = int(buy_pressure >= min_buy_pressure) + int(tick_accel >= min_tick) + int(
        micro_vwap_bp >= min_micro_vwap
    )
    micro_reconfirmed = positive_count >= 2
    latency_relevant = _latency_price_drift_guard_relevant(latency_fields)

    fields = {
        "late_entry_price_drift_guard_enabled": True,
        "late_entry_price_drift_guard_blocked": False,
        "late_entry_price_drift_guard_reason": "pass",
        "late_entry_price_drift_bps": round(drift_bps, 3),
        "late_entry_price_drift_hard_bps": hard_bps,
        "late_entry_price_drift_soft_bps": soft_bps,
        "late_entry_reference_target_price": reference_price,
        "late_entry_submitted_order_price": submitted_price,
        "late_entry_latency_relevant": latency_relevant,
        "late_entry_micro_reconfirmed": micro_reconfirmed,
        "late_entry_micro_positive_count": positive_count,
        "late_entry_min_tick_accel": min_tick,
        "late_entry_min_buy_pressure": min_buy_pressure,
        "late_entry_min_micro_vwap_bp": min_micro_vwap,
        "late_entry_fresh_buy_pressure_10t": buy_pressure,
        "late_entry_fresh_tick_acceleration_ratio": tick_accel,
        "late_entry_fresh_micro_vwap_bp": micro_vwap_bp,
        "latency_state": str(latency_fields.get("latency_state") or ""),
        "latency_danger_reasons": str(
            latency_fields.get("latency_danger_reasons")
            or latency_fields.get("danger_reasons")
            or ""
        ),
    }
    if price_snapshot:
        fields["late_entry_best_bid_at_submit"] = price_snapshot.get("best_bid_at_submit")
        fields["late_entry_best_ask_at_submit"] = price_snapshot.get("best_ask_at_submit")

    if reference_price <= 0 or submitted_price <= 0:
        fields["late_entry_price_drift_guard_reason"] = "missing_reference_or_price"
        return {"blocked": False, "reason": fields["late_entry_price_drift_guard_reason"], "fields": fields}
    if drift_bps < soft_bps:
        fields["late_entry_price_drift_guard_reason"] = "below_soft_drift"
        return {"blocked": False, "reason": fields["late_entry_price_drift_guard_reason"], "fields": fields}
    if not latency_relevant:
        fields["late_entry_price_drift_guard_reason"] = "no_latency_drift_context"
        return {"blocked": False, "reason": fields["late_entry_price_drift_guard_reason"], "fields": fields}
    if drift_bps >= hard_bps:
        fields["late_entry_price_drift_guard_blocked"] = True
        fields["late_entry_price_drift_guard_reason"] = "hard_price_drift_after_latency"
        return {"blocked": True, "reason": fields["late_entry_price_drift_guard_reason"], "fields": fields}
    if not micro_reconfirmed:
        fields["late_entry_price_drift_guard_blocked"] = True
        fields["late_entry_price_drift_guard_reason"] = "soft_price_drift_without_micro_reconfirmation"
        return {"blocked": True, "reason": fields["late_entry_price_drift_guard_reason"], "fields": fields}
    fields["late_entry_price_drift_guard_reason"] = "micro_reconfirmed_after_soft_drift"
    return {"blocked": False, "reason": fields["late_entry_price_drift_guard_reason"], "fields": fields}


def _evaluate_weak_context_late_entry_guard(
    *,
    strategy: str,
    stock: dict,
    now_ts: float,
    latency_gate: dict,
    late_drift_guard: dict,
    pre_submit_fields: dict | None = None,
    microstructure_fields: dict | None = None,
    orderbook_fields: dict | None = None,
) -> dict:
    fields = {
        "weak_context_late_entry_guard_enabled": bool(_rule_bool("WEAK_CONTEXT_LATE_ENTRY_GUARD_ENABLED", False)),
        "weak_context_late_entry_guard_blocked": False,
        "weak_context_guard_reason": "disabled",
        "trade_quality_signature_version": "trade_quality_signature_v1",
        "entry_fill_quality_signature": "weak_context_late_entry_v1",
    }
    if not fields["weak_context_late_entry_guard_enabled"]:
        return {"blocked": False, "reason": fields["weak_context_guard_reason"], "fields": fields}
    if not _is_scalp_strategy(strategy):
        fields["weak_context_guard_reason"] = "not_scalping"
        return {"blocked": False, "reason": fields["weak_context_guard_reason"], "fields": fields}
    if _rule_bool("ENTRY_STAGE_LIVE_TUNING_SELECTED", False):
        fields["weak_context_guard_reason"] = "entry_live_tuning_selected"
        return {"blocked": False, "reason": fields["weak_context_guard_reason"], "fields": fields}
    if _is_scalp_simulated_position(stock, strategy) or _has_sim_probe_provenance(stock):
        fields["weak_context_guard_reason"] = "sim_or_probe_scope"
        return {"blocked": False, "reason": fields["weak_context_guard_reason"], "fields": fields}

    recent_counts = _recent_trade_quality_block_counts(stock, now_ts=now_ts)
    min_block_count = max(1, _rule_int("WEAK_CONTEXT_LATE_ENTRY_MIN_BLOCK_COUNT", 2))
    late_drift_fields = late_drift_guard.get("fields") if isinstance(late_drift_guard, dict) else {}
    late_drift_fields = late_drift_fields if isinstance(late_drift_fields, dict) else {}
    source_quality_fields = (stock or {}).get("last_watching_ai_source_quality_fields")
    source_quality_fields = source_quality_fields if isinstance(source_quality_fields, dict) else {}
    tick_accel = _first_float_field(
        latency_gate,
        pre_submit_fields,
        microstructure_fields,
        orderbook_fields,
        late_drift_fields,
        source_quality_fields,
        stock or {},
        key="tick_acceleration_ratio",
        aliases=("tick_accel", "tick_acceleration", "late_entry_fresh_tick_acceleration_ratio"),
        default=0.0,
    )
    buy_pressure = _first_float_field(
        latency_gate,
        pre_submit_fields,
        microstructure_fields,
        orderbook_fields,
        late_drift_fields,
        source_quality_fields,
        stock or {},
        key="buy_pressure_10t",
        aliases=("buy_pressure", "buy_pressure_ratio", "late_entry_fresh_buy_pressure_10t"),
        default=0.0,
    )
    micro_vwap_bp = _first_float_field(
        latency_gate,
        pre_submit_fields,
        microstructure_fields,
        orderbook_fields,
        late_drift_fields,
        source_quality_fields,
        stock or {},
        key="curr_vs_micro_vwap_bp",
        aliases=("micro_vwap_bp", "late_entry_fresh_micro_vwap_bp"),
        default=0.0,
    )

    weak_reasons: list[str] = []
    if micro_vwap_bp < _rule_float("WEAK_CONTEXT_LATE_ENTRY_MIN_MICRO_VWAP_BP", 0.0):
        weak_reasons.append("micro_vwap_negative")
    if buy_pressure <= _rule_float("WEAK_CONTEXT_LATE_ENTRY_MIN_BUY_PRESSURE", 0.0):
        weak_reasons.append("buy_pressure_non_positive")
    if tick_accel < _rule_float("WEAK_CONTEXT_LATE_ENTRY_MIN_TICK_ACCEL", 1.10):
        weak_reasons.append("tick_accel_below_min")
    has_drift_context = bool(
        late_drift_fields.get("late_entry_latency_relevant")
        and _safe_float(late_drift_fields.get("late_entry_price_drift_bps"), 0.0)
        >= float(_rule_int("SCALP_LATE_ENTRY_PRICE_DRIFT_SOFT_BPS", 35))
    )
    if has_drift_context:
        weak_reasons.append("late_entry_drift_context")
    weak_signal_count = len([reason for reason in weak_reasons if reason != "late_entry_drift_context"])
    current_context_weak = has_drift_context or weak_signal_count >= 2

    fields.update(
        {
            "recent_blocked_strength_count": _safe_int(recent_counts.get("blocked_strength_momentum"), 0),
            "recent_blocked_vpw_count": _safe_int(recent_counts.get("blocked_vpw"), 0),
            "recent_blocked_overbought_count": _safe_int(recent_counts.get("blocked_overbought"), 0),
            "pre_entry_block_signature": recent_counts.get("signature") or "-",
            "weak_context_guard_lookback_sec": _safe_int(recent_counts.get("lookback_sec"), 0),
            "weak_context_guard_min_block_count": min_block_count,
            "weak_context_guard_tick_accel": f"{tick_accel:.3f}",
            "weak_context_guard_buy_pressure_10t": f"{buy_pressure:.2f}",
            "weak_context_guard_curr_vs_micro_vwap_bp": f"{micro_vwap_bp:.2f}",
            "weak_context_guard_has_drift_context": has_drift_context,
            "weak_context_guard_weak_signal_count": weak_signal_count,
        }
    )

    if recent_counts.get("total_count", 0) < min_block_count:
        fields["weak_context_guard_reason"] = "insufficient_recent_block_history"
        return {"blocked": False, "reason": fields["weak_context_guard_reason"], "fields": fields}
    if not current_context_weak:
        fields["weak_context_guard_reason"] = "current_submit_context_not_weak"
        return {"blocked": False, "reason": fields["weak_context_guard_reason"], "fields": fields}

    fields["weak_context_late_entry_guard_blocked"] = True
    fields["weak_context_guard_reason"] = "|".join(weak_reasons)
    return {"blocked": True, "reason": fields["weak_context_guard_reason"], "fields": fields}


def _truthy_field(value) -> bool:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    return str(value or "").strip().lower() in {"1", "true", "yes", "on", "y"}


def _entry_latency_allows_normal_submit(latency_gate: dict | None) -> bool:
    fields = latency_gate if isinstance(latency_gate, dict) else {}
    for key in ("effective_decision", "policy_decision", "decision"):
        decision = str(fields.get(key) or "").strip().upper()
        if decision:
            return decision == "ALLOW_NORMAL"
    return False


def _entry_submit_field(*sources, key: str, default=None, aliases=None):
    keys = [key, *(aliases or [])]
    for source in sources:
        if not isinstance(source, dict):
            continue
        for candidate_key in keys:
            if source.get(candidate_key) not in (None, ""):
                return source.get(candidate_key)
    return default


def _evaluate_real_weak_pullback_entry_block(
    *,
    strategy,
    stock,
    latency_gate,
    pre_ai_fields,
    guard_fields,
    orderbook_fields,
    microstructure_fields=None,
) -> dict:
    if str(strategy or "").upper() not in {"SCALPING", "SCALP"}:
        return {"blocked": False, "reason": "non_scalping"}
    if not _rule_bool("SCALP_REAL_WEAK_PULLBACK_ENTRY_BLOCK_ENABLED", False):
        return {"blocked": False, "reason": "disabled"}
    if _is_any_simulated_position(stock, strategy) or _is_swing_live_order_dry_run(strategy):
        return {"blocked": False, "reason": "sim_or_dry_run"}

    latency_fields = latency_gate if isinstance(latency_gate, dict) else {}
    latency_state = str(latency_fields.get("latency_state") or "").strip().upper()
    if latency_state == "DANGER":
        return {"blocked": False, "reason": "latency_danger_precedes_weak_pullback"}
    if not _entry_latency_allows_normal_submit(latency_fields):
        return {"blocked": False, "reason": "not_allow_normal"}

    weak_states = {"weak_momentum_context", "below_static_vpw_context"}
    weak_reasons = {"below_buy_ratio", "below_window_buy_value"}
    strength_state = str(
        _entry_submit_field(
            pre_ai_fields,
            guard_fields,
            latency_fields,
            stock,
            key="strength_momentum_risk_state",
            aliases=("entry_strength_momentum_risk_state", "strength_momentum_state"),
            default="",
        )
    ).strip()
    strength_reason = str(
        _entry_submit_field(
            pre_ai_fields,
            guard_fields,
            latency_fields,
            stock,
            key="strength_momentum_reason",
            aliases=("entry_strength_momentum_reason",),
            default="",
        )
    ).strip()
    weak_strength = strength_state in weak_states or strength_reason in weak_reasons
    if not weak_strength:
        return {"blocked": False, "reason": "strength_not_weak"}

    context = latency_fields.get("conditional_1tick_real_override_context")
    context = context if isinstance(context, dict) else {}
    spread_ticks = _safe_int(
        context.get("spread_ticks")
        or _entry_submit_field(orderbook_fields, microstructure_fields, key="orderbook_micro_spread_ticks", default=0),
        0,
    )
    min_spread_ticks = max(0, _rule_int("SCALP_REAL_WEAK_PULLBACK_ENTRY_BLOCK_MIN_SPREAD_TICKS", 5))
    if spread_ticks < min_spread_ticks:
        return {"blocked": False, "reason": "spread_not_wide", "spread_ticks": spread_ticks}

    positive_signal_count = sum(
        1
        for name in ("buy_pressure_ok", "ofi_ok", "depth_ok")
        if _truthy_field(context.get(name))
    )
    micro_state = str(
        _entry_submit_field(orderbook_fields, microstructure_fields, latency_fields, key="orderbook_micro_state", default="")
    ).strip().lower()
    if micro_state in {"bullish", "strong_bullish"} and positive_signal_count <= 0:
        positive_signal_count = 1

    min_micro_positives = max(0, _rule_int("SCALP_REAL_WEAK_PULLBACK_ENTRY_BLOCK_MIN_MICRO_POSITIVES", 2))
    if positive_signal_count >= min_micro_positives:
        return {
            "blocked": False,
            "reason": "micro_confirmed",
            "positive_signal_count": positive_signal_count,
            "spread_ticks": spread_ticks,
        }

    overbought_state = str(
        _entry_submit_field(pre_ai_fields, guard_fields, latency_fields, key="overbought_risk_state", default="")
    ).strip()
    overbought_bucket = str(
        _entry_submit_field(pre_ai_fields, guard_fields, latency_fields, key="overbought_risk_bucket", default="")
    ).strip()
    return {
        "blocked": True,
        "reason": "weak_momentum_caution_without_micro_confirmation",
        "block_reason": "weak_momentum_caution_without_micro_confirmation",
        "threshold_family": "operator_real_weak_pullback_entry_block",
        "decision_authority": "operator_runtime_override_real_entry_block",
        "runtime_effect": True,
        "actual_order_submitted": False,
        "broker_order_forbidden": True,
        "weak_pullback_entry_block_enabled": True,
        "weak_pullback_entry_block_min_micro_positives": min_micro_positives,
        "weak_pullback_entry_block_min_spread_ticks": min_spread_ticks,
        "weak_pullback_entry_block_positive_signal_count": positive_signal_count,
        "weak_pullback_entry_block_spread_ticks": spread_ticks,
        "weak_pullback_entry_block_strength_state": strength_state or "-",
        "weak_pullback_entry_block_strength_reason": strength_reason or "-",
        "weak_pullback_entry_block_overbought_state": overbought_state or "-",
        "weak_pullback_entry_block_overbought_bucket": overbought_bucket or "-",
        "weak_pullback_entry_block_micro_state": micro_state or "-",
        "forbidden_uses": "sim_probe_authority_change,provider_route_change,score_threshold_mutation,quantity_cap_release,broker_guard_bypass,tuning_auto_apply_authority",
    }


def _entry_planned_total_qty(planned_orders) -> int:
    total = 0
    for order in planned_orders or []:
        try:
            total += max(0, int((order or {}).get("qty", 0) or 0))
        except (TypeError, ValueError):
            continue
    return total


def _resolve_passive_probe_candidate_price(*, candidate_price, best_bid, curr_price, max_below_bid_ticks):
    candidate_price = _coerce_int_value(candidate_price)
    best_bid = _coerce_int_value(best_bid)
    if candidate_price <= 0 or best_bid <= 0:
        return candidate_price, 0, 0
    tick_size = int(kiwoom_utils.get_tick_size(_coerce_int_value(curr_price) or best_bid) or 1)
    tick_size = max(1, tick_size)
    max_below_bid_ticks = max(0, int(max_below_bid_ticks or 0))
    floor_price = clamp_price_to_tick(best_bid - (tick_size * max_below_bid_ticks))
    if floor_price <= 0:
        return candidate_price, tick_size, 0
    return max(candidate_price, floor_price), tick_size, floor_price


def _maybe_apply_entry_passive_probe(
    *,
    stock,
    latency_gate,
    planned_orders,
    action,
    candidate_price,
    curr_price,
    best_bid,
    best_ask,
):
    if not bool(_rule("SCALPING_ENTRY_PASSIVE_PROBE_ENABLED", True)):
        return candidate_price, {}
    if str(action or "").strip().upper() != "USE_DEFENSIVE":
        return candidate_price, {}
    latency_state = str((latency_gate or {}).get("latency_state") or "").strip().upper()
    if latency_state != "DANGER":
        return candidate_price, {}
    watching_action = str((stock or {}).get("last_watching_ai_action") or "").strip().upper()
    watching_score = _safe_float((stock or {}).get("last_watching_ai_score"), 0.0)
    min_score = float(_rule("SCALPING_ENTRY_PASSIVE_PROBE_MIN_AI_SCORE", 75) or 75)
    if watching_action != "WAIT" or watching_score < min_score:
        return candidate_price, {}
    max_qty = int(_rule("SCALPING_ENTRY_PASSIVE_PROBE_MAX_QTY", 1) or 1)
    total_qty = _entry_planned_total_qty(planned_orders)
    if total_qty <= 0 or total_qty > max_qty:
        return candidate_price, {}

    max_below_bid_ticks = int(_rule("SCALPING_ENTRY_PASSIVE_PROBE_MAX_BELOW_BID_TICKS", 1) or 1)
    adjusted_price, tick_size, floor_price = _resolve_passive_probe_candidate_price(
        candidate_price=candidate_price,
        best_bid=best_bid,
        curr_price=curr_price,
        max_below_bid_ticks=max_below_bid_ticks,
    )
    if adjusted_price <= 0:
        return candidate_price, {}
    if _coerce_int_value(best_ask) > 0 and adjusted_price > _coerce_int_value(best_ask):
        return candidate_price, {}

    return adjusted_price, {
        "entry_order_lifecycle": "passive_probe",
        "entry_passive_probe_applied": True,
        "entry_passive_probe_reason": "wait_score_danger_defensive_1share",
        "entry_passive_probe_original_price": _coerce_int_value(candidate_price),
        "entry_passive_probe_adjusted_price": _coerce_int_value(adjusted_price),
        "entry_passive_probe_floor_price": _coerce_int_value(floor_price),
        "entry_passive_probe_tick_size": int(tick_size or 0),
        "entry_passive_probe_max_below_bid_ticks": max_below_bid_ticks,
        "entry_passive_probe_ai_action": watching_action,
        "entry_passive_probe_ai_score": f"{watching_score:.1f}",
        "entry_passive_probe_total_qty": total_qty,
    }


def _fresh_entry_defensive_price_from_context(
    *,
    latency_gate,
    current_price,
    best_bid,
    applied_bps,
) -> tuple[int, dict[str, Any]]:
    """Rebase defensive submit price on the freshest pre-submit price context."""
    original_price = _coerce_int_value((latency_gate or {}).get("latency_guarded_order_price"))
    original_basis = _coerce_int_value((latency_gate or {}).get("latest_price"))
    context_best_bid = _coerce_int_value(best_bid)
    context_current = _coerce_int_value(current_price)
    fresh_basis = max(context_best_bid, context_current, original_basis)
    if fresh_basis <= 0 or applied_bps <= 0:
        return original_price, {
            "entry_price_fresh_basis_applied": False,
            "entry_price_fresh_basis_reason": "invalid_basis_or_bps",
            "entry_price_fresh_basis_price": fresh_basis,
            "entry_price_fresh_basis_original_price": original_price,
        }

    fresh_price = move_price_down_by_bps(fresh_basis, int(applied_bps), floor_ticks=1)
    fresh_price = clamp_price_to_tick(fresh_price)
    applied = fresh_price > original_price
    return (fresh_price if applied else original_price), {
        "entry_price_fresh_basis_applied": bool(applied),
        "entry_price_fresh_basis_reason": (
            "rebased_to_fresh_context"
            if applied
            else "fresh_context_not_more_aggressive_than_existing_defensive"
        ),
        "entry_price_fresh_basis_price": int(fresh_basis),
        "entry_price_fresh_basis_original_price": int(original_price),
        "entry_price_fresh_basis_recomputed_price": int(fresh_price),
        "entry_price_fresh_basis_context_best_bid": int(context_best_bid),
        "entry_price_fresh_basis_context_current": int(context_current),
        "entry_price_fresh_basis_original_latest": int(original_basis),
        "entry_price_fresh_basis_bps": int(applied_bps),
    }


def _build_entry_submit_revalidation_fields(ws_data, latency_gate, *, now_ts=None):
    now_ts = float(now_ts or time.time())
    decision_ts = _safe_float((latency_gate or {}).get("ai_entry_price_canary_decision_ts"), 0.0)
    context_age_ms = _coerce_int_value((latency_gate or {}).get("ai_entry_price_canary_context_age_ms"))
    quote_age_sec = _get_ws_snapshot_age_sec(ws_data)
    quote_age_ms = "-" if quote_age_sec is None else int(round(quote_age_sec * 1000.0))
    decision_age_ms = "-" if decision_ts <= 0 else int(round(max(0.0, now_ts - decision_ts) * 1000.0))
    max_context_age_ms = _env_or_rule_int("SCALPING_ENTRY_SUBMIT_REVALIDATION_MAX_CONTEXT_AGE_MS", 8000)
    max_quote_age_ms = _env_or_rule_int("SCALPING_ENTRY_SUBMIT_REVALIDATION_MAX_QUOTE_AGE_MS", 2000)
    context_stale = context_age_ms > max_context_age_ms if context_age_ms else False
    quote_stale = quote_age_ms != "-" and int(quote_age_ms) > max_quote_age_ms
    return {
        "entry_submit_revalidation": "checked",
        "price_decision_age_ms": decision_age_ms,
        "price_decision_context_age_ms": context_age_ms or "-",
        "quote_age_at_submit_ms": quote_age_ms,
        "price_context_stale_at_submit": bool(context_stale),
        "quote_stale_at_submit": bool(quote_stale),
        "entry_submit_revalidation_warning": "stale_context_or_quote" if (context_stale or quote_stale) else "",
        "entry_order_lifecycle": str((latency_gate or {}).get("entry_order_lifecycle") or "standard"),
        "entry_passive_probe_applied": bool((latency_gate or {}).get("entry_passive_probe_applied")),
        "entry_passive_probe_reason": str((latency_gate or {}).get("entry_passive_probe_reason") or ""),
    }


def _is_passive_probe_stale_submit_block(submit_revalidation_fields) -> bool:
    if not _env_or_rule_bool("SCALPING_ENTRY_PASSIVE_PROBE_STALE_SUBMIT_BLOCK_ENABLED", True):
        return False
    fields = submit_revalidation_fields or {}
    if str(fields.get("entry_order_lifecycle") or "").strip() != "passive_probe":
        return False
    return bool(fields.get("price_context_stale_at_submit") or fields.get("quote_stale_at_submit"))


def _is_standard_stale_submit_block(submit_revalidation_fields) -> bool:
    if not _env_or_rule_bool("SCALPING_ENTRY_SUBMIT_REVALIDATION_BLOCK_STALE_STANDARD_ENABLED", True):
        return False
    fields = submit_revalidation_fields or {}
    if str(fields.get("entry_order_lifecycle") or "standard").strip() != "standard":
        return False
    return bool(fields.get("price_context_stale_at_submit") or fields.get("quote_stale_at_submit"))


def _is_caution_overbought_stale_submit_block(
    *,
    strategy: str | None,
    submit_revalidation_fields: dict | None,
    latency_gate: dict | None,
    guard_fields: dict | None,
) -> bool:
    if not _rule_bool("SCALPING_ENTRY_CAUTION_OVERBOUGHT_STALE_SUBMIT_BLOCK_ENABLED", True):
        return False
    if str(strategy or "").strip().upper() not in {"SCALPING", "SCALP"}:
        return False
    submit_fields = submit_revalidation_fields if isinstance(submit_revalidation_fields, dict) else {}
    if not bool(submit_fields.get("price_context_stale_at_submit") or submit_fields.get("quote_stale_at_submit")):
        return False
    latency_state = str((latency_gate or {}).get("latency_state") or "").strip().upper()
    if latency_state != "CAUTION":
        return False
    fields = guard_fields if isinstance(guard_fields, dict) else {}
    overbought_state = str(
        fields.get("pre_submit_overbought_risk_state")
        or fields.get("overbought_risk_state")
        or ""
    ).strip()
    return overbought_state == "pullback_observed"


def _resolve_buy_order_timeout_sec(stock, strategy):
    normalized_strategy = 'SCALPING' if str(strategy or '').upper() in ('SCALPING', 'SCALP') else str(strategy or '').upper()
    if normalized_strategy != 'SCALPING':
        if _coerce_int_value((stock or {}).get('target_buy_price')) > 0:
            return _rule_int('RESERVE_TIMEOUT_SEC', 1200)
        return _rule_int('ORDER_TIMEOUT_SEC', 30)

    attribution_enabled = _rule_bool('ENTRY_CANCEL_WAIT_ATTRIBUTION_ENABLED', False)

    if attribution_enabled:
        stored_result = (stock or {}).get('entry_cancel_wait_attribution_result')
        if isinstance(stored_result, dict) and stored_result.get('cancel_wait_sec'):
            return max(5, min(1200, int(stored_result.get('cancel_wait_sec', 90) or 90)))

    explicit_timeout = _coerce_int_value((stock or {}).get('entry_timeout_sec_override'))

    profile = str(
        (stock or {}).get('entry_timeout_profile')
        or (stock or {}).get('entry_price_timeout_profile')
        or (stock or {}).get('entry_mode')
        or ''
    ).strip().upper()
    pos_tag = normalize_position_tag('SCALPING', (stock or {}).get('position_tag'))

    if profile in {'RESERVE', 'RESERVED'} or pos_tag in {'RESERVE', 'RESERVED'}:
        base_sec = _rule_int('SCALPING_RESERVE_ENTRY_TIMEOUT_SEC', 1200)
    elif 'PULLBACK' in profile or 'PULLBACK' in pos_tag:
        base_sec = _rule_int('SCALPING_PULLBACK_ENTRY_TIMEOUT_SEC', 600)
    elif 'BREAKOUT' in profile or 'BREAKOUT' in pos_tag:
        base_sec = _rule_int('SCALPING_BREAKOUT_ENTRY_TIMEOUT_SEC', 120)
    else:
        base_sec = _rule_int('SCALPING_ENTRY_TIMEOUT_SEC', 90)

    return base_sec


def _entry_cancel_wait_profile_base_sec(stock) -> tuple[str, int]:
    profile = resolve_entry_cancel_wait_profile(
        (stock or {}).get("position_tag"), (stock or {}).get("entry_mode")
    )
    rule_name, default = {
        "standard": ("SCALPING_ENTRY_TIMEOUT_SEC", 60),
        "breakout": ("SCALPING_BREAKOUT_ENTRY_TIMEOUT_SEC", 120),
        "pullback": ("SCALPING_PULLBACK_ENTRY_TIMEOUT_SEC", 600),
        "reserve": ("SCALPING_RESERVE_ENTRY_TIMEOUT_SEC", 1200),
    }[profile]
    return profile, max(5, min(1200, _rule_int(rule_name, default)))


def _compute_and_emit_entry_cancel_wait_attribution(stock, code, *, latency_gate=None, curr_price=0):
    if not isinstance(stock, dict):
        return None
    attribution_enabled = _rule_bool('ENTRY_CANCEL_WAIT_ATTRIBUTION_ENABLED', False)
    real_min_sec = _rule_int('ENTRY_CANCEL_WAIT_ATTRIBUTION_REAL_MIN_SEC', 60)
    stale_max_sec = _rule_int('ENTRY_CANCEL_WAIT_ATTRIBUTION_STALE_MAX_SEC', 30)
    gate = latency_gate or {}

    entry_order_lifecycle = str(
        (stock or {}).get('entry_order_lifecycle')
        or gate.get('entry_order_lifecycle')
        or 'standard'
    ).strip()
    entry_passive_probe_applied = bool(
        stock.get('entry_passive_probe_applied') or gate.get('entry_passive_probe_applied')
    )

    position_tag = normalize_position_tag('SCALPING', stock.get('position_tag'))
    entry_mode = str(stock.get('entry_mode') or '').strip()

    best_bid = _coerce_int_value(gate.get('ai_entry_price_canary_context_best_bid') or gate.get('best_bid_at_submit'))
    best_ask = _coerce_int_value(gate.get('ai_entry_price_canary_context_best_ask') or gate.get('best_ask_at_submit'))
    order_price = _coerce_int_value(gate.get('order_price'))

    quote_age_ms = _safe_int(gate.get('quote_age_at_submit_ms') or stock.get('quote_age_at_submit_ms'), 0)
    quote_stale = bool(gate.get('quote_stale_at_submit') or stock.get('quote_stale_at_submit'))
    context_age_ms = _safe_int(
        gate.get('ai_entry_price_canary_context_age_ms') or gate.get('price_decision_context_age_ms'), 0
    )
    context_stale = bool(gate.get('price_context_stale_at_submit') or stock.get('price_context_stale_at_submit'))

    liquidity_verdict = str(gate.get('liquidity_guard_action') or gate.get('liquidity_value') or '').strip()
    ai_action = str(gate.get('ai_entry_price_canary_action') or '').strip().upper()
    ai_confidence = _safe_int(gate.get('ai_entry_price_canary_confidence'), 0)
    ofi_direction = str(gate.get('ofi_ai_smoothing_verdict') or gate.get('ofi_direction_label') or '').strip()

    score_bucket = str(stock.get('score_bucket') or stock.get('ai_score_bucket') or '').strip()

    active_priority = bool(
        stock.get('entry_adm_active_priority_matched')
        or gate.get('active_priority_matched')
    )

    cancelled_or_filled_qty = _safe_int(stock.get('entry_filled_qty'), 0)
    requested_qty = _safe_int(stock.get('entry_requested_qty') or stock.get('requested_buy_qty'), 0)

    spread_ratio = 0.0
    if best_bid > 0 and best_ask > 0 and best_ask > best_bid:
        spread_ratio = float(best_ask - best_bid) / float(best_bid)

    overbought_action = str(gate.get('overbought_guard_action') or '').strip()

    suggested_wait_sec = _coerce_int_value((stock or {}).get('entry_timeout_sec_override'))
    wait_profile, profile_base_wait_sec = _entry_cancel_wait_profile_base_sec(stock)

    result = compute_entry_cancel_wait_attribution(
        cancelled_or_partial_filled_qty=cancelled_or_filled_qty,
        requested_qty=requested_qty,
        position_tag=position_tag,
        entry_mode=entry_mode,
        entry_order_lifecycle=entry_order_lifecycle,
        entry_passive_probe_applied=entry_passive_probe_applied,
        best_bid=best_bid,
        best_ask=best_ask,
        order_price=order_price,
        quote_age_ms=quote_age_ms,
        quote_stale_at_submit=quote_stale,
        context_age_ms=context_age_ms,
        context_stale_at_submit=context_stale,
        liquidity_verdict=liquidity_verdict,
        ai_action=ai_action,
        ai_confidence=ai_confidence,
        score_bucket=score_bucket,
        ofi_direction_label=ofi_direction,
        active_priority_matched=active_priority,
        suggested_wait_sec=suggested_wait_sec,
        is_report_only=not attribution_enabled,
        real_min_sec=real_min_sec,
        stale_max_sec=stale_max_sec,
        spread_ratio=spread_ratio,
        overbought_guard_action=overbought_action,
        profile_base_wait_sec=profile_base_wait_sec,
    )

    wait_log_fields = result.as_log_fields()
    wait_log_fields.update({
        key: str(value)
        for key, value in (result.attribution_context_summary or {}).items()
    })
    stored = {
        "cancel_wait_sec": result.cancel_wait_sec,
        "base_wait_sec": result.base_wait_sec,
        "min_wait_sec": result.min_wait_sec,
        "max_wait_sec": result.max_wait_sec,
        "suggested_wait_sec": result.suggested_wait_sec,
        "wait_adjustment_reasons": result.adjustment_reasons,
        "wait_policy_version": result.wait_policy_version,
        "decision_authority": result.decision_authority,
        "forbidden_uses": result.forbidden_uses,
        "wait_policy_applied": attribution_enabled,
        "is_report_only": not attribution_enabled,
        "actual_timeout_sec": 0,
        "attribution_emitted_at": time.time(),
        "wait_profile": wait_profile,
        "runtime_family": ENTRY_CANCEL_WAIT_RUNTIME_FAMILY,
        "policy_version": ENTRY_CANCEL_WAIT_POLICY_VERSION,
    }
    with ENTRY_LOCK:
        stock['entry_cancel_wait_attribution_result'] = stored

    actual_timeout_sec = _resolve_buy_order_timeout_sec(stock, stock.get('strategy'))
    with ENTRY_LOCK:
        stored = stock.get('entry_cancel_wait_attribution_result', {})
        if isinstance(stored, dict):
            stored['actual_timeout_sec'] = actual_timeout_sec
            stored['projected_cancel_wait_sec'] = result.cancel_wait_sec
            if not attribution_enabled:
                stored['cancel_wait_sec'] = actual_timeout_sec

    wait_log_fields.update({
        "projected_cancel_wait_sec": str(result.cancel_wait_sec),
        "cancel_wait_sec": str(actual_timeout_sec if not attribution_enabled else result.cancel_wait_sec),
        "wait_policy_applied": str(attribution_enabled).lower(),
        "is_report_only": str(not attribution_enabled).lower(),
        "selected_timeout_sec": str(actual_timeout_sec),
        "actual_timeout_sec": str(actual_timeout_sec),
        "wait_profile": wait_profile,
        "runtime_family": ENTRY_CANCEL_WAIT_RUNTIME_FAMILY,
        "policy_version": ENTRY_CANCEL_WAIT_POLICY_VERSION,
    })
    _log_entry_pipeline(stock, code, "entry_cancel_wait_attribution", **wait_log_fields)

    return result


def _observe_entry_cancel_wait_counterfactuals(stock, code, *, now_ts: float, curr_price: int) -> None:
    observations = list((stock or {}).get("entry_cancel_wait_counterfactuals") or [])
    if not observations or curr_price <= 0:
        return
    remaining = []
    for observation in observations:
        updated, events = observe_counterfactual(observation, now_ts=now_ts, current_price=curr_price)
        common = {
            "runtime_family": ENTRY_CANCEL_WAIT_RUNTIME_FAMILY,
            "policy_version": ENTRY_CANCEL_WAIT_POLICY_VERSION,
            "decision_authority": ENTRY_CANCEL_WAIT_COUNTERFACTUAL_AUTHORITY,
            "runtime_effect": False,
            "actual_order_submitted": False,
            "broker_order_forbidden": True,
            "forbidden_uses": "adm_ldm_input|lifecycle_bucket_input|general_threshold_ev_input|order_authority",
            "source_order_no": updated.get("order_no"),
            "wait_profile": updated.get("profile"),
            "submitted_price": updated.get("submitted_price"),
            "qty": updated.get("qty"),
            "actual_timeout_sec": updated.get("actual_timeout_sec"),
            "selected_timeout_sec": updated.get("selected_timeout_sec"),
        }
        for event in events:
            payload = dict(event)
            stage = str(payload.pop("stage"))
            _log_entry_pipeline(stock, code, stage, **common, **payload)
        if not updated.get("completed"):
            remaining.append(updated)
    _mutate_stock_state(stock, set_fields={"entry_cancel_wait_counterfactuals": remaining})


def _build_entry_ai_price_context(stock, latency_gate, *, curr_price, best_bid, best_ask):
    ctx = {
        "strategy": normalize_strategy((stock or {}).get("strategy")),
        "position_tag": normalize_position_tag("SCALPING", (stock or {}).get("position_tag")),
        "current_price": _coerce_int_value(curr_price),
        "best_bid": _coerce_int_value(best_bid),
        "best_ask": _coerce_int_value(best_ask),
        "reference_target_price": _coerce_int_value((latency_gate or {}).get("target_buy_price")),
        "defensive_order_price": _coerce_int_value((latency_gate or {}).get("latency_guarded_order_price")),
        "normal_defensive_order_price": _coerce_int_value((latency_gate or {}).get("normal_defensive_order_price")),
        "resolved_order_price": _coerce_int_value((latency_gate or {}).get("order_price")),
        "resolution_reason": str((latency_gate or {}).get("price_resolution_reason") or ""),
        "price_below_bid_bps": _compute_price_below_bid_bps(
            _coerce_int_value((latency_gate or {}).get("order_price")),
            best_bid,
        ),
        "reference_target_below_bid_bps": _coerce_int_value((latency_gate or {}).get("reference_target_below_bid_bps")),
        "latency_state": str((latency_gate or {}).get("latency_state") or ""),
        "ws_age_ms": _coerce_int_value((latency_gate or {}).get("ws_age_ms")),
        "ws_jitter_ms": _coerce_int_value((latency_gate or {}).get("ws_jitter_ms")),
        "spread_ratio": float((latency_gate or {}).get("spread_ratio", 0.0) or 0.0),
        "quote_stale": bool((latency_gate or {}).get("quote_stale")),
        "signal_score": round(float((stock or {}).get("rt_ai_prob", (stock or {}).get("prob", 0.0)) or 0.0) * 100.0, 2),
    }
    orderbook_micro = _build_orderbook_micro_context(
        latency_gate,
        curr_price=curr_price,
        best_bid=best_bid,
        best_ask=best_ask,
    )
    if orderbook_micro is not None:
        ctx["orderbook_micro"] = orderbook_micro
    return ctx


def _apply_entry_ai_price_canary(
    *,
    stock,
    code,
    strategy,
    ws_data,
    ai_engine,
    latency_gate,
    planned_orders,
    curr_price,
    best_bid,
    best_ask,
    refresh_attempt=False,
):
    if strategy not in ("SCALPING", "SCALP"):
        return planned_orders, False
    if not bool(_rule("SCALPING_ENTRY_AI_PRICE_CANARY_ENABLED", True)):
        return planned_orders, False
    if ai_engine is None or not hasattr(ai_engine, "evaluate_scalping_entry_price"):
        _log_entry_pipeline(stock, code, "entry_ai_price_canary_fallback", reason="ai_engine_unavailable")
        return planned_orders, False

    current_price = _coerce_int_value(curr_price)
    defensive_price = _coerce_int_value((latency_gate or {}).get("latency_guarded_order_price"))
    reference_price = _coerce_int_value((latency_gate or {}).get("target_buy_price"))
    resolved_price = _coerce_int_value((latency_gate or {}).get("order_price"))
    price_context_started_at = time.time()
    price_ctx = _build_entry_ai_price_context(
        stock,
        latency_gate,
        curr_price=current_price,
        best_bid=best_bid,
        best_ask=best_ask,
    )
    micro_log_fields = _build_orderbook_micro_log_fields(price_ctx.get("orderbook_micro"))
    planned_order_price = 0
    try:
        if planned_orders and isinstance(planned_orders[0], dict):
            planned_order_price = _coerce_int_value(planned_orders[0].get("price"))
    except Exception:
        planned_order_price = 0
    invalid_price_context_fields = {
        "current_price": current_price,
        "reference_price": reference_price,
        "defensive_order_price": defensive_price,
        "resolved_order_price": resolved_price,
        "best_bid": _coerce_int_value(best_bid),
        "best_ask": _coerce_int_value(best_ask),
        "planned_order_count": len(planned_orders or []),
        "planned_order_price": planned_order_price,
    }

    try:
        tick_limit = int(_rule("SCALPING_ENTRY_AI_PRICE_TICK_LIMIT", 20) or 20)
        candle_limit = int(_rule("SCALPING_ENTRY_AI_PRICE_CANDLE_LIMIT", 20) or 20)
        recent_ticks = kiwoom_utils.get_tick_history_ka10003(KIWOOM_TOKEN, code, limit=tick_limit) or []
        recent_candles = kiwoom_utils.get_minute_candles_ka10080(KIWOOM_TOKEN, code, limit=candle_limit) or []
    except Exception as exc:
        _log_entry_pipeline(
            stock,
            code,
            "entry_ai_price_canary_fallback",
            reason="context_fetch_failed",
            error=str(exc)[:160],
            **micro_log_fields,
        )
        return planned_orders, False

    ai_eval_started_at = time.perf_counter()
    entry_price_metadata = {
        "record_id": stock.get("record_id") or stock.get("id"),
        "sim_record_id": stock.get("sim_record_id"),
        "sim_parent_record_id": stock.get("sim_parent_record_id") or stock.get("record_id") or stock.get("id"),
        "entry_adm_candidate_id": stock.get("entry_adm_candidate_id") or stock.get("candidate_id"),
        "source_event_stage": "entry_price",
    }
    result = ai_engine.evaluate_scalping_entry_price(
        stock.get("name"),
        code,
        ws_data or {},
        recent_ticks,
        recent_candles,
        price_ctx,
        metadata_extra=entry_price_metadata,
    )
    ai_eval_ms = int(round((time.perf_counter() - ai_eval_started_at) * 1000.0))
    decision_ts = time.time()
    context_age_ms = int(round(max(0.0, decision_ts - price_context_started_at) * 1000.0))
    if (
        bool(_rule("SCALPING_ENTRY_PRICE_REFRESH_ENABLED", False))
        and not refresh_attempt
        and not bool(latency_gate.get("ai_entry_price_refresh_attempted"))
    ):
        refresh_age_ms = max(1, _rule_int("SCALPING_ENTRY_PRICE_REFRESH_DECISION_AGE_MS", 1500))
        start_bid = _coerce_int_value(price_ctx.get("best_bid"))
        start_ask = _coerce_int_value(price_ctx.get("best_ask"))
        start_spread = start_ask - start_bid if start_ask > 0 and start_bid > 0 else 0
        current_spread = _coerce_int_value(best_ask) - _coerce_int_value(best_bid) if best_ask > 0 and best_bid > 0 else 0
        micro = price_ctx.get("orderbook_micro") if isinstance(price_ctx.get("orderbook_micro"), dict) else {}
        micro_state = str(micro.get("micro_state") or "")
        current_micro = _build_orderbook_micro_context(
            latency_gate,
            curr_price=curr_price,
            best_bid=best_bid,
            best_ask=best_ask,
        )
        current_micro_state = str((current_micro or {}).get("micro_state") or micro_state)
        should_refresh = (
            context_age_ms > refresh_age_ms
            or (start_bid > 0 and abs(_coerce_int_value(best_bid) - start_bid) >= 1)
            or (start_ask > 0 and abs(_coerce_int_value(best_ask) - start_ask) >= 1)
            or (start_spread > 0 and current_spread > 0 and start_spread != current_spread)
            or (micro_state and current_micro_state and micro_state != current_micro_state)
        )
        if should_refresh:
            latency_gate["ai_entry_price_refresh_attempted"] = True
            _log_entry_pipeline(
                stock,
                code,
                "entry_ai_price_refresh_triggered",
                reason="state_change_or_decision_age",
                context_age_ms=context_age_ms,
                refresh_age_ms=refresh_age_ms,
                start_best_bid=start_bid,
                current_best_bid=_coerce_int_value(best_bid),
                start_best_ask=start_ask,
                current_best_ask=_coerce_int_value(best_ask),
                start_spread=start_spread,
                current_spread=current_spread,
                start_micro_state=micro_state,
                current_micro_state=current_micro_state,
            )
            return _apply_entry_ai_price_canary(
                stock=stock,
                code=code,
                strategy=strategy,
                ws_data=ws_data,
                ai_engine=ai_engine,
                latency_gate=latency_gate,
                planned_orders=planned_orders,
                curr_price=curr_price,
                best_bid=best_bid,
                best_ask=best_ask,
                refresh_attempt=True,
            )
    action = str((result or {}).get("action") or "USE_DEFENSIVE").strip().upper()
    confidence = _coerce_int_value((result or {}).get("confidence"))
    min_confidence = int(_rule("SCALPING_ENTRY_AI_PRICE_MIN_CONFIDENCE", 60) or 60)
    skip_min_confidence = int(_rule("SCALPING_ENTRY_AI_PRICE_SKIP_MIN_CONFIDENCE", 80) or 80)
    reason = str((result or {}).get("reason") or "")
    parse_ok = bool((result or {}).get("ai_parse_ok", True))
    parse_fail = bool((result or {}).get("ai_parse_fail", False))
    source = str((result or {}).get("ai_result_source") or (result or {}).get("result_source") or "live")
    openai_transport_fields = {
        str(key): value
        for key, value in (result or {}).items()
        if str(key).startswith("openai_")
    }

    if parse_fail or not parse_ok:
        _log_entry_pipeline(
            stock, code, "entry_ai_price_canary_fallback", reason="parse_or_ai_fail",
            action=action, confidence=confidence, source=source, **openai_transport_fields, **micro_log_fields,
        )
        return planned_orders, False
    if confidence < min_confidence:
        _log_entry_pipeline(
            stock, code, "entry_ai_price_canary_fallback", reason="low_confidence",
            action=action, confidence=confidence, min_confidence=min_confidence,
            **openai_transport_fields, **micro_log_fields,
        )
        return planned_orders, False

    if action == "SKIP":
        if confidence < skip_min_confidence:
            _log_entry_pipeline(
                stock, code, "entry_ai_price_canary_fallback", reason="skip_low_confidence",
                action=action, confidence=confidence, skip_min_confidence=skip_min_confidence, **micro_log_fields,
            )
            return planned_orders, False
        latency_gate["ai_entry_price_canary_action"] = action
        latency_gate["ai_entry_price_canary_confidence"] = confidence
        latency_gate["ai_entry_price_canary_reason"] = reason
        orderbook_micro = price_ctx.get("orderbook_micro") if isinstance(price_ctx, dict) else {}
        skip_policy_fields = _build_entry_ai_price_skip_policy_fields(orderbook_micro)
        demote_skip, ofi_state = _should_demote_entry_ai_price_skip(confidence, orderbook_micro)
        ofi_log_fields = ofi_smoothing_log_fields(ofi_state, prefix="entry_ai_price_ofi")
        if demote_skip:
            latency_gate["ai_entry_price_canary_raw_action"] = "SKIP"
            latency_gate["ai_entry_price_canary_action"] = "USE_DEFENSIVE"
            latency_gate["ai_entry_price_canary_final_action"] = "USE_DEFENSIVE"
            latency_gate["ai_entry_price_canary_confidence"] = confidence
            latency_gate["ai_entry_price_canary_reason"] = reason
            latency_gate["ai_entry_price_ofi_skip_demoted"] = True
            latency_gate["price_resolution_reason"] = "ai_tier2_skip_demoted_to_p1"
            latency_gate["ai_entry_price_canary_applied"] = True
            _log_entry_pipeline(
                stock,
                code,
                "entry_ai_price_ofi_skip_demoted",
                action="SKIP",
                raw_action="SKIP",
                final_action="USE_DEFENSIVE",
                confidence=confidence,
                reason=reason[:160],
                demotion_path="P1_USE_DEFENSIVE",
                **openai_transport_fields,
                **skip_policy_fields,
                **ofi_log_fields,
                **micro_log_fields,
            )
            return planned_orders, True
        _mutate_stock_state(
            stock,
            set_fields={
                "entry_ai_price_skip_started_at": time.time(),
                "entry_ai_price_skip_mark_price": current_price,
                "entry_ai_price_skip_max_price": current_price,
                "entry_ai_price_skip_min_price": current_price,
                "entry_ai_price_skip_micro_state": str((orderbook_micro or {}).get("micro_state") or ""),
                "entry_ai_price_skip_policy_warning": str(
                    skip_policy_fields.get("entry_ai_price_skip_policy_warning") or ""
                ),
                "entry_ai_price_skip_threshold_source": str((orderbook_micro or {}).get("ofi_threshold_source") or ""),
                "entry_ai_price_skip_bucket_key": str((orderbook_micro or {}).get("ofi_bucket_key") or ""),
                "entry_ai_price_skip_followup_30s": False,
                "entry_ai_price_skip_followup_90s": False,
            },
        )
        _log_entry_pipeline(
            stock, code, "entry_ai_price_canary_skip_order",
            action=action,
            confidence=confidence,
            reason=reason[:160],
            **openai_transport_fields,
            **skip_policy_fields,
            **ofi_log_fields,
            **micro_log_fields,
        )
        return [], True

    if action == "USE_REFERENCE":
        candidate_price = reference_price
    elif action == "IMPROVE_LIMIT":
        candidate_price = _coerce_int_value((result or {}).get("order_price"))
    else:
        action = "USE_DEFENSIVE"
        applied_bps = _coerce_int_value((latency_gate or {}).get("entry_price_gap_profile_bps"))
        candidate_price, fresh_basis_fields = _fresh_entry_defensive_price_from_context(
            latency_gate=latency_gate,
            current_price=current_price,
            best_bid=best_bid,
            applied_bps=applied_bps,
        )
        if candidate_price <= 0:
            candidate_price = defensive_price or resolved_price
            fresh_basis_fields = {
                **fresh_basis_fields,
                "entry_price_fresh_basis_reason": "fallback_to_existing_defensive",
            }

    if candidate_price <= 0:
        _log_entry_pipeline(
            stock, code, "entry_ai_price_canary_fallback", reason="invalid_price", action=action,
            **invalid_price_context_fields, **openai_transport_fields, **micro_log_fields
        )
        return planned_orders, False
    unclamped_candidate_price = candidate_price
    candidate_price = clamp_price_to_tick(candidate_price)
    if candidate_price <= 0:
        _log_entry_pipeline(
            stock, code, "entry_ai_price_canary_fallback", reason="invalid_price", action=action,
            unclamped_candidate_price=unclamped_candidate_price,
            **invalid_price_context_fields,
            **openai_transport_fields,
            **micro_log_fields,
        )
        return planned_orders, False
    if best_ask > 0 and candidate_price > best_ask:
        _log_entry_pipeline(
            stock, code, "entry_ai_price_canary_fallback", reason="above_best_ask",
            action=action, candidate_price=candidate_price, best_ask=best_ask,
            **openai_transport_fields, **micro_log_fields,
        )
        return planned_orders, False
    if _is_pre_submit_price_guard_block(strategy, candidate_price, best_bid):
        _log_entry_pipeline(
            stock, code, "entry_ai_price_canary_fallback", reason="pre_submit_price_guard",
            action=action, candidate_price=candidate_price, best_bid=best_bid,
            **openai_transport_fields, **micro_log_fields,
        )
        return planned_orders, False

    passive_price, passive_fields = _maybe_apply_entry_passive_probe(
        stock=stock,
        latency_gate=latency_gate,
        planned_orders=planned_orders,
        action=action,
        candidate_price=candidate_price,
        curr_price=current_price,
        best_bid=best_bid,
        best_ask=best_ask,
    )
    if passive_fields:
        candidate_price = clamp_price_to_tick(passive_price)
        if _is_pre_submit_price_guard_block(strategy, candidate_price, best_bid):
            _log_entry_pipeline(
                stock,
                code,
                "entry_ai_price_canary_fallback",
                reason="passive_probe_price_guard",
                action=action,
                candidate_price=candidate_price,
                best_bid=best_bid,
                **openai_transport_fields,
                **passive_fields,
                **micro_log_fields,
            )
            return planned_orders, False

    if action == "USE_DEFENSIVE" and fresh_basis_fields.get("entry_price_fresh_basis_applied"):
        defensive_price = _coerce_int_value(
            fresh_basis_fields.get("entry_price_fresh_basis_recomputed_price")
        ) or candidate_price
        latency_gate["latency_guarded_order_price"] = defensive_price
        latency_gate["normal_defensive_order_price"] = defensive_price
        latency_gate["entry_price_fresh_basis_applied"] = True
        latency_gate["entry_price_fresh_basis_reason"] = fresh_basis_fields.get(
            "entry_price_fresh_basis_reason"
        )
        latency_gate["entry_price_fresh_basis_price"] = fresh_basis_fields.get(
            "entry_price_fresh_basis_price"
        )
        latency_gate["entry_price_fresh_basis_recomputed_price"] = fresh_basis_fields.get(
            "entry_price_fresh_basis_recomputed_price"
        )
        latency_gate["latest_price"] = max(
            _coerce_int_value(latency_gate.get("latest_price")),
            _coerce_int_value(fresh_basis_fields.get("entry_price_fresh_basis_price")),
        )

    adjusted_orders = []
    for order in planned_orders or []:
        next_order = dict(order)
        if str(next_order.get("tif", "DAY") or "DAY").upper() != "IOC":
            next_order["price"] = candidate_price
        adjusted_orders.append(next_order)

    max_wait_sec = max(5, min(1200, _coerce_int_value((result or {}).get("max_wait_sec"), 90)))
    if passive_fields:
        passive_timeout_sec = int(_rule("SCALPING_ENTRY_PASSIVE_PROBE_TIMEOUT_SEC", 30) or 30)
        max_wait_sec = max(5, min(max_wait_sec, passive_timeout_sec))
    latency_gate["orders"] = adjusted_orders
    latency_gate["order_price"] = candidate_price
    latency_gate["price_resolution_reason"] = f"ai_tier2_{action.lower()}"
    latency_gate["ai_entry_price_canary_applied"] = True
    latency_gate["ai_entry_price_canary_action"] = action
    latency_gate["ai_entry_price_canary_confidence"] = confidence
    latency_gate["ai_entry_price_canary_reason"] = reason
    latency_gate["ai_entry_price_canary_max_wait_sec"] = max_wait_sec
    latency_gate["ai_entry_price_canary_eval_ms"] = ai_eval_ms
    latency_gate["ai_entry_price_canary_decision_ts"] = decision_ts
    latency_gate["ai_entry_price_canary_context_age_ms"] = context_age_ms
    latency_gate["ai_entry_price_canary_context_best_bid"] = _coerce_int_value(best_bid)
    latency_gate["ai_entry_price_canary_context_best_ask"] = _coerce_int_value(best_ask)
    latency_gate.update(openai_transport_fields)
    if passive_fields:
        latency_gate.update(passive_fields)
    _mutate_stock_state(stock, set_fields={"entry_timeout_sec_override": max_wait_sec})
    _log_entry_pipeline(
        stock,
        code,
        "entry_ai_price_canary_applied",
        action=action,
        confidence=confidence,
        reason=reason[:160],
        original_order_price=resolved_price,
        candidate_price=candidate_price,
        reference_target_price=reference_price,
        defensive_order_price=defensive_price,
        max_wait_sec=max_wait_sec,
        ai_eval_ms=ai_eval_ms,
        price_decision_context_age_ms=context_age_ms,
        **(fresh_basis_fields if action == "USE_DEFENSIVE" else {}),
        **openai_transport_fields,
        **passive_fields,
        **micro_log_fields,
    )
    return adjusted_orders, True


def _get_ws_snapshot_age_sec(ws_data):
    raw_ts = (ws_data or {}).get('last_ws_update_ts')
    if raw_ts in (None, '', 0):
        return None
    try:
        age = time.time() - float(raw_ts)
        return max(0.0, float(age))
    except Exception:
        return None


def _parse_rest_quote_price(value):
    text = str(value or "").strip().replace(",", "").replace("+", "")
    if not text:
        return 0
    try:
        return abs(int(float(text)))
    except Exception:
        return 0


def _fetch_holding_rest_quote_snapshot(code, now_ts):
    if not KIWOOM_TOKEN:
        return {}
    try:
        url = kiwoom_utils.get_api_url("/api/dostk/stkinfo")
        rows = kiwoom_utils.fetch_kiwoom_api_continuous(
            url,
            KIWOOM_TOKEN,
            "ka10001",
            {"stk_cd": code},
            max_retries=1,
            use_continuous=False,
        )
    except Exception as exc:
        log_error(f"[HOLDING_WS_FRESHNESS] quote fallback failed ({code}): {exc}")
        return {}
    if not rows:
        return {}
    row = rows[0] if isinstance(rows[0], dict) else {}
    curr = 0
    for key in ("cur_prc", "curr_price", "price", "stck_prpr", "trade_price"):
        curr = _parse_rest_quote_price(row.get(key))
        if curr > 0:
            break
    if curr <= 0:
        return {}
    return {
        "curr": curr,
        "last_ws_update_ts": float(now_ts),
        "quote_stale": False,
        "quote_age_ms": 0,
        "quote_age_source": "ka10001_rest_quote_fallback",
        "ws_snapshot_recovery_source": "holding_ka10001_rest_quote_fallback",
        "ws_snapshot_recovery_epoch": float(now_ts),
        "ws_snapshot_recovery_runtime_effect": True,
    }


def _holding_exit_ws_max_age_sec():
    return max(1.0, _rule_float("HOLDING_EXIT_MAX_WS_AGE_SEC", 15.0))


def _holding_rest_quote_fallback_min_interval_sec():
    return max(3.0, _rule_float("HOLDING_EXIT_REST_QUOTE_FALLBACK_MIN_INTERVAL_SEC", 10.0))


def _holding_ws_repair_min_interval_sec():
    return max(20.0, _rule_float("HOLDING_EXIT_WS_REPAIR_MIN_INTERVAL_SEC", 60.0))


def _maybe_publish_holding_ws_repair(state, code, fields, *, now_ts):
    min_interval_sec = _holding_ws_repair_min_interval_sec()
    last_reg_ts = _safe_float((state or {}).get("last_ws_repair_reg_ts"), 0.0)
    next_after = last_reg_ts + min_interval_sec
    fields["holding_ws_repair_min_interval_sec"] = round(min_interval_sec, 3)
    if last_reg_ts > 0 and float(now_ts) < next_after:
        fields["holding_ws_reg_reissued"] = False
        fields["holding_ws_repair_cycle_state"] = "holding_ws_repair_interval_active"
        fields["holding_ws_repair_next_after_epoch"] = f"{next_after:.3f}"
        return
    if EVENT_BUS is None:
        fields["holding_ws_reg_reissued"] = False
        fields["holding_ws_repair_cycle_state"] = "holding_ws_repair_event_bus_unavailable"
        return
    try:
        EVENT_BUS.publish(
            "COMMAND_WS_REG",
            {
                "codes": [code],
                "source": "holding_ws_freshness_repair",
                "force": True,
                "repair_cycle": "holding_ws_stale_or_missing",
            },
        )
        if isinstance(state, dict):
            state["last_ws_repair_reg_ts"] = float(now_ts)
        fields["holding_ws_reg_reissued"] = True
        fields["holding_ws_repair_cycle_state"] = "holding_ws_repair_reg_reissued"
    except Exception as exc:
        fields["holding_ws_reg_reissued"] = False
        fields["holding_ws_repair_cycle_state"] = "holding_ws_repair_reg_error"
        fields["holding_ws_reg_error"] = str(exc)[:120]


def _holding_ws_freshness_recover_or_block(stock, code, ws_data, *, now_ts):
    if _has_sim_probe_provenance(stock):
        return ws_data or {}, False, {}
    if normalize_strategy((stock or {}).get("strategy")) != "SCALPING":
        return ws_data or {}, False, {}
    ws_data = dict(ws_data or {})
    curr_price = _safe_int(ws_data.get("curr"), 0)
    age_sec = _get_ws_snapshot_age_sec(ws_data)
    max_age_sec = _holding_exit_ws_max_age_sec()
    quote_stale = _boolish_true(ws_data.get("quote_stale"))
    block_reason = ""
    if curr_price <= 0:
        block_reason = "holding_ws_curr_missing_or_zero"
    elif quote_stale:
        block_reason = "holding_ws_quote_stale"
    elif age_sec is not None and age_sec > max_age_sec:
        block_reason = "holding_ws_snapshot_stale"
    if not block_reason:
        if isinstance(stock, dict):
            stock.pop("holding_rest_quote_only_recovery", None)
            stock.pop("holding_rest_quote_only_recovered_at", None)
        return ws_data, False, {}

    state = stock.setdefault("_holding_ws_freshness_recovery", {}) if isinstance(stock, dict) else {}
    if not isinstance(state, dict):
        state = {}
        if isinstance(stock, dict):
            stock["_holding_ws_freshness_recovery"] = state
    miss_count = _safe_int(state.get("miss_count"), 0) + 1
    state["miss_count"] = miss_count
    state["last_block_reason"] = block_reason
    fields = {
        "metric_role": "holding_exit_source_quality_guard",
        "decision_authority": "hard_safety_price_freshness_guard",
        "window_policy": "intraday_runtime_latest_quote",
        "sample_floor": "not_applicable_runtime_guard",
        "primary_decision_metric": "quote_age_sec",
        "source_quality_gate": "fresh_holding_quote_required_before_exit_decision",
        "forbidden_uses": "threshold_mutation|provider_change|order_guard_bypass|stale_price_exit_submit",
        "runtime_effect": True,
        "actual_order_submitted": False,
        "broker_order_forbidden": True,
        "holding_ws_freshness_block_reason": block_reason,
        "holding_ws_curr_price": curr_price,
        "holding_ws_quote_stale": quote_stale,
        "holding_ws_age_sec": "-" if age_sec is None else round(age_sec, 3),
        "holding_ws_max_age_sec": round(max_age_sec, 3),
        "holding_ws_recovery_miss_count": miss_count,
        **_ws_realtime_type_freshness_fields(ws_data, now_ts=now_ts),
    }

    last_rest_ts = _safe_float(state.get("last_rest_quote_ts"), 0.0)
    rest_due = float(now_ts) - last_rest_ts >= _holding_rest_quote_fallback_min_interval_sec()
    if rest_due:
        state["last_rest_quote_ts"] = float(now_ts)
        fallback = _fetch_holding_rest_quote_snapshot(code, now_ts)
        if fallback:
            fallback_curr = _safe_int(fallback.get("curr"), 0)
            divergence_max_pct = max(
                0.0,
                _rule_float("HOLDING_REST_QUOTE_RECOVERY_MAX_WS_DIVERGENCE_PCT", 5.0),
            )
            recent_age_limit = max_age_sec * max(
                1.0,
                _rule_float("HOLDING_REST_QUOTE_RECOVERY_RECENT_WS_AGE_MULTIPLIER", 2.0),
            )
            divergence_pct = (
                abs(float(fallback_curr) - float(curr_price)) / float(curr_price) * 100.0
                if curr_price > 0 and fallback_curr > 0
                else 0.0
            )
            ws_recent_enough = age_sec is not None and age_sec <= recent_age_limit
            if (
                curr_price > 0
                and fallback_curr > 0
                and ws_recent_enough
                and divergence_pct > divergence_max_pct
            ):
                fields.update(
                    {
                        "holding_ws_recovery_action": "rest_quote_divergence_blocked",
                        "holding_ws_recovery_outcome": "rest_quote_divergence_blocked",
                        "holding_ws_recovered_curr": fallback_curr,
                        "holding_rest_quote_divergence_pct": round(divergence_pct, 3),
                        "holding_rest_quote_divergence_max_pct": round(divergence_max_pct, 3),
                        "holding_rest_quote_recent_ws_age_limit_sec": round(recent_age_limit, 3),
                    }
                )
                _maybe_publish_holding_ws_repair(state, code, fields, now_ts=now_ts)
                if isinstance(stock, dict):
                    stock.pop("holding_rest_quote_only_recovery", None)
                    stock.pop("holding_rest_quote_only_recovered_at", None)
                _log_holding_pipeline(stock, code, "holding_rest_quote_divergence_blocked", **fields)
                return ws_data, True, fields
            recovered = dict(ws_data)
            recovered.update(fallback)
            recovered.pop("orderbook", None)
            recovered["holding_rest_quote_only_recovery"] = True
            if isinstance(stock, dict):
                stock["holding_rest_quote_only_recovery"] = True
                stock["holding_rest_quote_only_recovered_at"] = float(now_ts)
            fields.update(
                {
                    "holding_ws_recovery_action": "rest_quote_applied",
                    "holding_ws_recovery_outcome": "rest_quote_applied",
                    "holding_ws_recovered_curr": fallback_curr,
                    "holding_rest_quote_only_recovery": True,
                }
            )
            _maybe_publish_holding_ws_repair(state, code, fields, now_ts=now_ts)
            _log_holding_pipeline(stock, code, "holding_ws_freshness_recovered", **fields)
            return recovered, False, fields
        fields["holding_ws_recovery_action"] = "rest_quote_unavailable"
        fields["holding_ws_recovery_outcome"] = "rest_quote_unavailable"
    else:
        fields["holding_ws_recovery_action"] = "rest_quote_deferred"
        fields["holding_ws_recovery_outcome"] = "rest_quote_deferred"
        fields["holding_rest_quote_next_after_epoch"] = f"{last_rest_ts + _holding_rest_quote_fallback_min_interval_sec():.3f}"

    _maybe_publish_holding_ws_repair(state, code, fields, now_ts=now_ts)
    if isinstance(stock, dict):
        stock.pop("holding_rest_quote_only_recovery", None)
        stock.pop("holding_rest_quote_only_recovered_at", None)
    return ws_data, True, fields


def _rest_quote_only_hard_stop_confirmation_block(
    stock,
    code,
    *,
    exit_rule: str,
    profit_rate: float,
    emergency_pct: float,
    held_sec: int,
    curr_price: int,
    buy_price,
    quote_fields: dict | None = None,
) -> bool:
    if str(exit_rule or "").strip() not in {
        "scalp_preset_hard_stop_pct",
        "scalp_hard_stop_pct",
        "scalp_soft_stop_pct",
    }:
        return False
    if not bool((stock or {}).get("holding_rest_quote_only_recovery")):
        return False
    if float(profit_rate or 0.0) <= float(emergency_pct or -999.0):
        return False
    _log_holding_pipeline(
        stock,
        code,
        "hard_stop_rest_quote_only_confirmation_blocked",
        exit_rule=str(exit_rule or "-"),
        profit_rate=f"{float(profit_rate or 0.0):+.2f}",
        emergency_pct=f"{float(emergency_pct or 0.0):+.2f}",
        held_sec=int(held_sec or 0),
        curr_price=int(curr_price or 0),
        buy_price=buy_price,
        confirmation_required="ws_or_orderbook_quote",
        actual_order_submitted=False,
        broker_order_forbidden=True,
        runtime_effect=False,
        **(quote_fields or {}),
    )
    return True


def _normalize_pre_ai_strength_ws_timestamp(snapshot: dict | None) -> tuple[dict, str]:
    normalized = dict(snapshot or {}) if isinstance(snapshot, dict) else {}
    if not normalized:
        return normalized, ""
    if _safe_int(normalized.get("curr"), 0) <= 0:
        return normalized, ""

    base_ts = _safe_float(normalized.get("last_ws_update_ts"), 0.0)
    candidates: list[tuple[str, float]] = []
    type_ts = normalized.get("last_realtime_type_ts")
    if isinstance(type_ts, dict):
        tick_ts = _safe_float(type_ts.get("0B"), 0.0)
        if tick_ts > 0:
            candidates.append(("last_realtime_type_ts_0B", tick_ts))
    last_trade = normalized.get("last_trade_tick")
    if isinstance(last_trade, dict):
        trade_ts = _safe_float(last_trade.get("ts"), 0.0)
        if trade_ts > 0:
            candidates.append(("last_trade_tick", trade_ts))
    history = normalized.get("strength_momentum_history") or []
    try:
        latest_history = history[-1] if history else None
    except Exception:
        latest_history = None
    if isinstance(latest_history, dict):
        history_ts = _safe_float(latest_history.get("ts") or latest_history.get("timestamp"), 0.0)
        if history_ts > 0:
            candidates.append(("strength_momentum_history", history_ts))

    if not candidates:
        return normalized, ""
    source, candidate_ts = max(candidates, key=lambda item: item[1])
    now_ts = time.time()
    if candidate_ts <= 0 or candidate_ts > now_ts + 1.0:
        return normalized, ""
    if base_ts > 0 and candidate_ts <= base_ts:
        return normalized, ""

    normalized["last_ws_update_ts"] = candidate_ts
    normalized["pre_ai_last_ws_update_ts_normalized_from"] = source
    return normalized, source


def _pre_ai_refresh_strength_momentum_ws_snapshot(code: str, ws_data: dict | None, strategy: str) -> tuple[dict, dict]:
    """Refresh pre-AI strength input from the latest WS cache without changing thresholds."""
    base, base_normalized_from = _normalize_pre_ai_strength_ws_timestamp(ws_data)
    fields = {
        "pre_ai_ws_snapshot_refresh_enabled": False,
        "pre_ai_ws_snapshot_refresh_applied": False,
        "pre_ai_ws_snapshot_refresh_reason": "not_attempted",
        "pre_ai_ws_snapshot_refresh_source": "ws_manager_latest_data",
        "pre_ai_ws_snapshot_refresh_input_age_ms": None,
        "pre_ai_ws_snapshot_refresh_age_ms": None,
        "pre_ai_ws_snapshot_refresh_latest_price": _safe_int(base.get("curr"), 0),
        "pre_ai_ws_snapshot_refresh_history_count": 0,
        "pre_ai_ws_snapshot_refresh_input_timestamp_normalized_from": base_normalized_from or "",
        "pre_ai_ws_snapshot_refresh_latest_timestamp_normalized_from": "",
    }
    if str(strategy or "").upper() not in {"SCALPING", "SCALP", "KOSPI_ML"}:
        fields["pre_ai_ws_snapshot_refresh_reason"] = "non_scalping"
        return base, fields
    if not _rule_bool("SCALP_PRE_AI_WS_SNAPSHOT_REFRESH_ENABLED", True):
        fields["pre_ai_ws_snapshot_refresh_reason"] = "disabled"
        return base, fields

    fields["pre_ai_ws_snapshot_refresh_enabled"] = True
    base_age = _get_ws_snapshot_age_sec(base)
    max_age_sec = _rule_float("SCALP_PRE_AI_MAX_WS_AGE_SEC", 3.0)
    near_stale_buffer_sec = min(0.5, max(0.0, max_age_sec * 0.2))
    base_history = base.get("strength_momentum_history") or []
    base_history_count = len(base_history) if hasattr(base_history, "__len__") else 0
    fields["pre_ai_ws_snapshot_refresh_history_count"] = int(base_history_count or 0)
    if base_age is not None:
        fields["pre_ai_ws_snapshot_refresh_input_age_ms"] = round(base_age * 1000.0, 3)
    if base_age is None:
        fields["pre_ai_ws_snapshot_refresh_reason"] = "input_timestamp_missing"
    elif base_age < max(0.0, max_age_sec - near_stale_buffer_sec):
        fields["pre_ai_ws_snapshot_refresh_reason"] = "input_snapshot_fresh"
        return base, fields
    else:
        fields["pre_ai_ws_snapshot_refresh_reason"] = "input_snapshot_near_stale"

    manager = WS_MANAGER
    if manager is None or not hasattr(manager, "get_latest_data"):
        fields["pre_ai_ws_snapshot_refresh_reason"] = "ws_manager_missing"
        return base, fields
    try:
        latest = manager.get_latest_data(code) or {}
    except Exception as exc:
        fields["pre_ai_ws_snapshot_refresh_reason"] = "ws_manager_error"
        fields["pre_ai_ws_snapshot_refresh_error"] = str(exc)[:120]
        return base, fields
    if not isinstance(latest, dict) or not latest:
        fields["pre_ai_ws_snapshot_refresh_reason"] = "latest_snapshot_missing"
        return base, fields

    latest, latest_normalized_from = _normalize_pre_ai_strength_ws_timestamp(latest)
    fields["pre_ai_ws_snapshot_refresh_latest_timestamp_normalized_from"] = latest_normalized_from or ""
    latest_ts = _safe_float(latest.get("last_ws_update_ts"), 0.0)
    base_ts = _safe_float(base.get("last_ws_update_ts"), 0.0)
    latest_age = None if latest_ts <= 0 else max(0.0, (time.time() - latest_ts) * 1000.0)
    history = latest.get("strength_momentum_history") or []
    history_count = len(history) if hasattr(history, "__len__") else 0
    fields.update(
        {
            "pre_ai_ws_snapshot_refresh_age_ms": None if latest_age is None else round(latest_age, 3),
            "pre_ai_ws_snapshot_refresh_latest_price": _safe_int(latest.get("curr"), 0),
            "pre_ai_ws_snapshot_refresh_history_count": int(history_count or 0),
        }
    )
    if latest_ts <= 0:
        fields["pre_ai_ws_snapshot_refresh_reason"] = "latest_timestamp_missing"
        return base, fields
    if base_ts > 0 and latest_ts < base_ts:
        fields["pre_ai_ws_snapshot_refresh_reason"] = "latest_snapshot_older_than_input"
        return base, fields
    if latest_age is None or latest_age > max_age_sec * 1000.0:
        fields["pre_ai_ws_snapshot_refresh_reason"] = "latest_snapshot_stale"
        return base, fields
    if _safe_int(latest.get("curr"), 0) <= 0:
        fields["pre_ai_ws_snapshot_refresh_reason"] = "latest_price_missing"
        return base, fields
    if history_count <= 0:
        fields["pre_ai_ws_snapshot_refresh_reason"] = "latest_strength_history_missing"
        return base, fields

    refreshed = dict(latest)
    fields["pre_ai_ws_snapshot_refresh_applied"] = True
    fields["pre_ai_ws_snapshot_refresh_reason"] = "latest_ws_snapshot_fresh"
    refreshed.update(fields)
    return refreshed, fields


def _update_ai_quote_freshness_fields(ws_data: dict | None) -> dict:
    """Recompute AI quote freshness from the current snapshot instead of preserving stale flags."""
    if not isinstance(ws_data, dict):
        return {}
    quote_age_sec = _get_ws_snapshot_age_sec(ws_data)
    if quote_age_sec is not None:
        quote_age_ms = int(round(quote_age_sec * 1000.0))
        ws_data["quote_age_ms"] = quote_age_ms
        ws_data["quote_age_source"] = "last_ws_update_ts"
        max_quote_age_ms = int(_rule("SCALPING_ENTRY_SUBMIT_REVALIDATION_MAX_QUOTE_AGE_MS", 2000) or 2000)
        ws_data["quote_stale"] = quote_age_ms > max(1, max_quote_age_ms)
        return ws_data
    elif ws_data.get("orderbook"):
        ws_data.setdefault("quote_age_source", "orderbook_without_timestamp")
    quote_freshness = _quote_freshness_bucket(ws_data)
    if quote_freshness in {"fresh", "aging"}:
        ws_data["quote_stale"] = False
    elif quote_freshness == "stale":
        ws_data["quote_stale"] = True
    elif ws_data.get("orderbook") and "quote_stale" not in ws_data:
        ws_data["quote_stale"] = False
        ws_data.setdefault(
            "quote_freshness_source_quality",
            "orderbook_timestamp_missing",
        )
    return ws_data


def _history_tick_window_fields(ws_data: dict | None, gate_result: dict | None = None) -> dict[str, Any]:
    ws_data = ws_data if isinstance(ws_data, dict) else {}
    gate_result = gate_result if isinstance(gate_result, dict) else {}
    history = ws_data.get("strength_momentum_history") or []
    normalized_ts: list[float] = []
    if isinstance(history, list):
        for item in history:
            if not isinstance(item, dict):
                continue
            ts = _safe_float(item.get("ts"), 0.0)
            if ts > 0:
                normalized_ts.append(ts)
    normalized_ts.sort()
    sample_count = len(normalized_ts)
    latest_ts = normalized_ts[-1] if normalized_ts else 0.0
    window_sec = _safe_float(gate_result.get("window_sec"), _rule_float("SCALP_VPW_WINDOW_SECONDS", 5.0))
    if latest_ts > 0:
        window_start = latest_ts - max(0.0, window_sec)
        window_ts = [ts for ts in normalized_ts if ts >= window_start]
    else:
        window_ts = []
    window_sample_count = len(window_ts)
    if window_ts:
        window_span = max(0.0, window_ts[-1] - window_ts[0])
    else:
        window_span = 0.0
    latest_age_ms: Any
    if latest_ts > 0:
        latest_age_ms = round(max(0.0, time.time() - latest_ts) * 1000.0, 3)
    else:
        latest_age_ms = "not_available_tick_latest_age_ms"
    return {
        "tick_sample_count": sample_count,
        "tick_window_sample_count": window_sample_count,
        "tick_latest_age_ms": latest_age_ms,
        "tick_window_span_sec": round(window_span, 3),
        "sample_count": sample_count,
        "window_span_sec": round(window_span, 3),
    }


def _pre_ai_blocked_gate_quality_fields(
    *,
    gate_name: str,
    ws_data: dict | None,
    gate_result: dict | None = None,
    refresh_fields: dict | None = None,
    liquidity_totals_present: bool | None = None,
) -> dict[str, Any]:
    """Self-contained freshness/stability provenance for pre-AI blocked gates."""
    ws_data = ws_data if isinstance(ws_data, dict) else {}
    gate_result = gate_result if isinstance(gate_result, dict) else {}
    refresh_fields = refresh_fields if isinstance(refresh_fields, dict) else {}
    tick_fields = _history_tick_window_fields(ws_data, gate_result)
    quote_age_sec = _get_ws_snapshot_age_sec(ws_data)
    quote_age_ms: Any
    if quote_age_sec is None:
        quote_age_ms = "not_available_quote_age_ms"
    else:
        quote_age_ms = round(max(0.0, quote_age_sec) * 1000.0, 3)

    refresh_applied = bool(refresh_fields.get("pre_ai_ws_snapshot_refresh_applied"))
    refresh_reason = str(
        refresh_fields.get("pre_ai_ws_snapshot_refresh_reason")
        or ("not_attempted_no_refresh_fields" if not refresh_fields else "not_available_refresh_reason")
    )
    refresh_age_ms = refresh_fields.get("pre_ai_ws_snapshot_refresh_age_ms")
    if refresh_age_ms in (None, "", "-"):
        refresh_age_ms = refresh_fields.get("pre_ai_ws_snapshot_refresh_input_age_ms")
    if refresh_age_ms in (None, "", "-"):
        refresh_age_ms = "not_available_refresh_age_ms"
    refresh_history_count = refresh_fields.get("pre_ai_ws_snapshot_refresh_history_count")
    if refresh_history_count in (None, "", "-"):
        refresh_history_count = "not_available_refresh_history_count"
    snapshot_source = str(
        refresh_fields.get("pre_ai_ws_snapshot_refresh_source")
        or ("ws_snapshot_input" if ws_data else "missing_ws_snapshot")
    )
    sample_count = _safe_int(tick_fields.get("tick_sample_count"), 0)
    window_sample_count = _safe_int(tick_fields.get("tick_window_sample_count"), 0)
    window_span = _safe_float(tick_fields.get("tick_window_span_sec"), 0.0)
    gate_key = str(gate_name or "").strip() or "unknown_gate"
    if gate_key == "liquidity" and liquidity_totals_present is False:
        stability_result = "missing_orderbook_snapshot"
        stability_reason = "ask_bid_totals_missing"
    elif sample_count <= 0:
        stability_result = "not_available"
        stability_reason = "strength_momentum_history_missing"
    elif window_sample_count <= 1:
        stability_result = "single_snapshot_only"
        stability_reason = "insufficient_window_samples"
    elif window_span <= 0:
        stability_result = "single_timestamp_window"
        stability_reason = "window_span_zero"
    else:
        stability_result = "window_available"
        stability_reason = "window_samples_present"
    return {
        **tick_fields,
        "quote_age_ms": quote_age_ms,
        "snapshot_source": snapshot_source,
        "refresh_applied": refresh_applied,
        "refresh_reason": refresh_reason,
        "refresh_age_ms": refresh_age_ms,
        "refresh_history_count": refresh_history_count,
        **_ws_realtime_type_freshness_fields(ws_data, now_ts=time.time()),
        "stability_window_result": stability_result,
        "stability_window_reason": stability_reason,
        "stability_sample_count": window_sample_count,
        "blocked_gate_quality_stage": gate_key,
    }


def _resolve_reference_age_sec(primary_ts, *, fallback_ts=None, now_ts=None):
    def _coerce_ts(value):
        if value in (None, "", 0, "0", "None"):
            return None
        try:
            ts = float(value)
        except Exception:
            return None
        return ts if ts > 0 else None

    reference_ts = _coerce_ts(primary_ts)
    if reference_ts is None:
        reference_ts = _coerce_ts(fallback_ts)
    if reference_ts is None:
        return None

    current_ts = time.time() if now_ts is None else float(now_ts)
    return max(0.0, float(current_ts - reference_ts))


def _extract_ai_overlap_snapshot(
    *,
    ws_data,
    recent_ticks=None,
    recent_candles=None,
    ai_engine=None,
):
    snapshot = {
        "latest_strength": float(ws_data.get("v_pw", 0.0) or 0.0),
        "buy_pressure_10t": float(ws_data.get("buy_ratio", 0.0) or 0.0),
        "distance_from_day_high_pct": None,
        "intraday_range_pct": None,
        "overlap_context_source_quality": "missing_range_context",
    }

    ticks = list(recent_ticks or [])
    candles = list(recent_candles or [])
    if ticks:
        try:
            snapshot["latest_strength"] = float(ticks[0].get("strength", snapshot["latest_strength"]) or snapshot["latest_strength"])
        except Exception:
            pass
        try:
            buy_vol = sum(_safe_int(tick.get("volume"), 0) for tick in ticks if str(tick.get("dir") or "").upper() == "BUY")
            sell_vol = sum(_safe_int(tick.get("volume"), 0) for tick in ticks if str(tick.get("dir") or "").upper() == "SELL")
            total_vol = buy_vol + sell_vol
            if total_vol > 0:
                snapshot["buy_pressure_10t"] = (buy_vol / total_vol) * 100.0
        except Exception:
            pass

    curr_price = _safe_int(ws_data.get("curr"), 0)
    high_price = _safe_float(
        ws_data.get("high")
        or ws_data.get("high_price")
        or ws_data.get("day_high")
        or ws_data.get("today_high"),
        0.0,
    )
    low_price = _safe_float(
        ws_data.get("low")
        or ws_data.get("low_price")
        or ws_data.get("day_low")
        or ws_data.get("today_low"),
        0.0,
    )
    if curr_price > 0 and high_price and high_price > 0:
        snapshot["distance_from_day_high_pct"] = ((curr_price - high_price) / high_price) * 100.0
    if curr_price > 0 and high_price and low_price and low_price > 0 and high_price >= low_price:
        snapshot["intraday_range_pct"] = ((high_price - low_price) / low_price) * 100.0
        snapshot["overlap_context_source_quality"] = "ws_high_low"

    if candles and curr_price > 0:
        highs = []
        lows = []
        for candle in candles:
            try:
                highs.append(float(candle.get("고가", 0) or 0))
                lows.append(float(candle.get("저가", 0) or 0))
            except Exception:
                continue
        candle_high_price = max([value for value in highs if value > 0], default=0.0)
        candle_low_price = min([value for value in lows if value > 0], default=0.0)
        if candle_high_price > 0:
            snapshot["distance_from_day_high_pct"] = ((curr_price - candle_high_price) / candle_high_price) * 100.0
        if candle_low_price > 0 and candle_high_price >= candle_low_price:
            snapshot["intraday_range_pct"] = ((candle_high_price - candle_low_price) / candle_low_price) * 100.0
            snapshot["overlap_context_source_quality"] = "recent_candles"

    if ai_engine and hasattr(ai_engine, "_extract_scalping_features"):
        try:
            feature_map = ai_engine._extract_scalping_features(ws_data, ticks, candles)
            snapshot["latest_strength"] = float(feature_map.get("latest_strength", snapshot["latest_strength"]) or snapshot["latest_strength"])
            snapshot["buy_pressure_10t"] = float(feature_map.get("buy_pressure_10t", snapshot["buy_pressure_10t"]) or snapshot["buy_pressure_10t"])
            feature_distance = feature_map.get("distance_from_day_high_pct")
            feature_range = feature_map.get("intraday_range_pct")
            if feature_distance not in (None, "", "-", "None", "none", "null"):
                snapshot["distance_from_day_high_pct"] = float(feature_distance)
            if feature_range not in (None, "", "-", "None", "none", "null"):
                snapshot["intraday_range_pct"] = float(feature_range)
                snapshot["overlap_context_source_quality"] = "scalping_feature_packet"
        except Exception:
            pass

    return snapshot


def _entry_top3_depth_ratio(ws_data) -> float:
    orderbook = (ws_data or {}).get("orderbook") if isinstance(ws_data, dict) else {}
    if not isinstance(orderbook, dict):
        return 0.0
    asks = orderbook.get("asks") if isinstance(orderbook.get("asks"), list) else []
    bids = orderbook.get("bids") if isinstance(orderbook.get("bids"), list) else []
    ask_vol = sum(_safe_float((item or {}).get("volume"), 0.0) for item in asks[:3] if isinstance(item, dict))
    bid_vol = sum(_safe_float((item or {}).get("volume"), 0.0) for item in bids[:3] if isinstance(item, dict))
    if bid_vol <= 0:
        return 0.0
    return round(ask_vol / bid_vol, 4)


def _signed_regime(value, *, zero_band=0.0) -> str:
    numeric = _safe_float(value, 0.0)
    if numeric > zero_band:
        return "positive"
    if numeric < -zero_band:
        return "negative"
    return "neutral"


def _bucket_tick_acceleration(value) -> str:
    numeric = _safe_float(value, 0.0)
    if numeric >= 1.2:
        return "accelerating"
    if numeric >= 0.9:
        return "steady"
    if numeric > 0:
        return "slowing"
    return "unknown"


def _bucket_top_depth_ratio(value) -> str:
    numeric = _safe_float(value, 0.0)
    if numeric >= 1.35:
        return "ask_heavy"
    if numeric > 0 and numeric <= 0.75:
        return "bid_heavy"
    if numeric > 0:
        return "balanced"
    return "unknown"


def _quote_freshness_bucket(ws_data) -> str:
    raw_quote_stale = (ws_data or {}).get("quote_stale")
    if isinstance(raw_quote_stale, str):
        quote_stale = raw_quote_stale.strip().lower() in {"1", "true", "yes", "y", "stale"}
    else:
        quote_stale = bool(raw_quote_stale)
    if quote_stale:
        return "stale"
    age = _get_ws_snapshot_age_sec(ws_data)
    if age is None:
        return "unknown"
    if age <= 1.5:
        return "fresh"
    if age <= 3.0:
        return "aging"
    return "stale"


def _build_watching_state_change_signature(ws_data, feature_packet=None) -> dict:
    packet = feature_packet if isinstance(feature_packet, dict) else {}
    source = ws_data if isinstance(ws_data, dict) else {}
    buy_pressure = packet.get("buy_pressure_10t", packet.get("buy_pressure", (ws_data or {}).get("buy_ratio", 0.0)))
    top3_ratio = packet.get("top3_depth_ratio")
    if top3_ratio in (None, "", 0):
        top3_ratio = _entry_top3_depth_ratio(ws_data)
    tick_accel = packet.get(
        "tick_acceleration_ratio",
        packet.get(
            "tick_accel",
            source.get("tick_acceleration_ratio", source.get("tick_accel", 0.0)),
        ),
    )
    micro_vwap_bp = packet.get(
        "curr_vs_micro_vwap_bp",
        packet.get(
            "micro_vwap_bp",
            source.get("curr_vs_micro_vwap_bp", source.get("micro_vwap_bp", 0.0)),
        ),
    )
    ma5_bp = packet.get("curr_vs_ma5_bp", source.get("curr_vs_ma5_bp", 0.0))
    large_sell = packet.get(
        "large_sell_print_detected",
        packet.get(
            "large_sell_print",
            source.get("large_sell_print_detected", source.get("large_sell_print", False)),
        ),
    )
    return {
        "micro_vwap_side": _signed_regime(micro_vwap_bp),
        "ma5_side": _signed_regime(ma5_bp),
        "buy_pressure_10t": round(_safe_float(buy_pressure, 0.0), 3),
        "tick_acceleration_regime": _bucket_tick_acceleration(tick_accel),
        "large_sell_print_detected": _boolish_true(large_sell),
        "top3_depth_regime": _bucket_top_depth_ratio(top3_ratio),
        "quote_freshness": _quote_freshness_bucket(ws_data),
    }


def _watching_refresh_available_axes(ws_data, feature_packet=None) -> list[str]:
    packet = feature_packet if isinstance(feature_packet, dict) else {}
    source = ws_data if isinstance(ws_data, dict) else {}
    axes = ["buy_pressure_10t", "top3_depth_regime", "quote_freshness"]
    if any(key in packet or key in source for key in ("curr_vs_micro_vwap_bp", "micro_vwap_bp")):
        axes.append("micro_vwap_side")
    if "curr_vs_ma5_bp" in packet or "curr_vs_ma5_bp" in source:
        axes.append("ma5_side")
    if any(key in packet or key in source for key in ("tick_acceleration_ratio", "tick_accel")):
        axes.append("tick_acceleration_regime")
    if any(key in packet or key in source for key in ("large_sell_print_detected", "large_sell_print")):
        axes.append("large_sell_print_detected")
    return sorted(set(axes))


def _build_watching_refresh_signature(ws_data, feature_packet=None) -> dict:
    signature = _build_watching_state_change_signature(ws_data, feature_packet)
    signature["signature_source"] = "runtime_context_v2"
    signature["available_axes"] = _watching_refresh_available_axes(ws_data, feature_packet)
    return signature


def _resolve_watching_state_change_refresh(stock, ws_data, *, now_ts, last_ai_time, cooldown_sec) -> dict:
    smoothing_mode = normalize_watching_score_smoothing_mode(
        _rule("AI_WATCHING_SCORE_SMOOTHING_MODE", "off")
    )
    if not bool(_rule("AI_WATCHING_STATE_CHANGE_REFRESH_ENABLED", False)) and smoothing_mode == "off":
        return {"allowed": False, "reason": "disabled", "signature": {}}
    if last_ai_time <= 0:
        return {"allowed": False, "reason": "first_call_uses_normal_path", "signature": {}}
    if now_ts - last_ai_time > max(1, cooldown_sec):
        return {"allowed": False, "reason": "cooldown_elapsed", "signature": {}}
    marker = str((stock or {}).get("watching_state_change_refresh_last_ai_time") or "")
    if marker == f"{float(last_ai_time):.3f}":
        return {"allowed": False, "reason": "already_refreshed_this_cooldown", "signature": {}}
    block_until = _safe_float((stock or {}).get("watching_state_change_refresh_block_until"), 0.0)
    if block_until > 0 and now_ts < block_until:
        return {"allowed": False, "reason": "already_refreshed_this_cooldown", "signature": {}}
    if smoothing_mode != "off" and now_ts - last_ai_time < 20.0:
        return {"allowed": False, "reason": "early_refresh_min_interval", "signature": {}}

    previous = (stock or {}).get("last_watching_ai_state_signature")
    if not isinstance(previous, dict):
        return {"allowed": False, "reason": "missing_previous_signature", "signature": {}}
    current = _build_watching_refresh_signature(ws_data)
    if smoothing_mode != "off" and previous.get("signature_source") not in {current.get("signature_source"), "ws_runtime_context_v1"}:
        return {"allowed": False, "reason": "legacy_signature_source_mismatch", "signature": current}
    reasons = []
    previous_axes = set(previous.get("available_axes") or ())
    current_axes = set(current.get("available_axes") or ())
    if not previous_axes:
        previous_axes = {"buy_pressure_10t", "top3_depth_regime", "quote_freshness"}
    comparable_axes = previous_axes & current_axes
    for key in ("micro_vwap_side", "ma5_side", "tick_acceleration_regime", "top3_depth_regime", "quote_freshness"):
        if key not in comparable_axes:
            continue
        if previous.get(key) and current.get(key) and previous.get(key) != current.get(key):
            reasons.append(f"{key}_changed")
    if "large_sell_print_detected" in comparable_axes and bool(previous.get("large_sell_print_detected")) != bool(current.get("large_sell_print_detected")):
        reasons.append("large_sell_print_changed")
    pressure_delta = abs(
        _safe_float(current.get("buy_pressure_10t"), 0.0)
        - _safe_float(previous.get("buy_pressure_10t"), 0.0)
    )
    min_delta = max(0.0, _rule_float("AI_WATCHING_STATE_CHANGE_BUY_PRESSURE_DELTA", 10.0))
    if pressure_delta >= min_delta:
        reasons.append("buy_pressure_delta")
    return {
        "allowed": bool(reasons),
        "reason": "|".join(reasons) if reasons else "state_unchanged",
        "signature": current,
    }


EARLY_ACCEL_RECHECK_FORBIDDEN_USES = (
    "EV|rolling|MTD|cumulative_tuning|live_auto_promotion|runtime_apply_bridge|"
    "threshold_mutation|provider_route_change|order_price_change|quantity_cap_change"
)
AI_NUMERIC_CONSISTENCY_RECHECK_FORBIDDEN_USES = (
    "EV|rolling|MTD|cumulative_tuning|live_auto_promotion|runtime_apply_bridge|"
    "threshold_mutation|provider_route_change|order_price_change|quantity_cap_change|broker_guard_bypass"
)
PRE_SUBMIT_LIQUIDITY_RELIEF_FORBIDDEN_USES = (
    "EV|rolling|MTD|cumulative_tuning|live_auto_promotion|runtime_apply_bridge|"
    "threshold_mutation|provider_change|order_price_change|quantity_cap_change|broker_guard_bypass"
)
EARLY_ACCEL_RECHECK_PROMOTION_REASONS = frozenset(
    {
        "probe_acceleration_confirmed",
        "early_discovery_source_present",
        "new_vi_triggered_source",
        "new_supernova_source",
        "price_jump_start_acceleration",
        "price_jump_multisource_confirmation",
        "rank_jump_acceleration",
        "spike_rate_acceleration",
        "priority_score_acceleration",
        "execution_strength_acceleration",
    }
)


