def _microstructure_reaction_log_fields_from_stock(stock: dict | None) -> dict:
    if not isinstance(stock, dict):
        return {}
    fields = stock.get("last_watching_ai_source_quality_fields")
    fields = fields if isinstance(fields, dict) else {}
    return {key: fields.get(key) for key in MICROSTRUCTURE_REACTION_CONTEXT_KEYS if key in fields}


def _merge_entry_pipeline_field_groups(*field_groups) -> dict:
    fields = {}
    for field_group in field_groups:
        if isinstance(field_group, dict):
            fields.update(field_group)
    return fields


def _without_entry_pipeline_fields(fields: dict | None, *keys: str) -> dict:
    out = dict(fields or {})
    for key in keys:
        out.pop(key, None)
    return out


def _build_ai_input_not_evaluated_fields(reason: str) -> dict:
    microstructure_context = neutral_microstructure_reaction_context("not_evaluated", str(reason or "not_evaluated"))
    return {
        "ai_input_source_quality_status": "not_evaluated",
        "ai_input_source_quality_reason": str(reason or "not_evaluated"),
        "tick_source_quality_fields_sent": False,
        "tick_accel_source": "not_evaluated",
        "tick_context_quality": "not_evaluated",
        "quote_age_source": "not_evaluated",
        "tick_acceleration_ratio": "-",
        "tick_acceleration_ratio_raw": "-",
        "recent_5tick_seconds": "-",
        "prev_5tick_seconds": "-",
        "tick_accel_effective_recent_5tick_seconds": "-",
        **microstructure_context,
    }


def _ensure_ai_source_quality_fields(fields: dict, stock: dict | None, *, not_evaluated_reason: str) -> dict:
    out = dict(fields or {})
    if "tick_source_quality_fields_sent" not in out and isinstance(stock, dict):
        out.update(dict(stock.get("last_watching_ai_source_quality_fields") or {}))
    for key in ("buy_pressure_10t", "curr_vs_micro_vwap_bp", "curr_vs_ma5_bp"):
        value = out.get(key)
        if value is None or (isinstance(value, str) and value.strip() in {"", "-", "None", "none", "null"}):
            out.pop(key, None)
    if "tick_source_quality_fields_sent" not in out:
        for key, value in _build_ai_input_not_evaluated_fields(not_evaluated_reason).items():
            out.setdefault(key, value)
    elif "ai_input_source_quality_status" not in out:
        out["ai_input_source_quality_status"] = "evaluated"
        out["ai_input_source_quality_reason"] = str(out.get("tick_context_quality") or "tick_audit_present")
    return out


